             <div onClick={() => setActiveQuadrant(q => q === "EXCESS_HEAT" ? "ALL" : "EXCESS_HEAT")} className={`border rounded-xl p-2 bg-slate-900/80 cursor-pointer transition ${activeQuadrant === "EXCESS_HEAT" ? "border-amber-400 bg-amber-900/20" : "border-slate-800 hover:border-amber-500"}`}>
