                  <h1 className="text-2xl font-bold text-white flex items-center gap-2">{selected.name_id} {selected.__isTodo && <span className="text-xs bg-amber-900/60 text-amber-200 px-2 py-0.5 rounded border border-amber-500/60 font-mono font-normal">TODO</span>}</h1>
                  <div className="text-sm text-slate-400 italic">{selected.name_en}</div>
               </div>
               <div className="flex flex-col items-end gap-2">
                 <span className="px-2 py-1 rounded-full text-[11px] border border-slate-700 text-slate-300 uppercase tracking-wide">{selected.pattern_type.replace(/_/g, " ")}</span>
                 {onSelectSyndrome && (
                   <button onClick={() => onSelectSyndrome(selected.id)} className="inline-flex items-center gap-1 px-3 py-1.5 rounded-lg bg-emerald-600 hover:bg-emerald-500 text-xs font-semibold shadow shadow-emerald-900/30 text-white transition-all">
                     <ArrowRightCircle className="w-4 h-4" /> Kirim ke Auto-Resep
                   </button>
                 )}
               </div>
             </div>

             <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                {/* Manifestasi */}
                <div className="bg-slate-900/80 border border-slate-800 rounded-xl p-4">
                   <h3 className="text-sm font-semibold mb-2 flex items-center gap-2 text-slate-200"><Thermometer className="w-4 h-4 text-blue-400" /> Manifestasi Klinis Utama</h3>
                   {selected.clinical_manifestations && selected.clinical_manifestations.length > 0 ? (
                      <ul className="list-disc list-inside text-xs text-slate-300 space-y-1">
                        {selected.clinical_manifestations.map((m) => <li key={m}>{m}</li>)}
