                   ) : (
                      <p className="text-xs text-amber-400/80 italic">Pola ini belum ada detail gejala di database. Aman sebagai placeholder, tapi disarankan melengkapi data.</p>
                   )}
                   {selected.key_symptoms && selected.key_symptoms.length > 0 && (
                      <div className="mt-3 pt-2 border-t border-slate-800">
                         <div className="text-[11px] font-semibold text-slate-400 mb-1">Gejala Kunci:</div>
                         <div className="flex flex-wrap gap-1">{selected.key_symptoms.map(k => <span key={k} className="px-2 py-1 rounded bg-slate-800 text-[11px] text-slate-200 border border-slate-700">{k}</span>)}</div>
                      </div>
                   )}
                </div>

                {/* Terapi & Titik */}
                <div className="bg-slate-900/80 border border-slate-800 rounded-xl p-4">
                   <h3 className="text-sm font-semibold mb-2 flex items-center gap-2 text-slate-200"><BrainCircuit className="w-4 h-4 text-tcm-accent" /> Prinsip Terapi & Titik</h3>
                   {selected.treatment_principle && selected.treatment_principle.length > 0 ? (
                      <ul className="list-disc list-inside text-xs text-slate-300 space-y-1 mb-3">{selected.treatment_principle.map(t => <li key={t}>{t}</li>)}</ul>
                   ) : <p className="text-xs text-slate-500 mb-3">Belum diisi.</p>}

                   <div className="mt-2">
                      <div className="text-[11px] font-semibold text-slate-400 mb-2">Titik Akupunktur (Manual + Auto):</div>
                      {displayPoints.length > 0 ? (
                         <div className="flex flex-wrap gap-2 text-[11px]">
                           {displayPoints.map((p, i) => (
                              <div key={`${p.code}-${i}`} className="px-2 py-1 rounded bg-slate-800 text-slate-200 border border-slate-700 flex flex-col items-start min-w-[60px]">
                                 <span className="font-bold text-tcm-primary">{p.code}</span>
                                 {p.role && <span className="text-[9px] text-slate-400 uppercase tracking-tighter">{p.role.replace(/_/g,' ').replace('wuxing','WX')}</span>}
                              </div>
                           ))}
                         </div>
                      ) : <p className="text-xs text-slate-500">Belum ada titik.</p>}
                   </div>
                </div>
             </div>

             {/* Herbal */}
             <div className="bg-slate-900/80 border border-emerald-700/60 rounded-xl p-4">
                <h3 className="text-sm font-semibold mb-2 flex items-center gap-2 text-emerald-400"><Leaf className="w-4 h-4" /> Rekomendasi Herbal</h3>
                {!herbalForSelected ? <p className="text-xs text-slate-500">Belum ada data herbal.</p> : (
                   <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-xs">
                      <div>
                         <h4 className="text-[11px] font-semibold text-emerald-300 mb-1">Formula Utama:</h4>
                         {herbalForSelected.key_formulas?.length ? (
                            <ul className="space-y-1">{herbalForSelected.key_formulas.map((f: any, idx: number) => <li key={idx} className="bg-slate-950/60 border border-slate-800 rounded px-2 py-1"><div className="font-semibold text-slate-100">{f.name}</div><div className="text-[10px] text-slate-400">{f.focus}</div></li>)}</ul>
                         ) : <span className="text-slate-500">Kosong</span>}
                      </div>
                      <div>
                         <h4 className="text-[11px] font-semibold text-emerald-300 mb-1">Single Herbs:</h4>
                         {herbalForSelected.single_herbs?.length ? (
                            <ul className="space-y-1">{herbalForSelected.single_herbs.map((h: any, idx: number) => {
                               const base = singleIndex[h.ref] || {};
                               return <li key={idx} className="bg-slate-950/60 border border-slate-800 rounded px-2 py-1 flex justify-between"><span>{base.name || h.ref}</span> <span className="text-[10px] text-emerald-300 bg-emerald-900/30 px-1 rounded">{h.role}</span></li>
                            })}</ul>
                         ) : <span className="text-slate-500">Kosong</span>}
