  const classified = useMemo(() => 
      allSyndromes.map((s) => ({
        ...s,
        quadrant: classifyQuadrant(s.pattern_type, s.name_en),
      })),
    []
  );

  const filtered = useMemo(() => {
    let list = classified;
    if (activeQuadrant !== "ALL") list = list.filter((s) => s.quadrant === activeQuadrant);
    if (organFilter !== "ALL") list = list.filter((s) => s.primary_organs?.includes(organFilter));
    if (search.trim()) {
      const q = search.toLowerCase();
      list = list.filter(s =>
          s.name_id.toLowerCase().includes(q) ||
          (s.name_en && s.name_en.toLowerCase().includes(q)) ||
          (s.primary_organs || []).some((o) => o.toLowerCase().includes(q))
      );
    }
    return list;
  }, [classified, activeQuadrant, organFilter, search]);

  const selected = filtered.find((s) => s.id === selectedId) || filtered[0] || null;

  useEffect(() => {
    if (!selectedId && filtered.length > 0) setSelectedId(filtered[0].id);
  }, [filtered, selectedId]);

