import React, { useState } from 'react';
import jsPDF from 'jspdf';
import { translations } from '../translations'; // Adjust path

interface TCMWuXingProPanelProps {
  t: (key: string) => string;
  onGenerateImage: (prompt: string) => void; // Callback to app's image generator
}

const elements = ['Wood', 'Fire', 'Earth', 'Metal', 'Water'];
const meridianMap = {
  Wood: 'Liver/Gallbladder',
  Fire: 'Heart/Small Intestine/Pericardium/Triple Burner',
  Earth: 'Spleen/Stomach',
  Metal: 'Lung/Large Intestine',
  Water: 'Kidney/Bladder',
};
const twelvePointsExamples = {
  Wood: 'LV-3, GB-41',
  Fire: 'HT-7, PC-3',
  Earth: 'SP-6, ST-36',
  Metal: 'LU-5, LI-11',
  Water: 'KI-3, BL-65',
};

const TCMWuXingProPanel: React.FC<TCMWuXingProPanelProps> = ({ t, onGenerateImage }) => {
  const [symptoms, setSymptoms] = useState('');
  const [diagnosis, setDiagnosis] = useState<{ element: string; imbalance: string; points: string; } | null>(null);

  const diagnose = () => {
    // Simple logic based on Wu Xing (pro: extend with ML if needed)
    const keywords = symptoms.toLowerCase();
    let element = 'Earth'; // Default
    if (keywords.includes('anger') || keywords.includes('eyes')) element = 'Wood';
    else if (keywords.includes('joy') || keywords.includes('heart')) element = 'Fire';
    else if (keywords.includes('digestion') || keywords.includes('worry')) element = 'Earth';
    else if (keywords.includes('grief') || keywords.includes('lungs')) element = 'Metal';
    else if (keywords.includes('fear') || keywords.includes('kidneys')) element = 'Water';

    const imbalance = Math.random() > 0.5 ? 'Excess' : 'Deficiency';
    const points = twelvePointsExamples[element as keyof typeof twelvePointsExamples];
    setDiagnosis({ element, imbalance, points });
  };

  const generateImagePrompt = () => {
    if (!diagnosis) return;
    const prompt = `Photorealistic diagram of TCM Wu Xing cycle with highlighted ${diagnosis.element} element, showing meridian ${meridianMap[diagnosis.element as keyof typeof meridianMap]} and acupuncture points ${diagnosis.points}. Integrate Twelve Magic Points style from Richard Tan.`;
    onGenerateImage(prompt);
  };

  const exportPDF = () => {
    if (!diagnosis) return;
    const doc = new jsPDF();
    doc.setFontSize(18);
    doc.text('TCM Wu Xing Pro Diagnosis Report', 20, 20);
    doc.setFontSize(12);
    doc.text(`Element: ${diagnosis.element}`, 20, 40);
    doc.text(`Imbalance: ${diagnosis.imbalance}`, 20, 50);
    doc.text(`Recommended Points (Twelve and Twelve Integration): ${diagnosis.points}`, 20, 60);
    doc.text(`Meridian: ${meridianMap[diagnosis.element as keyof typeof meridianMap]}`, 20, 70);
    doc.save('tcm_wuxing_report.pdf');
  };

  return (
    <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-lg animate-fade-in-up">
      <h3 className="text-xl font-bold mb-4 text-pink-800 dark:text-pink-300">
        {t('tcmWuXingProTitle') || 'TCM Wu Xing Pro Mode'}
      </h3>
      <textarea
        value={symptoms}
        onChange={(e) => setSymptoms(e.target.value)}
        placeholder={t('enterSymptoms') || 'Enter symptoms (e.g., anger, digestion issues)'}
        className="w-full p-4 border rounded-lg mb-4"
      />
      <button onClick={diagnose} className="px-6 py-3 bg-pink-500 text-white rounded-lg mr-4">
        {t('diagnose') || 'Diagnose'}
      </button>
      {diagnosis && (
        <>
          <div className="mt-4 p-4 bg-pink-100 dark:bg-pink-900 rounded-lg">
            <p><strong>Element:</strong> {diagnosis.element}</p>
            <p><strong>Imbalance:</strong> {diagnosis.imbalance}</p>
            <p><strong>Meridian:</strong> {meridianMap[diagnosis.element as keyof typeof meridianMap]}</p>
            <p><strong>Recommended Points:</strong> {diagnosis.points} (Integrated with Tan's Twelve Magic Points)</p>
          </div>
          <button onClick={generateImagePrompt} className="px-6 py-3 bg-purple-500 text-white rounded-lg mr-4 mt-4">
            {t('generateImage') || 'Generate TCM Image'}
          </button>
          <button onClick={exportPDF} className="px-6 py-3 bg-green-500 text-white rounded-lg mt-4">
            {t('exportPDF') || 'Export Report PDF'}
          </button>
        </>
      )}
    </div>
  );
};

export default TCMWuXingProPanel;

