  ];

  const relationships: Record<string, { mother: string, child: string, controls: string, controlledBy: string }> = {
    wood: { mother: 'Water', child: 'Fire', controls: 'Earth', controlledBy: 'Metal' },
    fire: { mother: 'Wood', child: 'Earth', controls: 'Metal', controlledBy: 'Water' },
    earth: { mother: 'Fire', child: 'Metal', controls: 'Water', controlledBy: 'Wood' },
    metal: { mother: 'Earth', child: 'Water', controls: 'Wood', controlledBy: 'Fire' },
    water: { mother: 'Metal', child: 'Wood', controls: 'Fire', controlledBy: 'Earth' }
  };

  if (!isOpen) return null;

  const getOrganData = (name: string): OrganDetail | undefined => {
    return TCM_DB.organ_details[name];
  };

  const isPathRelevant = (startLabel: string, endLabel: string) => {
    if (!selectedElement) return true;
    return startLabel === selectedElement || endLabel === selectedElement;
  };

  const renderArrow = (start: any, end: any, type: 'generating' | 'controlling', key: string) => {
    if (activeCycle !== 'all' && activeCycle !== type) return null;

    const isRelevant = isPathRelevant(start.label, end.label);
    const opacity = selectedElement ? (isRelevant ? 1 : 0.1) : 1;

    const angle = Math.atan2(end.y - start.y, end.x - start.x);
    const r = 13; // radius of node circle + margin
    const x1 = start.x + r * Math.cos(angle);
    const y1 = start.y + r * Math.sin(angle);
    const x2 = end.x - (r + 2) * Math.cos(angle);
    const y2 = end.y - (r + 2) * Math.sin(angle);

    const color = type === 'generating' ? '#10b981' : '#f43f5e';
    const width = type === 'generating' ? 2 : 1.5;
    // Longer dashes for generating, shorter for controlling
    const dash = type === 'generating' ? '8 4' : '4 4';

    // Use standard style for animation to ensure it works across environments
    const animationStyle = (activeCycle === type || activeCycle === 'all') 
        ? { animation: 'flow 1.5s linear infinite' } 
        : {};

    // Pause animation if element selected but path not relevant
    if (selectedElement && !isRelevant) {
        (animationStyle as any).animationPlayState = 'paused';
    }

    return (
      <line
        key={key}
        x1={x1} y1={y1}
        x2={x2} y2={y2}
        stroke={color}
        strokeWidth={width}
        strokeDasharray={dash}
        strokeLinecap="round"
        opacity={opacity}
        markerEnd={`url(#arrow-${type})`}
        style={animationStyle}
        className="transition-opacity duration-300"
      />
    );
  };

  const selectedNode = elements.find(e => e.label === selectedElement?.toUpperCase());
  const selectedRel = selectedElement ? relationships[selectedElement.toLowerCase()] : null;

  const OrganDetailCard = ({ name, isFu, color }: { name: string, isFu?: boolean, color: string }) => {
    const data = getOrganData(name);
    if (!data) return null;

    return (
      <div className={`mb-3 p-4 rounded-xl shadow-sm border border-slate-700/50 ${isFu ? 'bg-slate-800/50' : 'bg-slate-800'}`}>
        <div className="flex justify-between items-start mb-2" style={{ borderLeft: isFu ? 'none' : `4px solid ${color}`, paddingLeft: isFu ? 0 : '0.5rem' }}>
          <div className="flex flex-col">
            <h4 className={`text-base font-bold ${isFu ? 'text-slate-300' : 'text-slate-200'}`}>
              {data.name} 
              <span className={`text-[10px] ml-2 px-1.5 py-0.5 rounded uppercase ${isFu ? 'bg-slate-700 text-slate-400' : 'bg-slate-700 text-white'}`}>
                {isFu ? 'FU (Yang)' : 'ZANG (Yin)'}
              </span>
            </h4>
            {data.spirit && (
               <span className="text-[10px] text-indigo-300 font-semibold mt-0.5 tracking-wide">
                 Spirit: {data.spirit}
               </span>
            )}
          </div>
          <span className="text-[10px] text-slate-500 bg-slate-900 px-2 py-1 rounded-full whitespace-nowrap border border-slate-800">
            {data.time_of_day}
          </span>
        </div>

        {data.description && (
          <p className="text-xs text-slate-300 italic mb-3 leading-relaxed opacity-90">
             {data.description}
          </p>
        )}

        <div className="space-y-2 text-xs text-slate-400 mt-2">
          <ul className="list-disc list-inside space-y-1 ml-1 mb-3">
             {data.main_functions.map((f, i) => <li key={i}>{f}</li>)}
          </ul>

          <div className="grid grid-cols-2 gap-x-4 gap-y-2 pt-3 border-t border-slate-700/50 text-[10px] sm:text-xs">
            {data.emotion && <div className="flex justify-between"><span className="text-slate-500">Emotion:</span> <span className="text-slate-300 font-medium">{data.emotion}</span></div>}
            {data.season && <div className="flex justify-between"><span className="text-slate-500">Season:</span> <span className="text-slate-300">{data.season}</span></div>}
            {data.sense_organ && <div className="flex justify-between"><span className="text-slate-500">Sense:</span> <span className="text-slate-300">{data.sense_organ}</span></div>}
            {data.tissues && <div className="flex justify-between"><span className="text-slate-500">Tissues:</span> <span className="text-slate-300">{data.tissues}</span></div>}
            {data.flavor && <div className="flex justify-between"><span className="text-slate-500">Flavor:</span> <span className="text-slate-300">{data.flavor}</span></div>}
            {data.manifests_in && <div className="flex justify-between"><span className="text-slate-500">Manifests:</span> <span className="text-slate-300">{data.manifests_in}</span></div>}
            {data.climate && <div className="flex justify-between"><span className="text-slate-500">Climate:</span> <span className="text-slate-300">{data.climate}</span></div>}
            {data.color && <div className="flex justify-between"><span className="text-slate-500">Color:</span> <span className="text-slate-300">{data.color}</span></div>}

            {data.sound && <div className="flex justify-between"><span className="text-slate-500">Sound:</span> <span className="text-slate-300">{data.sound}</span></div>}
            {data.smell && <div className="flex justify-between"><span className="text-slate-500">Smell:</span> <span className="text-slate-300">{data.smell}</span></div>}
            {data.direction && <div className="flex justify-between"><span className="text-slate-500">Direction:</span> <span className="text-slate-300">{data.direction}</span></div>}
          </div>

           {data.paired_organ && (
              <div className="mt-3 pt-2 border-t border-slate-700/50 flex items-center justify-between text-xs">
                  <span className="text-slate-500 font-semibold">Paired Organ:</span>
                  <span className="text-tcm-primary font-medium">{data.paired_organ}</span>
              </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-5xl rounded-2xl shadow-2xl flex flex-col h-[90vh] md:h-[85vh]">

        {/* Header */}
        <div className="flex items-center justify-between p-4 border-b border-slate-800 bg-slate-900 shrink-0 rounded-t-2xl">
          <div className="flex flex-col">
            <h2 className="text-xl font-bold text-tcm-primary flex items-center gap-2">
              Wu Xing Interactive Map
            </h2>
            <p className="text-xs text-slate-400 hidden sm:block">Explore the relationships between the Five Elements and Zang-Fu Organs</p>
          </div>
          <button onClick={onClose} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-full transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>

        {/* Content Body */}
        <div className="flex-1 overflow-hidden flex flex-col md:flex-row">

          {/* LEFT: Diagram */}
          <div className="md:w-7/12 relative bg-gradient-to-br from-slate-900 to-slate-800/50 flex items-center justify-center p-4 min-h-[300px] border-b md:border-b-0 md:border-r border-slate-800">
            <svg viewBox="0 0 100 100" className="w-full h-full max-h-[500px] select-none filter drop-shadow-xl">
              <defs>
                <marker id="arrow-generating" markerWidth="6" markerHeight="6" refX="5" refY="3" orient="auto">
                  <path d="M0,0 L0,6 L6,3 z" fill="#10b981" />
                </marker>
                <marker id="arrow-controlling" markerWidth="6" markerHeight="6" refX="5" refY="3" orient="auto">
                  <path d="M0,0 L0,6 L6,3 z" fill="#f43f5e" />
                </marker>
              </defs>

              {/* Connecting Lines */}
              {renderArrow(positions.wood, positions.fire, 'generating', 'wood-fire')}
              {renderArrow(positions.fire, positions.earth, 'generating', 'fire-earth')}
              {renderArrow(positions.earth, positions.metal, 'generating', 'earth-metal')}
              {renderArrow(positions.metal, positions.water, 'generating', 'metal-water')}
              {renderArrow(positions.water, positions.wood, 'generating', 'water-wood')}

              {renderArrow(positions.wood, positions.earth, 'controlling', 'wood-earth')}
              {renderArrow(positions.earth, positions.water, 'controlling', 'earth-water')}
              {renderArrow(positions.water, positions.fire, 'controlling', 'water-fire')}
              {renderArrow(positions.fire, positions.metal, 'controlling', 'fire-metal')}
              {renderArrow(positions.metal, positions.wood, 'controlling', 'metal-wood')}

              {/* Nodes */}
              {elements.map((el) => {
                const isSelected = selectedElement === el.label;
                const isDimmed = selectedElement && !isSelected;

                return (
                  <g 
                    key={el.id} 
                    className="cursor-pointer transition-all duration-300 hover:opacity-100" 
                    onClick={() => setSelectedElement(isSelected ? null : el.label)}
                    style={{ opacity: isDimmed ? 0.3 : 1 }}
                  >
                    {/* Glow ring */}
                    {isSelected && (
                       <circle cx={el.x} cy={el.y} r="18" fill="none" stroke={el.color} strokeWidth="0.5" strokeDasharray="3,3" className="animate-spin-slow" />
                    )}

                    <circle 
                      cx={el.x} cy={el.y} 
                      r={isSelected ? "14" : "12"} 
                      fill={isSelected ? el.color : "#1e293b"} 
                      stroke={el.color} 
                      strokeWidth={isSelected ? "0" : "2"} 
                      className="transition-all duration-300"
                    />
                    <text x={el.x} y={el.y - 0.5} textAnchor="middle" fontSize="2.8" fill={isSelected ? '#1e293b' : el.color} fontWeight="900" letterSpacing="0.5" pointerEvents="none">{el.label}</text>

                    <text x={el.x} y={el.y + 3} textAnchor="middle" fontSize="2.2" fill={isSelected ? 'white' : '#cbd5e1'} fontWeight="bold" pointerEvents="none">
                      {el.zang}
                    </text>

                    {el.zang2 && (
                       <text x={el.x} y={el.y + 5.2} textAnchor="middle" fontSize="2.2" fill={isSelected ? 'white' : '#cbd5e1'} fontWeight="bold" pointerEvents="none">
                         & {el.zang2}
                       </text>
                    )}

                    <text x={el.x} y={el.y + (el.zang2 ? 8 : 6)} textAnchor="middle" fontSize="2" fill={isSelected ? '#e2e8f0' : '#64748b'} pointerEvents="none">
                      {el.fu}
                    </text>
                  </g>
                );
              })}
            </svg>

            {/* Legend for Diagram */}
            <div className="absolute bottom-4 left-4 bg-slate-900/80 p-2 rounded-lg border border-slate-700/50 backdrop-blur-sm text-[10px]">
               <div className="flex items-center gap-2 mb-1">
                 <div className="w-4 h-0.5 bg-emerald-500 rounded-full"></div>
                 <span className="text-slate-300">Generating (Mother-Child)</span>
               </div>
               <div className="flex items-center gap-2">
                 <div className="w-4 h-0.5 border-t border-rose-500 border-dashed"></div>
                 <span className="text-slate-300">Controlling (Grandparent)</span>
               </div>
            </div>
          </div>

          {/* RIGHT: Detail Panel */}
          <div className="md:w-5/12 bg-slate-900 flex flex-col h-full overflow-hidden">

            {!selectedElement && (
               <div className="p-6 h-full flex flex-col justify-center animate-fade-in">
                  <div className="bg-slate-800/50 p-5 rounded-2xl border border-slate-700/50 mb-6">
                    <h3 className="text-sm font-bold text-white mb-4 flex items-center gap-2">
                      <Info className="w-4 h-4 text-tcm-accent" /> Filter Relationships
                    </h3>
                    <div className="space-y-2">
                      <button 
                        onClick={() => setActiveCycle('all')}
                        className={`w-full text-left px-4 py-3 rounded-xl text-sm font-medium transition-all border ${activeCycle === 'all' ? 'bg-indigo-900/30 border-indigo-500 text-indigo-300' : 'border-slate-700 text-slate-400 hover:bg-slate-800'}`}
                      >
                        Show All Cycles
                      </button>
                      <button 
                        onClick={() => setActiveCycle('generating')}
                        className={`w-full text-left px-4 py-3 rounded-xl text-sm font-medium transition-all border flex items-center justify-between ${activeCycle === 'generating' ? 'bg-emerald-900/20 border-emerald-500 text-emerald-400' : 'border-slate-700 text-slate-400 hover:bg-slate-800'}`}
                      >
                        <span>Generating (Mother-Child)</span>
                        <Info className="w-4 h-4 opacity-50" />
                      </button>
                      <button 
                        onClick={() => setActiveCycle('controlling')}
                        className={`w-full text-left px-4 py-3 rounded-xl text-sm font-medium transition-all border flex items-center justify-between ${activeCycle === 'controlling' ? 'bg-rose-900/20 border-rose-500 text-rose-400' : 'border-slate-700 text-slate-400 hover:bg-slate-800'}`}
                      >
                        <span>Controlling (Grandparent)</span>
                        <Info className="w-4 h-4 opacity-50" />
                      </button>
                    </div>
                  </div>

                  {/* NEW EXPLANATION SECTION */}
                  <div className="bg-slate-800/30 p-4 rounded-xl border border-slate-700/30 mb-6">
                    <h4 className="font-bold text-slate-300 text-sm mb-3">Cycle Principles & Clinical Importance</h4>
                    <div className="space-y-4 text-xs">
                        <div className="flex gap-3">
                            <div className="mt-1 w-2 h-2 rounded-full bg-emerald-500 shrink-0 shadow-[0_0_8px_rgba(16,185,129,0.5)]"></div>
                            <div>
                                <strong className="text-emerald-400 block mb-1 text-sm">Generating (Sheng) • "Mother-Child"</strong>
                                <p className="text-slate-300 leading-relaxed mb-1">
                                  A cycle of creation where one element promotes the growth of the next (e.g., Wood fuels Fire).
                                </p>
                                <p className="text-slate-500 italic">
                                  <strong>Clinical:</strong> Used for deficiency. "Tonify the Mother to strengthen the Child" (e.g., tonify Kidney Water to help Liver Wood).
                                </p>
                            </div>
                        </div>
                        <div className="flex gap-3">
                            <div className="mt-1 w-2 h-2 rounded-full bg-rose-500 shrink-0 shadow-[0_0_8px_rgba(244,63,94,0.5)]"></div>
                            <div>
                                <strong className="text-rose-400 block mb-1 text-sm">Controlling (Ke) • "Grandparent-Grandchild"</strong>
                                <p className="text-slate-300 leading-relaxed mb-1">
                                  A cycle of restraint ensuring no element becomes too excessive (e.g., Water extinguishes Fire).
                                </p>
                                <p className="text-slate-500 italic">
                                  <strong>Clinical:</strong> Used for excess or disharmony. Pathologies arise when control is too strong (Overacting) or reversed (Insulting).
                                </p>
                            </div>
                        </div>
                    </div>
                  </div>

                  <div className="text-center text-slate-500 text-sm">
                    Tap any <span className="text-tcm-primary font-bold">Element Node</span> on the map<br/>to view detailed Zang-Fu organ information.
                  </div>
               </div>
            )}

            {selectedNode && (
               <div className="flex-1 overflow-y-auto p-4 animate-slide-in-right scrollbar-hide">
                 <button 
                   onClick={() => setSelectedElement(null)}
                   className="text-xs text-tcm-primary hover:text-white flex items-center gap-1 mb-4 font-semibold uppercase tracking-wider sticky top-0 bg-slate-900 py-2 z-10 w-full border-b border-slate-800"
                 >
                   &larr; Back to Map
                 </button>

                 <div className="flex items-center gap-3 mb-6">
                   <div className="p-3 rounded-full bg-slate-800 border border-slate-700" style={{ color: selectedNode.color }}>
                      {selectedNode.id === 'fire' && <Flame className="w-6 h-6" />}
                      {selectedNode.id === 'earth' && <Mountain className="w-6 h-6" />}
                      {selectedNode.id === 'metal' && <Wind className="w-6 h-6" />}
                      {selectedNode.id === 'water' && <Droplets className="w-6 h-6" />}
                      {selectedNode.id === 'wood' && <Leaf className="w-6 h-6" />}
                   </div>
                   <div>
                     <h3 className="text-3xl font-black tracking-tight text-white">
                       {selectedElement}
                     </h3>
                     <span className="text-sm text-slate-500 font-medium">Element Properties</span>
                   </div>
                 </div>

                 {selectedRel && (
                   <div className="mb-6 bg-slate-800/50 rounded-xl p-3 border border-slate-700/50">
                     <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">Cycle Relationships</h4>
                     <div className="grid grid-cols-2 gap-3">
                        <div className="bg-emerald-900/10 p-2 rounded border border-emerald-900/30">
                          <div className="text-[10px] uppercase text-emerald-500 font-bold mb-1 flex items-center gap-1"><RefreshCw className="w-3 h-3"/> Generates</div>
                          <div className="text-sm text-slate-300 font-medium flex items-center gap-1">Child: <span className="text-white">{selectedRel.child}</span></div>
                        </div>
                        <div className="bg-emerald-900/10 p-2 rounded border border-emerald-900/30">
                          <div className="text-[10px] uppercase text-emerald-500 font-bold mb-1 flex items-center gap-1"><RefreshCw className="w-3 h-3"/> Generated By</div>
                          <div className="text-sm text-slate-300 font-medium flex items-center gap-1">Mother: <span className="text-white">{selectedRel.mother}</span></div>
                        </div>
                        <div className="bg-rose-900/10 p-2 rounded border border-rose-900/30">
                          <div className="text-[10px] uppercase text-rose-500 font-bold mb-1 flex items-center gap-1"><ShieldAlert className="w-3 h-3"/> Controls</div>
                          <div className="text-sm text-slate-300 font-medium flex items-center gap-1"> <ArrowRight className="w-3 h-3"/> <span className="text-white">{selectedRel.controls}</span></div>
                        </div>
                        <div className="bg-rose-900/10 p-2 rounded border border-rose-900/30">
                          <div className="text-[10px] uppercase text-rose-500 font-bold mb-1 flex items-center gap-1"><ShieldAlert className="w-3 h-3"/> Controlled By</div>
                          <div className="text-sm text-slate-300 font-medium flex items-center gap-1"> <ArrowRight className="w-3 h-3"/> <span className="text-white">{selectedRel.controlledBy}</span></div>
                        </div>
                     </div>
                   </div>
                 )}

                 <div className="space-y-4">
                    <OrganDetailCard name={selectedNode.zang} color={selectedNode.color} />
                    {selectedNode.zang2 && <OrganDetailCard name={selectedNode.zang2} color={selectedNode.color} />}
                    <OrganDetailCard name={selectedNode.fu} color={selectedNode.color} isFu />
                    {selectedNode.fu2 && <OrganDetailCard name={selectedNode.fu2} color={selectedNode.color} isFu /> }
                 </div>
               </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

