                    disabled={isLoading || (!inputText.trim() && !selectedImage)}
                    className="p-3 bg-tcm-primary hover:bg-tcm-secondary text-white rounded-full transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-tcm-primary/20"
                  >
                    <Send className="w-5 h-5" />
                  </button>
                </div>
              </div>
           </div>
        )}

        {activePanel === 'diagnosis' && (
           <div className="flex-1 min-h-0 bg-slate-950 print:h-auto print:overflow-visible print:bg-white print:text-black print:block">
             <ScoringAndPointsHub 
                analysis={cdssResults} 
                onAnalyzeRequest={() => setIsFormOpen(true)}
                initialSyndromeId={linkedSyndromeId ?? undefined}
                isAnalyzing={isAnalyzing}
                onBack={() => setActivePanel('atlas')}
             />
           </div>
        )}

        {activePanel === 'wuxing' && (
          <div className="flex-1 min-h-0 bg-slate-950 overflow-hidden">
             <WuXingMasterPanel 
                onSelectSyndrome={(id) => {
                  setLinkedSyndromeId(id);
                  setActivePanel('diagnosis');
                }}
                onGenerateImage={handleGenerateImage}
                onShowMap={() => setIsVisualizerOpen(true)}
             />
          </div>
        )}

        {activePanel === 'theory' && (
          <div className="flex-1 min-h-0 bg-slate-950 overflow-hidden">
             <YinYangTheoryWindow />
          </div>
        )}

        {activePanel === 'atlas' && (
          <div className="flex-1 min-h-0 bg-slate-950 overflow-hidden">
             <SyndromeAtlasWindow 
                onSelectSyndrome={(id) => {
                  setLinkedSyndromeId(id);
                  setActivePanel('diagnosis');
                }}
             />
          </div>
        )}

        {activePanel === 'stroke' && (
          <div className="flex-1 min-h-0 bg-slate-950 overflow-hidden">
             <StrokeEducationPanel />
          </div>
        )}

      </div>
    </div>
  );
};

