                 {selectedRel && (
                   <div className="mb-6 bg-slate-800/50 rounded-xl p-3 border border-slate-700/50">
                     <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">Cycle Relationships</h4>
                     <div className="grid grid-cols-2 gap-3">
                        <div className="bg-emerald-900/10 p-2 rounded border border-emerald-900/30">
                          <div className="text-[10px] uppercase text-emerald-500 font-bold mb-1 flex items-center gap-1"><RefreshCw className="w-3 h-3"/> Generates</div>
                          <div className="text-sm text-slate-300 font-medium">{selectedRel.child}</div>
                        </div>
                        <div className="bg-emerald-900/10 p-2 rounded border border-emerald-900/30">
                          <div className="text-[10px] uppercase text-emerald-500 font-bold mb-1 flex items-center gap-1"><RefreshCw className="w-3 h-3"/> From</div>
                          <div className="text-sm text-slate-300 font-medium">{selectedRel.mother}</div>
                        </div>
                        <div className="bg-rose-900/10 p-2 rounded border border-rose-900/30">
                          <div className="text-[10px] uppercase text-rose-500 font-bold mb-1 flex items-center gap-1"><ShieldAlert className="w-3 h-3"/> Controls</div>
                          <div className="text-sm text-slate-300 font-medium"><ArrowRight className="w-3 h-3 inline"/> {selectedRel.controls}</div>
                        </div>
                        <div className="bg-rose-900/10 p-2 rounded border border-rose-900/30">
                          <div className="text-[10px] uppercase text-rose-500 font-bold mb-1 flex items-center gap-1"><ShieldAlert className="w-3 h-3"/> By</div>
                          <div className="text-sm text-slate-300 font-medium"><ArrowRight className="w-3 h-3 inline"/> {selectedRel.controlledBy}</div>
                        </div>
                     </div>
                   </div>
                 )}
                 <div className="space-y-4">
                    {selectedNode?.zang && <OrganDetailCard name={selectedNode.zang} color={selectedNode.color} />}
                    {selectedNode?.zang2 && <OrganDetailCard name={selectedNode.zang2} color={selectedNode.color} />}
                    {selectedNode?.fu && <OrganDetailCard name={selectedNode.fu} color={selectedNode.color} isFu />}
                    {selectedNode?.fu2 && <OrganDetailCard name={selectedNode.fu2} color={selectedNode.color} isFu /> }
                 </div>
               </div>
            )}
          </div>
        </div>
    </div>
  );
};

import React, { useState } from 'react';
import { TCM_DB } from '../constants';
import { ArrowRight, Activity, FileText, Sparkles, Printer } from 'lucide-react';
