const twelvePointsExamples = {
  Wood: 'LV-3, GB-41 (Classic)',
  Fire: 'HT-7, PC-3 (Classic)',
  Earth: 'SP-6, ST-36 (Classic)',
  Metal: 'LU-5, LI-11 (Classic)',
  Water: 'KI-3, BL-65 (Classic)',
};

const WuXingMasterPanel: React.FC<Props> = ({ onSelectSyndrome, onGenerateImage, onShowMap }) => {
  const [hoveredElement, setHoveredElement] = useState<string | null>(null);
  const [symptoms, setSymptoms] = useState('');
  const [quickDiagnosis, setQuickDiagnosis] = useState<{ element: string; imbalance: string; points: string; } | null>(null);
  const [diagramSelection, setDiagramSelection] = useState<string | null>(null);

  const allSyndromes = [
    ...TCM_DB.syndromes.FILLED_FROM_PDF,
    ...TCM_DB.syndromes.TODO_FROM_PDF
  ];

  const handleDiagnose = () => {
    const keywords = symptoms.toLowerCase();
    let element = 'Earth'; 
    if (keywords.includes('anger') || keywords.includes('eyes') || keywords.includes('tendon') || keywords.includes('marah')) element = 'Wood';
    else if (keywords.includes('joy') || keywords.includes('heart') || keywords.includes('palpitation') || keywords.includes('insomnia')) element = 'Fire';
    else if (keywords.includes('digestion') || keywords.includes('worry') || keywords.includes('bloating') || keywords.includes('kembung')) element = 'Earth';
    else if (keywords.includes('grief') || keywords.includes('lungs') || keywords.includes('cough') || keywords.includes('skin')) element = 'Metal';
    else if (keywords.includes('fear') || keywords.includes('kidney') || keywords.includes('backache') || keywords.includes('pinggang')) element = 'Water';

    const imbalance = (keywords.includes('weak') || keywords.includes('tired') || keywords.includes('lemah')) ? 'Deficiency (Xu)' : 'Excess (Shi)';
    const points = twelvePointsExamples[element as keyof typeof twelvePointsExamples] || "ST-36, SP-6";

    setQuickDiagnosis({ element, imbalance, points });
  };

  const handleExportPDF = () => {
    if (!quickDiagnosis) return;
    const doc = new jsPDF();
    doc.setFontSize(18);
    doc.text('TCM Wu Xing Pro Diagnosis Report', 20, 20);
    doc.setFontSize(12);
    doc.text(`Element: ${quickDiagnosis.element}`, 20, 40);
    doc.text(`Imbalance: ${quickDiagnosis.imbalance}`, 20, 50);
    doc.text(`Recommended Points: ${quickDiagnosis.points}`, 20, 60);
    doc.text(`Notes: Integrated with Tan's Twelve Magic Points style.`, 20, 70);
    doc.save('tcm_wuxing_report.pdf');
  };

  const handleGenerateImagePrompt = () => {
    if (!quickDiagnosis || !onGenerateImage) return;
    const prompt = `Photorealistic diagram of TCM Wu Xing cycle with highlighted ${quickDiagnosis.element} element, showing meridian flow and acupuncture points ${quickDiagnosis.points}. Cinematic lighting, 8k resolution.`;
    onGenerateImage(prompt);
  };

  const filteredElements = diagramSelection 
    ? elements.filter(el => el.name.toLowerCase() === diagramSelection.toLowerCase()) 
    : elements;

  return (
    <div className="min-h-full bg-black text-white p-6 md:p-10 overflow-y-auto font-sans">

      {/* 1. Quick Analysis Lab */}
      <div className="max-w-4xl mx-auto bg-slate-900 border border-pink-500/30 rounded-2xl p-6 shadow-2xl shadow-pink-900/20 mb-12">
         <div className="flex items-center gap-3 mb-4">
            <Activity className="w-6 h-6 text-pink-500" />
            <h3 className="text-xl font-bold text-pink-100">Wu Xing Pro Lab (Quick Check)</h3>
         </div>

         <div className="flex flex-col md:flex-row gap-4">
            <textarea
              value={symptoms}
              onChange={(e) => setSymptoms(e.target.value)}
              placeholder="Enter symptoms (e.g., anger, red eyes, digestion issues, worry)..."
              className="flex-1 bg-black/50 border border-slate-700 rounded-xl p-4 text-sm text-slate-200 focus:border-pink-500 outline-none resize-none h-32 md:h-auto"
            />
            <div className="flex flex-col gap-2 justify-center">
               <button 
                 onClick={handleDiagnose}
                 className="px-6 py-3 bg-pink-600 hover:bg-pink-500 text-white rounded-xl font-bold transition-colors flex items-center justify-center gap-2"
               >
                 <Activity className="w-4 h-4" /> Diagnose
               </button>
            </div>
         </div>

         {quickDiagnosis && (
            <div className="mt-6 p-4 bg-slate-800/50 rounded-xl border border-slate-700 animate-fade-in">
               <div className="grid grid-cols-3 gap-2 mb-3 text-center">
                  <div><span className="text-[10px] text-slate-500 block">Element</span><span className="text-lg font-bold text-pink-400">{quickDiagnosis.element}</span></div>
                  <div><span className="text-[10px] text-slate-500 block">Status</span><span className="text-lg font-bold text-white">{quickDiagnosis.imbalance}</span></div>
                  <div><span className="text-[10px] text-slate-500 block">Points</span><span className="text-lg font-bold text-emerald-400">{quickDiagnosis.points}</span></div>
               </div>

               <div className="flex gap-2 justify-center pt-2 border-t border-slate-700/50">
                  <button onClick={handleGenerateImagePrompt} className="flex items-center gap-2 px-4 py-2 bg-purple-600 hover:bg-purple-500 text-white rounded-lg text-xs font-bold transition-colors"><Sparkles className="w-3 h-3" /> AI Image</button>
                  <button onClick={handleExportPDF} className="flex items-center gap-2 px-4 py-2 bg-emerald-600 hover:bg-emerald-500 text-white rounded-lg text-xs font-bold transition-colors"><Printer className="w-3 h-3" /> Export PDF</button>
               </div>
            </div>
         )}
      </div>

      {/* 2. Embedded Interactive Diagram */}
      <div className="mb-12 rounded-2xl overflow-hidden border border-slate-800 shadow-2xl bg-slate-900 h-[600px] md:h-[700px]">
         <div className="p-4 bg-slate-900 border-b border-slate-800">
            <h3 className="text-xl font-bold text-emerald-400">Interactive Map</h3>
            <p className="text-xs text-slate-500">Visualize Generating & Controlling Cycles. Select elements below to filter the grid.</p>
         </div>
         <WuXingInteractiveDiagram 
            embedded={true} 
            className="h-full" 
            onElementSelect={setDiagramSelection}
         />
      </div>

      {/* Header */}
      <div className="text-center mb-10 border-t border-slate-900/50 pt-8">
        <h2 className="text-xl md:text-2xl font-bold text-amber-300 uppercase tracking-widest">
          {diagramSelection ? `${diagramSelection} Element Syndromes` : 'Pola Sindrom TCM (Master Grid)'}
        </h2>
        <p className="text-slate-500 text-xs italic mt-1">
          {diagramSelection ? 'Filtered by Interactive Map selection' : 'Berdasarkan Giovanni Maciocia & 5 Elements Theory'}
        </p>
      </div>

      {/* Panel Wu Xing Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-5 gap-6 max-w-7xl mx-auto">
        {filteredElements.map((el) => {
          const elementSyndromes = allSyndromes.filter(s => {
            if (s.wuxing_element && s.wuxing_element.toLowerCase().startsWith(el.name.toLowerCase())) return true;
            const text = (s.name_en || "") + " " + (s.name_id || "") + " " + (s.primary_organs || []).join(" ");
            return el.keywords.some(k => text.includes(k));
          });

          const isHovered = hoveredElement === el.name;

          return (
            <div 
              key={el.name}
              className={`relative bg-gradient-to-b from-slate-900 to-black rounded-2xl p-6 border transition-all duration-300 group
                ${isHovered ? `${el.borderColor} shadow-2xl ${el.shadowColor} scale-105 z-10` : 'border-slate-800'}`}
              onMouseEnter={() => setHoveredElement(el.name)}
              onMouseLeave={() => setHoveredElement(null)}
            >
              <h3 className={`text-2xl font-black text-center mb-6 uppercase tracking-wider ${el.color}`}>
                {el.display}
              </h3>

              <div className="space-y-3">
                {elementSyndromes.map(s => (
                  <div 
                    key={s.id}
                    onClick={() => onSelectSyndrome?.(s.id)}
                    className="bg-slate-900/70 rounded-lg p-3.5 border border-slate-800 hover:border-white/40 cursor-pointer transition-all group/item flex justify-between items-center"
                  >
                    <div>
                      <p className={`font-bold text-sm ${el.color} group-hover/item:text-white transition-colors`}>
                        {s.name_id}
                      </p>
                      <p className="text-slate-500 text-xs italic">
                        {s.name_en}
                      </p>
                    </div>
                    <ArrowRight className="w-4 h-4 opacity-0 group-hover/item:opacity-100 transition-opacity text-white/60" />
                  </div>
                ))}

                {elementSyndromes.length === 0 && (
                  <p className="text-center text-slate-700 text-xs py-6">Belum ada data</p>
                )}
              </div>
            </div>
          );
        })}
      </div>

      <div className="text-center mt-20 pt-10 border-t border-slate-900 text-xs text-slate-600">
        TCM WuXing Pro v{TCM_DB.metadata.version}
      </div>
    </div>
  );
};

