const WuXingMasterPanel: React.FC<Props> = ({ onSelectSyndrome, onGenerateImage, onShowMap, isLoading = false }) => {
  const [hoveredElement, setHoveredElement] = useState<string | null>(null);
  const [diagramSelection, setDiagramSelection] = useState<string | null>(null);

  if (isLoading) {
    return (
      <div className="h-full flex flex-col items-center justify-center bg-black text-white p-6 animate-fade-in">
        <Loader2 className="w-16 h-16 text-emerald-500 animate-spin mb-6" />
        <h3 className="text-2xl font-bold text-emerald-400 tracking-wider">Loading Wu Xing Master...</h3>
        <p className="text-slate-500 text-sm mt-2 font-mono">Synchronizing 5 Elements Data</p>
      </div>
    );
  }

  const allSyndromes = [
    ...TCM_DB.syndromes.FILLED_FROM_PDF,
    ...TCM_DB.syndromes.TODO_FROM_PDF
  ];

  const filteredElements = diagramSelection 
    ? elements.filter(el => el.name.toLowerCase() === diagramSelection.toLowerCase()) 
    : elements;

  return (
    <div className="min-h-full bg-black text-white p-6 md:p-10 overflow-y-auto font-sans">

      {/* Embedded Interactive Diagram */}
      <div className="mb-12 rounded-2xl overflow-hidden border border-slate-800 shadow-2xl bg-slate-900 h-[600px] md:h-[700px]">
         <div className="p-4 bg-slate-900 border-b border-slate-800">
            <h3 className="text-xl font-bold text-emerald-400">Interactive Map</h3>
            <p className="text-xs text-slate-500">Visualize Generating & Controlling Cycles. Select elements below to filter the grid.</p>
         </div>
         <WuXingInteractiveDiagram 
            embedded={true} 
            className="h-full" 
            onElementSelect={setDiagramSelection}
         />
      </div>

      {/* Header */}
      <div className="text-center mb-10 border-t border-slate-900/50 pt-8">
        <h2 className="text-xl md:text-2xl font-bold text-amber-300 uppercase tracking-widest">
          {diagramSelection ? `${diagramSelection} Element Syndromes` : 'Pola Sindrom TCM (Master Grid)'}
        </h2>
        <p className="text-slate-500 text-xs italic mt-1">
          {diagramSelection ? 'Filtered by Interactive Map selection' : 'Berdasarkan Giovanni Maciocia & 5 Elements Theory'}
        </p>
      </div>

      {/* Panel Wu Xing Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-5 gap-6 max-w-7xl mx-auto">
        {filteredElements.map((el) => {
          const elementSyndromes = allSyndromes.filter(s => {
            if (s.wuxing_element && s.wuxing_element.toLowerCase().startsWith(el.name.toLowerCase())) return true;
            const text = (s.name_en || "") + " " + (s.name_id || "") + " " + (s.primary_organs || []).join(" ");
            return el.keywords.some(k => text.includes(k));
          });

          const isHovered = hoveredElement === el.name;

          return (
            <div 
              key={el.name}
              className={`relative bg-gradient-to-b from-slate-900 to-black rounded-2xl p-6 border transition-all duration-300 group
                ${isHovered ? `${el.borderColor} shadow-2xl ${el.shadowColor} scale-105 z-10` : 'border-slate-800'}`}
              onMouseEnter={() => setHoveredElement(el.name)}
              onMouseLeave={() => setHoveredElement(null)}
            >
              <h3 className={`text-2xl font-black text-center mb-6 uppercase tracking-wider ${el.color}`}>
                {el.display}
              </h3>

              <div className="space-y-3">
                {elementSyndromes.map(s => (
                  <div 
                    key={s.id}
                    onClick={() => onSelectSyndrome?.(s.id)}
                    className="bg-slate-900/70 rounded-lg p-3.5 border border-slate-800 hover:border-white/40 cursor-pointer transition-all group/item flex justify-between items-center"
                  >
                    <div>
                      <p className={`font-bold text-sm ${el.color} group-hover/item:text-white transition-colors`}>
                        {s.name_id}
                      </p>
                      <p className="text-slate-500 text-xs italic">
                        {s.name_en}
                      </p>
                    </div>
                    <ArrowRight className="w-4 h-4 opacity-0 group-hover/item:opacity-100 transition-opacity text-white/60" />
                  </div>
                ))}

                {elementSyndromes.length === 0 && (
                  <p className="text-center text-slate-700 text-xs py-6">Belum ada data</p>
                )}
              </div>
            </div>
          );
        })}
      </div>

      <div className="text-center mt-20 pt-10 border-t border-slate-900 text-xs text-slate-600">
        TCM WuXing Pro v{TCM_DB.metadata.version}
      </div>
    </div>
  );
};

