const DB_KEY_USERS = 'tcm_pro_users';

// Default Seed Data
const DEFAULT_ADMIN: UserAccount = {
  username: 'admin',
  password: 'admin123', // Changed for easier access/demo, can be changed later
  role: 'admin',
  createdAt: Date.now()
};

export const db = {
  users: {
    // Fetch all users from storage
    getAll: (): UserAccount[] => {
      if (typeof window === 'undefined') return [];
      try {
        const stored = localStorage.getItem(DB_KEY_USERS);
        if (!stored) {
            // Initialize with admin if empty
            const initial = [DEFAULT_ADMIN];
            localStorage.setItem(DB_KEY_USERS, JSON.stringify(initial));
            return initial;
        }
        return JSON.parse(stored);
      } catch (e) {
        console.error("Database Read Error:", e);
        return [];
      }
    },

    // Save full list to storage
    saveAll: (users: UserAccount[]) => {
      if (typeof window === 'undefined') return;
      localStorage.setItem(DB_KEY_USERS, JSON.stringify(users));
    },

    // Add a single user
    add: (user: UserAccount): boolean => {
       const users = db.users.getAll();
       if (users.some(u => u.username.toLowerCase() === user.username.toLowerCase())) {
           return false; // Duplicate
       }
       users.push(user);
       db.users.saveAll(users);
       return true;
    },

    // Delete a user
    delete: (username: string): boolean => {
        const users = db.users.getAll();
        const newUsers = users.filter(u => u.username !== username);
        if (newUsers.length === users.length) return false; // Not found
        db.users.saveAll(newUsers);
        return true;
    }
  }
};

import { UserAccount } from '../types';
import { db } from './db';

// Ensure DB is initialized
export const getUsers = (): UserAccount[] => {
  return db.users.getAll();
};

export const saveUser = (user: UserAccount): { success: boolean, message: string } => {
  // Simple validation
  if (!user.username || !user.password) {
      return { success: false, message: 'Username and password are required.' };
  }

  const success = db.users.add(user);
  if (success) {
      return { success: true, message: 'User successfully saved to database.' };
  } else {
      return { success: false, message: 'Username already exists.' };
  }
};

export const deleteUser = (username: string): { success: boolean, message: string } => {
  if (username === 'admin') {
      return { success: false, message: 'Cannot delete the main admin account.' };
  }

  const success = db.users.delete(username);
  if (success) {
      return { success: true, message: 'User deleted from database.' };
  } else {
      return { success: false, message: 'User not found.' };
  }
};

export const login = (username: string, password: string): UserAccount | null => {
  const users = getUsers();
  const user = users.find(u => u.username === username && u.password === password);
  return user || null;
};

