const App: React.FC = () => {
  // --- AUTHENTICATION STATE ---
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);

  const [activePanel, setActivePanel] = useState<'chat' | 'diagnosis' | 'theory' | 'stroke' | 'atlas' | 'wuxing'>('chat');
  const [linkedSyndromeId, setLinkedSyndromeId] = useState<string | null>(null);

  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: 'Selamat datang di TCM WuXing Pro. Silakan isi form pasien (tombol papan klip) atau ceritakan keluhan Anda untuk diagnosis.',
      timestamp: new Date()
    }
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false); // New state for CDSS analysis
  const [selectedLanguage, setSelectedLanguage] = useState<Language>(Language.INDONESIAN);
