  const [isVisualizerOpen, setIsVisualizerOpen] = useState(false);
  const [isUserMgmtOpen, setIsUserMgmtOpen] = useState(false);
  const [visualizerHighlight, setVisualizerHighlight] = useState<string | null>(null);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [cdssResults, setCdssResults] = useState<ScoredSyndrome[]>([]);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    if (activePanel === 'chat') {
        scrollToBottom();
    }
  }, [messages, activePanel]);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
    // Reset input value
    if (fileInputRef.current) {
        fileInputRef.current.value = '';
    }
  };

  const handleSendMessage = async (textOverride?: string, analysis?: ScoredSyndrome[]) => {
    const textToSend = textOverride || inputText;
    const imageToSend = textOverride ? undefined : (selectedImage || undefined);

    if ((!textToSend.trim() && !imageToSend) || isLoading) return;

    const userMessage: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend,
      image: imageToSend,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setSelectedImage(null);
    setIsLoading(true);

    try {
      const response = await sendMessageToGemini(textToSend, imageToSend, messages, selectedLanguage, isPregnant, analysis || cdssResults);

      const botMessage: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response.conversationalResponse,
        timestamp: new Date(),
        tcmResult: response.diagnosis
      };

      setMessages(prev => [...prev, botMessage]);
    } catch (error) {
      const errorMessage: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Maaf, terjadi kesalahan koneksi atau analisis. Silakan coba lagi.",
        timestamp: new Date(),
        isError: true
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleFormSubmit = (data: any) => {
    setIsAnalyzing(true);
    setActivePanel('diagnosis'); // Switch immediately so user sees the loader in the hub

    // Simulate async process for better UX (so spinner shows for a bit)
    setTimeout(() => {
        // 1. Run Deterministic CDSS Analysis
        const results = analyzePatient({
            identity: {
                patient_name: "Anonymous",
                visit_date: new Date().toISOString(),
                address: "",
                age: data.age,
                sex: data.sex
            },
            chief_complaint: data.complaint,
            selected_symptoms: [], 
            body_region_selector: data.body_region_selector || [], 
            tongue: data.tongue,
            pulse: data.pulse,
            isAcuteMode: data.isAcuteMode
        } as any);

        setCdssResults(results);
