        <div className="p-5">
           <h1 className="text-xl font-black bg-gradient-to-r from-tcm-primary to-tcm-accent bg-clip-text text-transparent flex items-center gap-2">
              <Activity className="w-6 h-6 text-tcm-primary" />
              TCM WuXing
           </h1>
           <p className="text-[10px] text-slate-500 mt-1 uppercase tracking-widest font-semibold flex items-center gap-1">
             <Shield className="w-3 h-3 text-emerald-500" /> {currentUser.role === 'admin' ? 'Admin Access' : 'Pro License'}
           </p>
