// === CONSTANTS FOR AUTO POINTS ===
const ORGAN_TO_CHANNEL: Record<string, string> = {
  Lung: "LU", Heart: "HT", Pericardium: "PC", Spleen: "SP", Liver: "LR", Kidney: "KI",
  "Large Intestine": "LI", "Small Intestine": "SI", Stomach: "ST", "GallBladder": "GB", "Gall Bladder": "GB", Bladder: "BL",
  "San Jiao": "TE", "SanJiao": "TE", "Triple Burner": "TE"
};

const MOTHER_OF: Record<string, string> = { Wood: "Water", Fire: "Wood", Earth: "Fire", Metal: "Earth", Water: "Metal" };
const CHILD_OF: Record<string, string> = { Wood: "Fire", Fire: "Earth", Earth: "Metal", Metal: "Water", Water: "Wood" };

// === HELPER FUNCTIONS ===

function patternFlags(patternType: string, name_en: string) {
  const t = (patternType || "").toLowerCase();
  const n = (name_en || "").toLowerCase();
  const isDef = t.includes("def") || t.includes("deficiency") || n.includes("deficiency") || t.includes("qi_not_firm") || t.includes("not_receiving");
  const isExcess = t.includes("full") || t.includes("excess") || t.includes("damp") || t.includes("phlegm") || t.includes("fire") || t.includes("stasis") || t.includes("invasion") || t.includes("obstruction");
  const hasHeat = t.includes("heat") || t.includes("fire") || n.includes("heat");
  const hasCold = t.includes("cold") || n.includes("cold");
  return { isDef, isExcess, hasHeat, hasCold };
}

function buildAutoPointsForSyndrome(s: DbSyndrome) {
  const pts: { code: string; role: string; note?: string }[] = [];
  const tables = TCM_DB.special_point_tables;
  const specTables = TCM_DB.tcm_specific_points;
  const organs = s.primary_organs || [];
  const flags = patternFlags(s.pattern_type, s.name_en);

  // 1) Back-Shu dan Yuan-Source organ utama
  organs.forEach((org) => {
    const channel = ORGAN_TO_CHANNEL[org];
    if (!channel) return;

    // Handle inconsistent naming in DB (LU vs Lung)
    const shortOrg = channel; 

    const shu = tables.back_shu_points?.[shortOrg] as string | undefined;
    const yuan = tables.yuan_source_points?.[channel] as string | undefined;

    if (shu) {
      pts.push({
        code: shu,
        role: "back_shu",
        note: `Back-Shu ${org} – titik kausal organ.`,
      });
    }
    if (yuan) {
      pts.push({
        code: yuan,
        role: "yuan_source",
        note: `Yuan-Source channel ${channel} – menyeimbangkan Qi organ.`,
      });
    }
  });

  // 2) Wu Xing Mother / Child
  if (s.wuxing_element) {
    const element = s.wuxing_element.split(" ")[0]; // e.g. "Wood"
    const channel = organs.length > 0 ? ORGAN_TO_CHANNEL[organs[0]] : undefined;

    if (channel && specTables && specTables.five_transporting_wu_xing) {
      const motherEl = MOTHER_OF[element];
      const childEl = CHILD_OF[element];

      const motherTable = specTables.five_transporting_wu_xing[motherEl?.toLowerCase()];
      const childTable = specTables.five_transporting_wu_xing[childEl?.toLowerCase()];

      // Try to find the point on the *current* channel that corresponds to Mother/Child Element
      if (flags.isDef && motherTable) {
        const pt = motherTable.yin_meridians?.[channel] || motherTable.yang_meridians?.[channel];
        if (pt) pts.push({ code: pt, role: "wuxing_mother_tonify", note: `Tonify Mother (${motherEl}) point.` });
      }

      if (flags.isExcess && childTable) {
        const pt = childTable.yin_meridians?.[channel] || childTable.yang_meridians?.[channel];
        if (pt) pts.push({ code: pt, role: "wuxing_child_sedate", note: `Sedate Child (${childEl}) point.` });
      }
    }
  }

  // 3) Tambahan pathogen-based
  const pathogenTable = tables.pathogen_cause_points;
  if (pathogenTable) {
    if (flags.hasHeat && pathogenTable.heat) {
        pathogenTable.heat.slice(0, 3).forEach((code: string) => pts.push({ code, role: "pathogen_heat", note: "Clear Heat." }));
    }
    if (flags.hasCold && pathogenTable.cold) {
        pathogenTable.cold.slice(0, 3).forEach((code: string) => pts.push({ code: code.replace(/ \(.*\)/, ""), role: "pathogen_cold", note: "Expel Cold." }));
    }
  }

  // 4) Dedup by code
  const seen = new Set<string>();
  return pts.filter((p) => {
    if (seen.has(p.code)) return false;
    seen.add(p.code);
    return true;
  });
}

// === COMPONENT ===

const rawFilled = TCM_DB.syndromes.FILLED_FROM_PDF as any[];
const rawTodo = (TCM_DB.syndromes.TODO_FROM_PDF || []) as any[];

const allSyndromes: DbSyndrome[] = [
  ...rawFilled.map((s) => ({ ...s, __isTodo: false })),
  ...rawTodo.map((s) => ({
    pattern_type: s.pattern_type || "todo_placeholder",
    name_en: s.name_en || s.name_id || s.id || "TODO pattern",
    name_id: s.name_id || s.id,
    clinical_manifestations: s.clinical_manifestations || [],
    treatment_principle: s.treatment_principle || [],
    acupuncture_points: s.acupuncture_points || [],
    tongue: s.tongue || [],
    pulse: s.pulse || [],
    primary_organs: s.primary_organs || [],
    ...s,
    __isTodo: true,
  })),
];

const organOptions = (() => {
  const set = new Set<string>();
  allSyndromes.forEach((s) => s.primary_organs?.forEach((o) => set.add(o)));
  return Array.from(set).sort();
})();

const elementColor: Record<string, string> = {
  Wood: "#22c55e",
  Fire: "#f97316",
  Earth: "#eab308",
  Metal: "#38bdf8",
  Water: "#6366f1",
};

function classifyQuadrant(patternType: string, name_en?: string): QuadrantId {
  const t = (patternType || "").toLowerCase();
  const n = (name_en || "").toLowerCase();

  const isDef = t.includes("def") || t.includes("deficiency") || n.includes("deficiency");
  const isExcess = t.includes("full") || t.includes("excess") || t.includes("damp") || t.includes("phlegm") || t.includes("fire") || t.includes("stasis") || t.includes("invasion") || t.includes("obstruction");
  const hasHeat = t.includes("heat") || t.includes("fire") || n.includes("heat") || n.includes("fire");
  const hasCold = t.includes("cold") || n.includes("cold");
  const hasDamp = t.includes("damp");
  const hasPhlegm = t.includes("phlegm");

  if (isDef && (hasCold || t.includes("yang"))) return "DEF_COLD";
  if (isDef && (hasHeat || t.includes("yin"))) return "DEF_HEAT";
  if (isExcess && (hasCold || hasDamp || hasPhlegm)) return "EXCESS_COLD";
  if (isExcess && hasHeat) return "EXCESS_HEAT";
  return "OTHER";
}

export const SyndromeAtlasWindow: React.FC<Props> = ({ onSelectSyndrome }) => {
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [activeQuadrant, setActiveQuadrant] = useState<QuadrantId | "ALL">("ALL");
  const [activeElement, setActiveElement] = useState<string>("ALL");
  const [organFilter, setOrganFilter] = useState<string | "ALL">("ALL");
  const [search, setSearch] = useState("");

  const classified = useMemo(() => 
      allSyndromes.map((s) => ({
        ...s,
        quadrant: classifyQuadrant(s.pattern_type, s.name_en),
      })),
    []
  );

  const filtered = useMemo(() => {
    let list = classified;
    if (activeQuadrant !== "ALL") list = list.filter((s) => s.quadrant === activeQuadrant);
    if (organFilter !== "ALL") list = list.filter((s) => s.primary_organs?.includes(organFilter));
    if (activeElement !== "ALL") list = list.filter((s) => s.wuxing_element?.startsWith(activeElement));
    if (search.trim()) {
      const q = search.toLowerCase();
      list = list.filter(s =>
          s.name_id.toLowerCase().includes(q) ||
          (s.name_en && s.name_en.toLowerCase().includes(q)) ||
          (s.primary_organs || []).some((o) => o.toLowerCase().includes(q))
      );
    }
    return list;
  }, [classified, activeQuadrant, organFilter, activeElement, search]);

  const selected = filtered.find((s) => s.id === selectedId) || filtered[0] || null;

  useEffect(() => {
    if (!selectedId && filtered.length > 0) setSelectedId(filtered[0].id);
  }, [filtered, selectedId]);

  const quadrantBuckets: Record<QuadrantId, DbSyndrome[]> = {
    DEF_COLD: [], DEF_HEAT: [], EXCESS_COLD: [], EXCESS_HEAT: [], OTHER: [],
  };
  // Populate buckets based on filtered list to reflect all active filters
  filtered.forEach((s) => {
      quadrantBuckets[s.quadrant].push(s);
  });

  const renderChip = (s: DbSyndrome) => {
    const isActive = selected?.id === s.id;
    const isTodo = s.__isTodo || !s.clinical_manifestations || s.clinical_manifestations.length === 0;
    return (
      <button
        key={s.id}
        type="button"
        onClick={() => setSelectedId(s.id)}
        className={`text-[11px] px-2 py-1 rounded-full border mb-1 mr-1 transition text-left ${
          isActive
            ? "bg-indigo-700 text-white border-indigo-400"
            : "bg-slate-900/60 text-slate-300 border-slate-700 hover:border-indigo-400 hover:text-indigo-200"
        }`}
      >
        {s.name_id || s.id}
        {isTodo && (
          <span className="ml-1 text-[9px] px-1 py-0.5 rounded-full bg-amber-900/60 text-amber-200 border border-amber-500/60 font-mono">TODO</span>
        )}
      </button>
    );
  };

