// === FUZZY MATCHING HELPERS ===
export const normalize = (s: string) => 
  (s || "").toLowerCase().replace(/[^\p{L}\p{N}\s]/gu, " ").replace(/\s+/g, " ").trim();

const levenshtein = (a: string, b: string): number => {
  const normA = normalize(a);
  const normB = normalize(b);
  if (normA === normB) return 0;
  if (normA.length === 0) return normB.length;
  if (normB.length === 0) return normA.length;

  const matrix = [];
  for (let i = 0; i <= normB.length; i++) matrix[i] = [i];
  for (let j = 0; j <= normA.length; j++) matrix[0][j] = j;

  for (let i = 1; i <= normB.length; i++) {
    for (let j = 1; j <= normA.length; j++) {
      if (normB.charAt(i - 1) === normA.charAt(j - 1)) {
        matrix[i][j] = matrix[i - 1][j - 1];
      } else {
        matrix[i][j] = Math.min(
          matrix[i - 1][j - 1] + 1,
          Math.min(matrix[i][j - 1] + 1, matrix[i - 1][j] + 1)
        );
      }
    }
  }
  return matrix[normB.length][normA.length];
};

const similarityRatio = (a: string, b: string): number => {
  const normA = normalize(a);
  const normB = normalize(b);
  if (normA.length === 0 || normB.length === 0) return 0.0;
  const dist = levenshtein(normA, normB);
  const maxLen = Math.max(normA.length, normB.length);
  return 1.0 - (dist / maxLen);
};

const tokenOverlap = (a: string, b: string): number => {
  const setA = new Set(normalize(a).split(/\s+/).filter(s => s));
  const setB = new Set(normalize(b).split(/\s+/).filter(s => s));
  if (setA.size === 0 || setB.size === 0) return 0.0;

  const intersection = new Set([...setA].filter(x => setB.has(x)));
  const union = new Set([...setA, ...setB]);

  return intersection.size / union.size;
};

export const fuzzyMatch = (a: string, b: string, threshold = 0.82): boolean => {
  const normA = normalize(a);
  const normB = normalize(b);

  // Direct inclusion check first (fastest)
  if (normA.includes(normB) || normB.includes(normA)) return true;

  const r1 = similarityRatio(a, b);
  if (r1 >= threshold) return true;

  const r2 = tokenOverlap(a, b);
  if (r2 >= 0.6) return true;

  return false;
};

const expandWithSynonyms = (base: string[]): Set<string> => {
  const out = new Set<string>();
  const synonymMap = TCM_DB.clinical_config.matching.synonym_map;

  base.forEach(s => {
    const key = normalize(s);
    if (!key) return;
    out.add(key);

    // If 's' is a key in the map
    if (synonymMap[key]) {
      synonymMap[key].forEach(syn => out.add(normalize(syn)));
    }

    // If 's' appears in any value list
    Object.entries(synonymMap).forEach(([k, values]) => {
      if (values.map(normalize).includes(key)) {
        out.add(normalize(k));
        values.forEach(v => out.add(normalize(v)));
      }
    });
  });
  return out;
};

const hasStrongIndicator = (selExpanded: Set<string>, indicators: string[]): boolean => {
  for (const ind of indicators) {
    const indExpanded = expandWithSynonyms([ind]);
    // Check if any indicator synonym matches any selected symptom
    for (const sel of selExpanded) {
      for (const ie of indExpanded) {
        if (fuzzyMatch(sel, ie, 0.78)) return true;
      }
    }
  }
  return false;
};

const extractSymptoms = (text: string): string[] => {
    return text.split(/[\n,.]+/).map(normalize).filter(s => s.length > 2);
};

// === PATHOLOGY DETECTION ===

interface PathologicalSigns {
  HEAT: boolean;
  COLD: boolean;
  DAMP_PHLEGM: boolean;
  STAGNATION: boolean;
  YIN_DEF: boolean;
  YANG_DEF: boolean;
  BLOOD_DEF: boolean;
  QI_DEF: boolean;
  // Organ Hints
  ORGANS_IMPLICATED: Set<string>;
}

const detectPathologyFromSigns = (
  tongue: PatientFormSchema['tongue'],
  pulse: PatientFormSchema['pulse']
): PathologicalSigns => {
  const signs = {
    HEAT: false,
    COLD: false,
    DAMP_PHLEGM: false,
    STAGNATION: false,
    YIN_DEF: false,
    YANG_DEF: false,
    BLOOD_DEF: false,
    QI_DEF: false,
    ORGANS_IMPLICATED: new Set<string>()
  };

  const tBody = normalize(tongue.body_color);
  const tCoat = normalize(tongue.coating_color);
  const tQual = normalize(tongue.coating_quality);
  const tFeat = tongue.special_features.map(normalize);
  const pQuals = pulse.qualities.map(normalize);

  // --- HEAT SIGNS ---
  if (tBody.includes('red') || tBody.includes('purple')) signs.HEAT = true;
  if (tCoat.includes('yellow')) signs.HEAT = true;
  if (pQuals.some(q => q.includes('rapid') || q.includes('surging') || q.includes('overflowing'))) signs.HEAT = true;

  // --- COLD SIGNS ---
  if (tBody.includes('pale') || tBody.includes('blue')) signs.COLD = true;
  if (tCoat.includes('white') && !tCoat.includes('yellow')) signs.COLD = true;
  if (pQuals.some(q => q.includes('slow') || q.includes('tight'))) signs.COLD = true;

  // --- DAMP/PHLEGM SIGNS ---
  if (tFeat.some(f => f.includes('swollen') || f.includes('teeth mark'))) signs.DAMP_PHLEGM = true;
  if (tQual.includes('greasy') || tQual.includes('sticky') || tQual.includes('thick')) signs.DAMP_PHLEGM = true;
  if (pQuals.some(q => q.includes('slippery') || q.includes('soggy') || q.includes('rolling'))) signs.DAMP_PHLEGM = true;

  // --- STAGNATION/STASIS SIGNS ---
  if (tBody.includes('purple') || tBody.includes('blue')) signs.STAGNATION = true;
  if (tFeat.some(f => f.includes('spot') || f.includes('prickle') || f.includes('stasis'))) signs.STAGNATION = true;
  if (pQuals.some(q => q.includes('wiry') || q.includes('choppy') || q.includes('tight'))) signs.STAGNATION = true;

  // --- YIN DEFICIENCY (Empty Heat) ---
  if (tBody.includes('red') && (tQual.includes('none') || tQual.includes('peeling') || tCoat.includes('none'))) signs.YIN_DEF = true;
  if (tFeat.some(f => f.includes('crack'))) signs.YIN_DEF = true;
  if (pQuals.some(q => q.includes('thready') || q.includes('fine') || q.includes('floating-empty'))) signs.YIN_DEF = true;

  // --- YANG DEFICIENCY (Empty Cold) ---
  if (tBody.includes('pale') && (tQual.includes('wet') || tFeat.some(f => f.includes('swollen')))) signs.YANG_DEF = true;
  if (pQuals.some(q => q.includes('deep') || q.includes('weak'))) signs.YANG_DEF = true;

  // --- QI DEFICIENCY ---
  if (tBody.includes('pale') || tFeat.some(f => f.includes('teeth mark'))) signs.QI_DEF = true;
  if (pQuals.some(q => q.includes('weak') || q.includes('empty') || q.includes('deficient'))) signs.QI_DEF = true;

  // --- ORGAN SPECIFIC CLUES (Tongue Topography & Pulse Positions) ---
  // Tip = Heart/Lung
  if (tFeat.some(f => f.includes('tip') && (f.includes('red') || f.includes('prickle')))) {
      signs.ORGANS_IMPLICATED.add('Heart');
      signs.ORGANS_IMPLICATED.add('Lung');
  }
  // Sides = Liver/GB
  if (tFeat.some(f => f.includes('side') && (f.includes('red') || f.includes('orange') || f.includes('swollen')))) {
      signs.ORGANS_IMPLICATED.add('Liver');
      signs.ORGANS_IMPLICATED.add('Gall Bladder');
  }
  if (pQuals.some(q => q.includes('wiry'))) signs.ORGANS_IMPLICATED.add('Liver');

  // Center = Spleen/Stomach
  if (tFeat.some(f => f.includes('center') || f.includes('middle'))) {
      signs.ORGANS_IMPLICATED.add('Spleen');
      signs.ORGANS_IMPLICATED.add('Stomach');
  }
  if (pQuals.some(q => q.includes('slippery'))) {
      signs.ORGANS_IMPLICATED.add('Spleen'); // Dampness often spleen
  }

  // Root = Kidney/Bladder
  if (tCoat.includes('thick') && (tCoat.includes('yellow') || tCoat.includes('white'))) {
      // Thick coat at root usually
      signs.ORGANS_IMPLICATED.add('Kidney'); 
      signs.ORGANS_IMPLICATED.add('Bladder'); // Damp-Heat/Cold in Lower Burner
  }
  if (pQuals.some(q => q.includes('deep'))) signs.ORGANS_IMPLICATED.add('Kidney');

  return signs;
};


// === SCORING LOGIC ===
export const scoreSyndrome = (
  syn: Syndrome, 
  selExpanded: Set<string>, 
  tongue: PatientFormSchema['tongue'], 
  pulse: PatientFormSchema['pulse'], 
  regions: string[],
  pathology: PathologicalSigns
): number => {
  let score = 0;
  const config = TCM_DB.clinical_config.scoring.weights;
  let anyKeyMatched = false;

  // 1. Key Symptoms (Fuzzy + Synonym)
  (syn.key_symptoms || []).forEach(ks => {
    const ksExpanded = expandWithSynonyms([ks]);
    let matched = false;
    for (const sel of selExpanded) {
      for (const kse of ksExpanded) {
         if (fuzzyMatch(sel, kse)) {
           matched = true;
           break;
         }
      }
      if (matched) break;
    }
    if (matched) {
      score += config.key_symptom_match;
      anyKeyMatched = true;
    }
  });

  // Guard: if keys exist but none matched, reduce likelihood
  if (!anyKeyMatched && (syn.key_symptoms || []).length > 0) {
      score -= 2; // Increased penalty
  }

  // 2. Manifestations with Weighted Importance
  (syn.clinical_manifestations || []).forEach(m => {
    const mExpanded = expandWithSynonyms([m]);
    let matched = false;
    let weightBonus = 0;

    for (const sel of selExpanded) {
       // Check against High Value Symptoms
       Object.entries(SYMPTOM_WEIGHTS).forEach(([key, val]) => {
           if (fuzzyMatch(sel, key)) {
               // If this specific high-value symptom matches the syndrome's nature
               if (val.element && syn.wuxing_element && syn.wuxing_element.includes(val.element)) weightBonus += 1;
               if (val.type && syn.pattern_type.includes(val.type)) weightBonus += 2;
           }
       });

       for (const me of mExpanded) {
          if (fuzzyMatch(sel, me)) {
            matched = true;
            break;
          }
       }
       if (matched) break;
    }

    if (matched) {
        score += config.manifestation_match + weightBonus;
    }
  });

  // 3. Region Bonus
  const regionMap = TCM_DB.clinical_config.diagnosis_engine.region_organ_map || {};
  const relevantOrgans = new Set<string>();
  regions.forEach(r => {
      const mapKey = Object.keys(regionMap).find(k => fuzzyMatch(r, k, 0.7));
      if (mapKey) {
          regionMap[mapKey].forEach(o => relevantOrgans.add(o));
      }
  });
  if ((syn.primary_organs || []).some(o => relevantOrgans.has(o))) {
      score += config.organ_region_bonus;
  }

  // 4. Pathological Bonuses (The "Smart" Layer)
  const pType = normalize(syn.pattern_type);

  // Refined Logic: Distinguish Full vs Empty Heat
  if (pathology.HEAT) {
    if (pType.includes('heat') || pType.includes('fire')) {
        // If Yin Def is present, prefer Empty Heat patterns over Full Heat
        if (pathology.YIN_DEF && (pType.includes('empty') || pType.includes('yin'))) {
            score += 6;
        } else if (!pathology.YIN_DEF && (pType.includes('excess') || pType.includes('full'))) {
            score += 5;
        } else {
            score += 3; // Generic heat match
        }
    }
    // Contradiction
    if (pType.includes('cold') && !pType.includes('heat')) score -= 6;
  }

  // Refined Logic: Distinguish Full vs Empty Cold
  if (pathology.COLD) {
    if (pType.includes('cold')) {
        if (pathology.YANG_DEF && (pType.includes('empty') || pType.includes('yang'))) {
            score += 6;
        } else if (!pathology.YANG_DEF && (pType.includes('excess') || pType.includes('full'))) {
            score += 5;
        } else {
            score += 3;
        }
    }
    if (pType.includes('heat') && !pType.includes('cold')) score -= 6;
  }

  // Damp/Phlegm Patterns
  if (pathology.DAMP_PHLEGM) {
    if (pType.includes('damp') || pType.includes('phlegm')) score += 5;
    if (pType.includes('dryness') || pType.includes('yin deficiency')) score -= 3;
  }

  // Stagnation/Stasis (Wood/Liver Focus)
  if (pathology.STAGNATION) {
    if (pType.includes('stagnation') || pType.includes('stasis')) score += 4;
    // Specific Pulse-Organ Affinity: Wiry pulse strongly suggests Liver/GB
    if (syn.primary_organs.some(o => o.includes('Liver') || o.includes('Gall'))) score += 3;
  }

  // Yin Deficiency
  if (pathology.YIN_DEF) {
    if (pType.includes('yin deficiency') || pType.includes('empty heat')) score += 6;
  }

  // Yang Deficiency
  if (pathology.YANG_DEF) {
    if (pType.includes('yang deficiency') || pType.includes('empty cold')) score += 6;
  }

  // Qi Deficiency
  if (pathology.QI_DEF) {
    if (pType.includes('qi deficiency')) score += 4;
  }

  // 5. Zang-Fu Synergy (Organ Profile Match)
  // If the syndrome involves organs that the patient shows signs of (via tongue/pulse/symptoms), boost it.
  const syndromeOrgans = syn.primary_organs || [];
  let synergyHits = 0;
  syndromeOrgans.forEach(org => {
      // Check topography/pulse hints
      if (pathology.ORGANS_IMPLICATED.has(org)) synergyHits++;
      // Check region hints
      if (relevantOrgans.has(org)) synergyHits++;
  });

  if (synergyHits > 0) {
      score += (synergyHits * 2); // Significant boost for organ alignment
  }

  // Bonus for Multi-Organ Logic
  // If syndrome has 2 organs (e.g. Liver & Spleen) and BOTH are implicated in signs, massive boost.
  if (syndromeOrgans.length > 1) {
      const allImplicated = syndromeOrgans.every(o => pathology.ORGANS_IMPLICATED.has(o) || relevantOrgans.has(o));
      if (allImplicated) score += 5; 
  }

  return score;
};

// === HERBAL RECOMMENDATION ENGINE ===
export const getHerbalRecommendation = (syndrome: Syndrome) => {
  const links = TCM_DB.herbal?.pattern_links?.[syndrome.id];
  const index = TCM_DB.herbal?.single_herbs_index || {};

  if (links) {
    return {
      formula_name: links.key_formulas?.[0]?.name,
      chief: links.single_herbs
        .filter(h => h.role === 'chief' || h.role === 'Jun' || h.role === 'king')
        .map(h => index[h.ref]?.name || h.ref),
      assistants: links.single_herbs
        .filter(h => h.role !== 'chief' && h.role !== 'Jun' && h.role !== 'king')
        .map(h => index[h.ref]?.name || h.ref),
      avoid: []
    };
  }

  const gl = TCM_DB.herbal_guidelines?.per_syndrome_overrides_for_current_DB_snippet?.[syndrome.id] 
             || TCM_DB.herbal_guidelines?.herbal_rules_by_pattern_type?.[syndrome.pattern_type];

  if (gl) {
    return {
      formula_name: "Guideline Based",
      chief: gl.suggest_chief || gl.suggest_chief_herbs || [],
      assistants: gl.suggest_assistants || [],
      avoid: gl.avoid || []
    };
  }

  return undefined;
};

// === AUTO PRESCRIPTION HELPERS ===

const uniqByCode = (pts: RxPoint[]) => {
  const m = new Map<string, RxPoint>();
  pts.forEach(p => {
    if (!m.has(p.code)) m.set(p.code, p);
  });
  return [...m.values()];
};

// deteksi jenis pola deficiency/excess dari pattern_type
function inferExcessDeficiency(patternType?: string) {
  const p = normalize(patternType || "");
  const deficiency =
    p.includes("deficiency") ||
    p.includes("defisiensi") ||
    p.includes("yin def") ||
    p.includes("yang def") ||
    p.includes("qi def") ||
    p.includes("blood def") ||
    p.includes("essence def");

  const excess =
    p.includes("excess") ||
    p.includes("heat") ||
    p.includes("fire") ||
    p.includes("phlegm") ||
    p.includes("damp") ||
    p.includes("stagnation") ||
    p.includes("stasis") ||
    p.includes("rebellious");

  return { deficiency, excess };
}

// ambil mother/child point dari table wuxing_points_by_channel
function getMotherChildPointsForChannels(
  channels: string[],
  wuxingPointsByChannel: any,
  elementName?: string
) {
  if (!channels?.length || !wuxingPointsByChannel) return { mother: [], child: [] };

  // map element -> mother/child element
  const rel: Record<string, { mother: string; child: string }> = {
    wood:  { mother: "Water", child: "Fire" },
    fire:  { mother: "Wood", child: "Earth" },
    earth: { mother: "Fire", child: "Metal" },
    metal: { mother: "Earth", child: "Water" },
    water: { mother: "Metal", child: "Wood" }
  };

  const el = normalize(elementName || "");
  const relEl = rel[el];
  if (!relEl) return { mother: [], child: [] };

  const mother: string[] = [];
  const child: string[] = [];

  const motherEl = relEl.mother.toLowerCase();
  const childEl = relEl.child.toLowerCase();

  channels.forEach(ch => {
    const up = ch.toUpperCase();

    // Find Mother point
    const motherTable = wuxingPointsByChannel[motherEl];
    if (motherTable) {
         const pt = motherTable.yin_meridians?.[up] || motherTable.yang_meridians?.[up];
         if (pt) mother.push(pt);
    }

    // Find Child point
    const childTable = wuxingPointsByChannel[childEl];
    if (childTable) {
        const pt = childTable.yin_meridians?.[up] || childTable.yang_meridians?.[up];
        if (pt) child.push(pt);
    }
  });

  return { mother, child };
}

// infer channel code dari organ
function organToChannelCodes(organs: string[]) {
  const map: Record<string, string[]> = {
    Lung: ["LU"],
    "Large Intestine": ["LI"],
    LargeIntestine: ["LI"],
    Heart: ["HT"],
    "Small Intestine": ["SI"],
    SmallIntestine: ["SI"],
    Spleen: ["SP"],
    Stomach: ["ST"],
    Kidney: ["KI"],
    Bladder: ["BL"],
    Liver: ["LR"],
    "Gall Bladder": ["GB"],
    GallBladder: ["GB"],
    Pericardium: ["PC"],
    "San Jiao": ["TE"],
    SanJiao: ["TE"],
    "Triple Burner": ["TE"],
    TripleBurner: ["TE"]
  };
  const out: string[] = [];
  organs?.forEach(o => {
    (map[o] || []).forEach(c => out.push(c));
  });
  return [...new Set(out)];
}

// deteksi pathogen dari syndrome + symptoms + tongue + pulse
function inferPathogens(syndrome: Syndrome, selectedSymptoms: string[], tongue: string[] = [], pulse: string[] = []) {
  const p = normalize(syndrome.pattern_type || "");
  const text = normalize(
    (syndrome.name_en || "") +
    " " + (syndrome.name_id || "") +
    " " + (syndrome.clinical_manifestations || []).join(" ") +
    " " + selectedSymptoms.join(" ") + 
    " " + tongue.join(" ") + 
    " " + pulse.join(" ")
  );

  return {
    wind: p.includes("wind") || text.includes("angin") || text.includes("wind"),
    cold: p.includes("cold") || text.includes("dingin") || text.includes("cold") || text.includes("pale") || text.includes("slow") || text.includes("tight"),
    heat: p.includes("heat") || p.includes("fire") || text.includes("panas") || text.includes("heat") || text.includes("red") || text.includes("rapid") || text.includes("yellow"),
    damp: p.includes("damp") || text.includes("lembap") || text.includes("damp") || text.includes("greasy") || text.includes("sticky") || text.includes("swollen") || text.includes("slippery"),
    phlegm: p.includes("phlegm") || text.includes("dahak") || text.includes("phlegm") || text.includes("greasy") || text.includes("slippery"),
    dryness: p.includes("dryness") || text.includes("kering") || text.includes("dry") || text.includes("cracks") || text.includes("peeled"),
    blood: p.includes("blood") || text.includes("darah") || p.includes("stasis") || text.includes("purple") || text.includes("spots"),
    qi_stag: p.includes("qi stagnation") || text.includes("stagnasi qi") || p.includes("rebellious") || text.includes("distension") || text.includes("wiry")
  };
}

// cek akut/nyeri/bleeding
function isAcutePattern(syndrome: Syndrome, selectedSymptoms: string[]) {
  const p = normalize(syndrome.pattern_type || "");
  const t = normalize(selectedSymptoms.join(" "));
  return (
    p.includes("acute") ||
    p.includes("pain") ||
    p.includes("stasis") ||
    p.includes("blood") ||
    t.includes("nyeri hebat") ||
    t.includes("menusuk") ||
    t.includes("darah")
  );
}

// === MAIN ENGINE ===
export function buildAutoPrescription(
  DB: any,
  input: AutoRxInput
): {
  points: RxPoint[];
  warnings: string[];
  rationale: string[];
} {
  const syn = input.syndrome;
  const warnings: string[] = [];
  const rationale: string[] = [];
  const points: RxPoint[] = [];

  const core = DB.core_rules || {};
  const sp = DB.special_point_tables || {};
  const spec = DB.tcm_specific_points || {};

  // 1) KAUSAL points from syndrome
  const synPtsArr: string[] =
    Array.isArray(syn.acupuncture_points)
      ? syn.acupuncture_points
      : (syn.acupuncture_points?.kausal || syn.acupuncture_points?.main || []);

  synPtsArr.forEach(code => {
    points.push({ code, role: "kausal", source: "syndrome", note: "Titik root dari pola" });
  });
  rationale.push("Kausal diambil dari acupuncture_points sindrom.");

  // 2) SIMPTOM lokasi
  const regionPkgs = core.location_based_point_packages || {};
  const regions = input.bodyRegion || [];
  regions.forEach(r => {
    // cari paket yang cocok fuzzy
    Object.entries(regionPkgs).forEach(([k, v]: any) => {
      if (fuzzyMatch(r, k, 0.3)) {
        (v as string[]).forEach(code => {
          points.push({ code, role: "simptom", source: `region:${k}` });
        });
      }
    });
  });
  if (regions.length) rationale.push("Simptomatik dari location_based_point_packages.");

  // 3) WU XING auto tonify/sedate
  const { deficiency, excess } = inferExcessDeficiency(syn.pattern_type);

  const organs = syn.primary_organs || [];
  const channels = organToChannelCodes(organs);

  // Use specific points if available, fallback to general special tables
  const wuxingByCh = spec.five_transporting_wu_xing;

  const elementName =
    (syn.wuxing_element || "")
      .split(" ")[0]
      .replace(/overacting|metal|wood|fire|earth|water/gi, (m) => m)
      .trim();

  if (wuxingByCh && channels.length) {
    const { mother, child } = getMotherChildPointsForChannels(
      channels,
      wuxingByCh,
      elementName
    );

    if (deficiency && mother.length) {
      mother.forEach(code =>
        points.push({ code, role: "wuxing", source: "wu_xing:mother", note: "Tonify Mother point" })
      );
      rationale.push("Deficiency → tonik Mother point sesuai Wu Xing.");
    }
    if (excess && child.length) {
      child.forEach(code =>
        points.push({ code, role: "wuxing", source: "wu_xing:child", note: "Sedate Child point" })
      );
      rationale.push("Excess → sedasi Child point sesuai Wu Xing.");
    }
  }

  // 4) XI-CLEFT kalau akut
  const xiTable = spec.xi_cleft_points || sp.xi_cleft_points;
  if (xiTable && isAcutePattern(syn, input.selectedSymptoms)) {
    channels.forEach(ch => {
      // Handle both simple key-value and structured yin/yang formats
      const xi = xiTable[ch] || xiTable.yin_channels?.[ch] || xiTable.yang_channels?.[ch];
      if (xi) points.push({ code: xi, role: "xi", source: "xi_cleft_points", note: "Akut/nyeri" });
    });
    rationale.push("Akut/nyeri → tambah Xi-Cleft channel terkait.");
  }

  // 5) Pathogen points
  const pathTable = spec.pathogenic_cause_points || sp.pathogen_cause_points;
  const pathogens = inferPathogens(syn, input.selectedSymptoms, input.tongue, input.pulse);

  if (pathTable) {
    const addPath = (list: string[] | undefined, source: string, note?: string) => {
        if (!list) return;
        list.forEach((code: string) => 
             points.push({ code: code.replace("+moxa","").replace("+prick",""), role: "pathogen", source, note: note || (code.includes("+moxa") ? "moxa" : undefined) })
        );
    };

    if (pathogens.wind) addPath((pathTable.wind || pathTable.angin_wind), "pathogen:wind");
    if (pathogens.cold) addPath((pathTable.cold || pathTable.dingin_cold), "pathogen:cold");
    if (pathogens.heat) addPath((pathTable.heat || pathTable.panas_heat), "pathogen:heat");
    if (pathogens.damp) addPath((pathTable.damp || pathTable.lembab_damp), "pathogen:damp");
    if (pathogens.dryness) addPath((pathTable.dryness || pathTable.kering_dryness), "pathogen:dryness");
    if (pathogens.blood) addPath((pathTable.blood || pathTable.xue_blood), "pathogen:blood");
    if (pathogens.qi_stag) addPath((pathTable.qi_stagnation || pathTable.qi), "pathogen:qi");
    if (pathogens.phlegm) addPath((pathTable.riak_phlegm || pathTable.phlegm), "pathogen:phlegm");
  }

  if (pathogens.wind || pathogens.cold || pathogens.heat || pathogens.damp || pathogens.dryness || pathogens.blood || pathogens.qi_stag || pathogens.phlegm) {
     rationale.push("Pathogen-cause points ditambah bila pola/symptom/lidah/nadi mengarah ke pathogen.");
  }

  // 6) Extra / dominant / 3 dewa (opsional ringan)
  const dom = spec.supplement_and_dominant_points || sp.dominant_and_supplement_points;
  if (dom?.dominant?.qi && pathogens.qi_stag) {
    dom.dominant.qi.forEach((code: string) =>
      points.push({ code, role: "extra", source: "dominant:qi" })
    );
    rationale.push("Qi stagnation → tambah dominant Qi points.");
  }

  // 7) Back-Shu Points (New Requirement)
  const backShuTable = sp.back_shu_points;
  if (backShuTable) {
    const channelCodes = organToChannelCodes(syn.primary_organs || []);
    channelCodes.forEach(ch => {
        const pt = backShuTable[ch];
        if (pt) {
            points.push({ code: pt, role: "back_shu", source: "auto:back_shu", note: `Back-Shu for ${ch}` });
        }
    });
    if (channelCodes.length > 0) rationale.push("Auto-add Back-Shu points for involved organs.");
  }

  // 8) Contraindication check
  if (input.isPregnant) {
    const contra =
      core.pregnancy_contraindications ||
      spec.contraindications?.pregnancy ||
      [];
    const contraSet = new Set(contra.map((c: string) => c.toUpperCase()));
    const filtered = points.filter(p => !contraSet.has(p.code.toUpperCase()));
    const removed = points.filter(p => contraSet.has(p.code.toUpperCase()));
    if (removed.length) {
      warnings.push(
        `Kehamilan: titik dibuang → ${removed.map(r => r.code).join(", ")}`
      );
    }
    return {
      points: uniqByCode(filtered),
      warnings,
      rationale
    };
  }

  return { points: uniqByCode(points), warnings, rationale };
}

// === MAIN ANALYZER ===
export const analyzePatient = (data: PatientFormSchema): ScoredSyndrome[] => {
    const allSyndromes = [
        ...TCM_DB.syndromes.FILLED_FROM_PDF,
        ...TCM_DB.syndromes.TODO_FROM_PDF
    ];

    // Prepare Symptoms
    let symptomsList = data.selected_symptoms || [];
    const rawData = data as any;
    if (rawData.symptoms && typeof rawData.symptoms === 'string') {
        symptomsList = [...symptomsList, ...extractSymptoms(rawData.symptoms)];
    }
    const selExpanded = expandWithSynonyms(symptomsList);

    // 0. Detect Pathological Signs from Tongue & Pulse (NEW LAYER)
    const signs = detectPathologyFromSigns(data.tongue, data.pulse);

    // 1. Candidate Selection (Acute Mode vs Standard)
    let candidates: Syndrome[] = [];
    if (data.isAcuteMode) {
      // Filter for SHL (Six Stages) or Wen Bing (Four Levels)
      candidates = allSyndromes.filter(s => 
          s.id.startsWith("SHL_") || s.id.startsWith("WB_") || 
          s.pattern_type.includes("acute") || s.pattern_type.includes("external")
      );
    } else {
      // Standard Filter: Region Based
      if (data.body_region_selector && data.body_region_selector.length > 0) {
        const regionMap = TCM_DB.clinical_config.diagnosis_engine.region_organ_map || {};
        const allowedOrgans = new Set<string>();
        data.body_region_selector.forEach(r => {
           const key = Object.keys(regionMap).find(k => fuzzyMatch(r, k, 0.7));
           if (key) regionMap[key].forEach(o => allowedOrgans.add(o));
        });

        candidates = allSyndromes.filter(s => 
            s.primary_organs.some(o => allowedOrgans.has(o))
        );
        // Fallback if strict filter yields nothing
        if (candidates.length === 0) candidates = allSyndromes;
      } else {
        candidates = allSyndromes;
      }
    }

    // 2. Strong Clinical Indicators
    const coldStrong = hasStrongIndicator(selExpanded, coldIndicators);
    const heatStrong = hasStrongIndicator(selExpanded, heatIndicators);
    const phlegmStrong = hasStrongIndicator(selExpanded, phlegmIndicators);

    // 3. Scoring & Exclusion
    const scored = candidates.map(syn => {
        // Pass the pathological signs to the scorer
        let score = scoreSyndrome(syn, selExpanded, data.tongue, data.pulse, data.body_region_selector, signs);

        // Exclusion Logic
        if (coldStrong && exclusionMap["cold_strong"].includes(syn.pattern_type)) score -= 999;
        if (heatStrong && exclusionMap["heat_strong"].includes(syn.pattern_type)) score -= 999;
        if (phlegmStrong && exclusionMap["phlegm_strong"].includes(syn.pattern_type)) score -= 300;

        return { syndrome: syn, score };
    });

    // 4. Sort and Top K
    const topScored = scored
        .filter(s => s.score > 0)
        .sort((a, b) => b.score - a.score)
        .slice(0, 3);

    // 5. Build Points using Auto Prescription Logic
    // NEW: Include quality and special features in the tongue array for auto-prescription context
    const tongueArr = [
        data.tongue.body_color, 
        data.tongue.coating_color,
        data.tongue.coating_quality,
        ...(data.tongue.special_features || [])
    ].filter(Boolean);

    const pulseArr = data.pulse.qualities || [];

    return topScored.map(s => {
        const autoRx = buildAutoPrescription(TCM_DB, {
            syndrome: s.syndrome,
            selectedSymptoms: symptomsList,
            tongue: tongueArr,
            pulse: pulseArr,
            bodyRegion: data.body_region_selector,
            isPregnant: false // Safety default, override if needed in future
        });

        const herbal = getHerbalRecommendation(s.syndrome);

        return {
            syndrome: s.syndrome,
            score: s.score,
            points: autoRx.points,
            warnings: autoRx.warnings,
            rationale: autoRx.rationale,
            herbal_recommendation: herbal
        };
    });
};

import { UserAccount } from '../types';

const DB_KEY_USERS = 'tcm_pro_users';

// Default Seed Data
const DEFAULT_ADMIN: UserAccount = {
  username: 'admin',
  password: 'admin123', 
  role: 'admin',
  createdAt: Date.now()
};

export const db = {
  users: {
    // Fetch all users from storage with robust error handling
    getAll: (): UserAccount[] => {
      if (typeof window === 'undefined') return [];
      try {
        const stored = localStorage.getItem(DB_KEY_USERS);
        if (!stored) {
            // Initialize with admin if empty
            const initial = [DEFAULT_ADMIN];
            localStorage.setItem(DB_KEY_USERS, JSON.stringify(initial));
            return initial;
        }

        const parsed = JSON.parse(stored);

        // Safety check: ensure it is actually an array
        if (!Array.isArray(parsed)) {
            console.warn("DB Corrupt: Resetting to default.");
            const initial = [DEFAULT_ADMIN];
            localStorage.setItem(DB_KEY_USERS, JSON.stringify(initial));
            return initial;
        }

        return parsed;
      } catch (e) {
        console.error("Database Read Error, resetting:", e);
        // Fallback to default admin if JSON parse fails
        const initial = [DEFAULT_ADMIN];
        localStorage.setItem(DB_KEY_USERS, JSON.stringify(initial));
        return initial;
      }
    },

    // Save full list to storage
    saveAll: (users: UserAccount[]) => {
      if (typeof window === 'undefined') return;
      try {
        localStorage.setItem(DB_KEY_USERS, JSON.stringify(users));
      } catch (e) {
        console.error("Database Save Error:", e);
      }
    },

    // Add a single user
    add: (user: UserAccount): boolean => {
       try {
           const users = db.users.getAll();

           // Check for duplicates (case-insensitive)
           if (users.some(u => u.username.toLowerCase() === user.username.trim().toLowerCase())) {
               return false; 
           }

           // Create new array with new user
           const updatedUsers = [...users, user];
           db.users.saveAll(updatedUsers);
           return true;
       } catch (e) {
           console.error("Failed to add user:", e);
           return false;
       }
    },

    // Delete a user
    delete: (username: string): boolean => {
        try {
            const users = db.users.getAll();
            const newUsers = users.filter(u => u.username !== username);

            if (newUsers.length === users.length) return false; // Not found

            db.users.saveAll(newUsers);
            return true;
        } catch (e) {
            console.error("Failed to delete user:", e);
            return false;
        }
    }
  }
};

import React, { useState, useEffect } from 'react';
import { X, UserPlus, Trash2, Shield, User, AlertCircle, Save } from 'lucide-react';
import { UserAccount } from '../types';
import { getUsers, saveUser, deleteUser } from '../services/authService';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  currentUser: UserAccount;
}

const UserManagementModal: React.FC<Props> = ({ isOpen, onClose, currentUser }) => {
  const [users, setUsers] = useState<UserAccount[]>([]);
  const [newUsername, setNewUsername] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [newRole, setNewRole] = useState<'admin' | 'user'>('user');
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  useEffect(() => {
    if (isOpen) {
      refreshList();
    }
  }, [isOpen]);

  const refreshList = () => {
    const currentUsers = getUsers();
    setUsers(currentUsers);
  };

  const handleAddUser = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');

    if (!newUsername.trim() || !newPassword.trim()) {
      setError('Username and password are required.');
      return;
    }

    const result = saveUser({
      username: newUsername.trim(),
      password: newPassword.trim(),
      role: newRole,
      createdAt: Date.now()
    });

    if (result.success) {
      setSuccessMsg(`User ${newUsername} added successfully.`);
      setNewUsername('');
      setNewPassword('');
      setNewRole('user');
      // Force refresh logic
      setTimeout(() => refreshList(), 50);
    } else {
      setError(result.message);
    }
  };

  const handleDelete = (username: string) => {
    if (username === currentUser.username) {
      setError("You cannot delete your own account.");
      return;
    }
    if (!window.confirm(`Are you sure you want to delete user "${username}"?`)) return;

    const result = deleteUser(username);
    if (result.success) {
      refreshList();
      setSuccessMsg(`User ${username} deleted.`);
    } else {
      setError(result.message);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-2xl rounded-2xl shadow-2xl flex flex-col max-h-[90vh]">

        {/* Header */}
        <div className="flex items-center justify-between p-5 border-b border-slate-700 bg-slate-800 rounded-t-2xl">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-900/50 p-2 rounded-lg border border-indigo-500/30">
               <Shield className="w-6 h-6 text-indigo-400" />
            </div>
            <div>
              <h2 className="text-xl font-bold text-white">Master Control</h2>
              <p className="text-xs text-slate-400">User Management & Access Control</p>
            </div>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-6">

           {/* Add User Form */}
           <div className="bg-slate-950 p-5 rounded-xl border border-slate-800">
              <h3 className="text-sm font-bold text-emerald-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                 <UserPlus className="w-4 h-4" /> Add New User
              </h3>

              <form onSubmit={handleAddUser} className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
                 <div className="md:col-span-1">
                    <label className="block text-xs font-semibold text-slate-500 mb-1">Username</label>
                    <input 
                      type="text" 
                      value={newUsername}
                      onChange={e => setNewUsername(e.target.value)}
                      className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-sm text-white focus:border-indigo-500 outline-none"
                      placeholder="e.g. doctor1"
                    />
                 </div>
                 <div className="md:col-span-1">
                    <label className="block text-xs font-semibold text-slate-500 mb-1">Password</label>
                    <input 
                      type="text" 
                      value={newPassword}
                      onChange={e => setNewPassword(e.target.value)}
                      className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-sm text-white focus:border-indigo-500 outline-none font-mono"
                      placeholder="Password"
                    />
                 </div>
                 <div className="md:col-span-1">
                    <label className="block text-xs font-semibold text-slate-500 mb-1">Role</label>
                    <select 
                       value={newRole}
                       onChange={e => setNewRole(e.target.value as any)}
                       className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-sm text-white focus:border-indigo-500 outline-none"
                    >
                       <option value="user">User</option>
                       <option value="admin">Admin</option>
                    </select>
                 </div>
                 <div className="md:col-span-1">
                    <button type="submit" className="w-full bg-indigo-600 hover:bg-indigo-500 text-white font-semibold py-2 rounded-lg transition-colors flex items-center justify-center gap-2 text-sm">
                       <Save className="w-4 h-4" /> Add
                    </button>
                 </div>
              </form>

              {error && (
                 <div className="mt-3 text-xs text-red-400 flex items-center gap-1 bg-red-900/10 p-2 rounded">
                    <AlertCircle className="w-3 h-3" /> {error}
                 </div>
              )}
              {successMsg && (
                 <div className="mt-3 text-xs text-emerald-400 flex items-center gap-1 bg-emerald-900/10 p-2 rounded">
                    <AlertCircle className="w-3 h-3" /> {successMsg}
                 </div>
              )}
           </div>

           {/* User List */}
           <div>
              <h3 className="text-sm font-bold text-slate-300 uppercase tracking-wider mb-3">Registered Users ({users.length})</h3>
              <div className="border border-slate-800 rounded-xl overflow-hidden">
                 <table className="w-full text-sm text-left">
                    <thead className="bg-slate-900 text-slate-500 font-medium">
                       <tr>
                          <th className="px-4 py-3">Username</th>
                          <th className="px-4 py-3">Role</th>
                          <th className="px-4 py-3">Password (Visible)</th>
                          <th className="px-4 py-3 text-right">Action</th>
                       </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-800 bg-slate-900/50">
                       {users.map(u => (
                          <tr key={u.username} className="hover:bg-slate-800/80 transition-colors">
                             <td className="px-4 py-3 font-semibold text-white flex items-center gap-2">
                                <User className={`w-4 h-4 ${u.role === 'admin' ? 'text-amber-400' : 'text-slate-400'}`} />
                                {u.username} {u.username === currentUser.username && <span className="text-[10px] bg-emerald-900/50 text-emerald-400 px-1.5 py-0.5 rounded ml-2">YOU</span>}
                             </td>
                             <td className="px-4 py-3">
                                <span className={`text-xs px-2 py-1 rounded-full uppercase font-bold tracking-wide ${u.role === 'admin' ? 'bg-amber-900/30 text-amber-500 border border-amber-900/50' : 'bg-slate-800 text-slate-400 border border-slate-700'}`}>
                                   {u.role}
                                </span>
                             </td>
                             <td className="px-4 py-3 font-mono text-slate-400">{u.password}</td>
                             <td className="px-4 py-3 text-right">
                                {u.username !== 'admin' && u.username !== currentUser.username && (
                                   <button 
                                      onClick={() => handleDelete(u.username)}
                                      className="text-slate-500 hover:text-red-400 transition-colors p-1"
                                      title="Delete User"
                                   >
                                      <Trash2 className="w-4 h-4" />
                                   </button>
                                )}
                             </td>
                          </tr>
                       ))}
                    </tbody>
                 </table>
              </div>
           </div>

        </div>
      </div>
    </div>
  );
};

export default UserManagementModal;

