                           value={patientName} onChange={e => setPatientName(e.target.value)} placeholder="Nama Pasien" />
                    <input className="w-20 bg-slate-900 border border-slate-700 rounded px-3 py-2 text-sm text-white" 
                           value={age} onChange={e => setAge(e.target.value)} placeholder="Umur" />
