                 <div className="flex items-center gap-2">
                    <label className="flex-1 cursor-pointer bg-slate-900 hover:bg-slate-700 border border-slate-600 border-dashed rounded-lg p-3 text-center transition-colors">
                        <span className="text-xs text-slate-400 flex items-center justify-center gap-2">
