                        </span>
                        <input type="file" accept="image/*" className="hidden" onChange={handleSignatureUpload} />
                    </label>
                    {signature && (
                        <button onClick={() => setSignature(null)} className="p-2 bg-red-900/50 text-red-400 rounded hover:bg-red-900">
                           <X className="w-4 h-4" />
                        </button>
                    )}
                 </div>
              </div>

              <button 
