                  <p className="text-[10px] text-slate-500 mt-1">Traditional Chinese Medicine & Acupuncture</p>
               </div>

               {/* Meta Data */}
               <div className="flex justify-between text-xs mb-6 font-sans">
                  <div className="space-y-1">
                     <p><span className="font-bold text-slate-500">Nama:</span> {patientName}</p>
                     <p><span className="font-bold text-slate-500">Umur:</span> {age} th</p>
                     <p><span className="font-bold text-slate-500">Alamat:</span> {address}</p>
                  </div>
                  <div className="text-right space-y-1">
                     <p><span className="font-bold text-slate-500">Tanggal:</span> {date}</p>
                     <p><span className="font-bold text-slate-500">No. RM:</span> -</p>
                  </div>
