            }
        }
    }
  }, [initialSyndromeId, analysis]);

  // Reset manual points when syndrome selection changes
  useEffect(() => {
    setManualPoints([]);
  }, [selectedSyndrome?.syndrome.id]);

  const sortedAnalysis = [...analysis].sort((a, b) => b.score - a.score);

  // Fallback to top score if nothing is selected
  useEffect(() => {
    if (!selectedSyndrome && sortedAnalysis.length > 0) {
        setSelectedSyndrome(sortedAnalysis[0]);
    }
  }, [sortedAnalysis]);


  // Helper for printing/snapshot
  const handleSnapshot = async () => {
    if (!contentRef.current) return;
    try {
        const canvas = await html2canvas(contentRef.current, {
            scale: 2,
            useCORS: true,
            backgroundColor: '#1e293b' // Keep slate-800 background
        });
        const imgData = canvas.toDataURL('image/png');
        const pdf = new jsPDF('l', 'mm', 'a4');
        const pdfW = pdf.internal.pageSize.getWidth();

        const imgProps = pdf.getImageProperties(imgData);
        const imgH = (imgProps.height * pdfW) / imgProps.width;

        pdf.addImage(imgData, 'PNG', 0, 0, pdfW, imgH);
        pdf.save(`CDSS_Snapshot_${selectedSyndrome?.syndrome.name_id || 'Analysis'}.pdf`);
    } catch(e) {
        console.error("Snapshot failed", e);
        alert("Gagal membuat snapshot PDF.");
    }
  };

  const handleAddManualPoint = (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!manualInput.trim()) return;

    const code = manualInput.toUpperCase().trim();

    // Check duplication
    const existsInSystem = selectedSyndrome?.points.some(p => p.code === code);
    const existsInManual = manualPoints.some(p => p.code === code);

    if (!existsInSystem && !existsInManual) {
        const newPoint: RxPoint = {
            code: code,
            role: 'manual',
            source: 'user_add',
            note: 'Ditambahkan manual'
        };
        setManualPoints([...manualPoints, newPoint]);
    }
    setManualInput('');
  };

  const removeManualPoint = (code: string) => {
      setManualPoints(manualPoints.filter(p => p.code !== code));
  };

  // Combine system points + manual points for visualization
  const activePoints = selectedSyndrome 
    ? [...(selectedSyndrome.points || []), ...manualPoints] 
    : [];

  // Convert to TcmDiagnosisResult for the modal
  const diagnosisForModal: TcmDiagnosisResult | null = selectedSyndrome ? {
      patternId: selectedSyndrome.syndrome.id,
      confidence: selectedSyndrome.score / 100,
      explanation: selectedSyndrome.rationale.join('\n\n'),
      recommendedPoints: activePoints.map(p => p.code),
      lifestyleAdvice: "Disarankan istirahat cukup, hindari faktor patogen (Angin/Dingin/Lembap), dan jaga pola makan sesuai sindrom.",
      herbal_recommendation: selectedSyndrome.herbal_recommendation,
      safetyWarnings: selectedSyndrome.warnings,
      isMultiOrganInteraction: false,
      wuxingElement: selectedSyndrome.syndrome.wuxing_element
  } : null;

  return (
    <div className="flex h-full p-4 gap-4 print:p-0 print:gap-0 print:block">
      {diagnosisForModal && (
          <DoctorNoteModal 
            isOpen={showNoteModal} 
            onClose={() => setShowNoteModal(false)} 
            diagnosis={diagnosisForModal}
          />
      )}

      {/* Kolom Kiri: Daftar Sindrom & Scoring */}
      <div className="w-1/3 min-h-full max-h-full overflow-y-auto bg-slate-900 rounded-xl p-3 shadow-lg print:hidden flex flex-col">
        {onBack && (
            <button 
                onClick={onBack}
                className="flex items-center gap-2 text-slate-400 hover:text-white mb-4 text-xs font-semibold uppercase tracking-wider transition-colors px-1"
            >
                <ArrowLeft className="w-4 h-4" /> Back to Syndrome Atlas
            </button>
        )}
        <h2 className="text-xl font-bold text-tcm-primary mb-4 border-b border-slate-800 pb-2">CDSS Analysis Results</h2>
        <div className="flex-1 overflow-y-auto">
            {sortedAnalysis.length > 0 ? (
                sortedAnalysis.map((res) => (
                  <div 
                    key={res.syndrome.id}
                    className={`p-3 mb-2 rounded-lg cursor-pointer transition-all ${
                      selectedSyndrome?.syndrome.id === res.syndrome.id 
                        ? 'bg-tcm-primary/30 border-tcm-primary border-l-4' 
                        : 'bg-slate-800 hover:bg-slate-700/50 border-l-4 border-slate-800'
                    }`}
                    onClick={() => setSelectedSyndrome(res)}
                  >
                    <div className="flex justify-between items-center">
                        <span className="font-semibold text-white">{res.syndrome.name_id}</span>
                        <span className="text-sm font-bold text-tcm-primary">{res.score.toFixed(1)}%</span>
                    </div>
                    <div className='text-xs text-slate-400 mt-1 flex gap-2 items-center'>
                        <Activity className='w-3 h-3 text-slate-500'/>
                        {res.syndrome.primary_organs?.join(', ') || 'N/A'}
                    </div>
                  </div>
                ))
            ) : (
                <div className="text-slate-500 text-sm text-center py-10 italic">
                    {initialSyndromeId ? "Viewing manual selection." : "No analysis run yet."}
                </div>
            )}
        </div>

        <div className="mt-4 border-t border-slate-800 pt-4 shrink-0">
             <button 
                onClick={onAnalyzeRequest}
                disabled={isAnalyzing}
                className="w-full px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg text-sm font-bold shadow-lg shadow-indigo-900/20 flex items-center justify-center gap-2 transition-colors disabled:opacity-50"
             >
                {isAnalyzing ? <Loader2 className="w-4 h-4 animate-spin" /> : <BrainCircuit className="w-4 h-4" />} 
                {isAnalyzing ? 'Analyzing...' : 'Re-Analyze Patient Data'}
             </button>
        </div>
      </div>

      {/* Kolom Kanan: Detail Sindrom & Peta 2D */}
      <div 
        ref={contentRef}
        className="flex-1 min-h-full flex flex-col bg-slate-800 rounded-xl p-4 shadow-lg overflow-hidden relative print:w-full print:min-h-0 print:h-auto print:p-0 print:rounded-none print:shadow-none print:bg-white print:text-black"
      >
        {selectedSyndrome ? (
          <>
            <div className="flex-shrink-0 mb-4 print:mb-0 print:border-b print:border-gray-300 print:pb-2">
                <h3 className="text-2xl font-bold text-white print:text-black">
                  {selectedSyndrome.syndrome.name_id} 
                  <span className='text-tcm-primary ml-2 text-xl'>({selectedSyndrome.score.toFixed(1)}%)</span>
                </h3>
                <p className='text-sm text-slate-400 print:text-gray-600'>{selectedSyndrome.syndrome.name_en}</p>
            </div>

            {/* Konten Utama Detail (Grid 2 Kolom: 2D Map + Rx Details) */}
            <div className='flex-1 grid grid-cols-2 gap-4 overflow-y-auto print:block print:overflow-visible print:h-auto print:p-4'>

                {/* Kolom 1: Peta Tubuh 2D (Standard) */}
                <div 
                    className="w-full rounded-lg border border-slate-700 bg-slate-900 overflow-hidden shadow-inner print:hidden flex items-center justify-center p-4 relative" 
                    style={{ minHeight: '450px' }}
                >
                    <div className="absolute top-2 left-2 z-10 bg-slate-900/80 px-2 py-1 rounded border border-slate-700 text-[10px] text-slate-400">
                        Map Visualizer
                    </div>
                    {selectedSyndrome ? (
                        <BodyMapSekarangJadi points={activePoints} />
                    ) : (
                        <div className="text-slate-500">Pilih sindrom untuk melihat titik.</div>
                    )}
                </div>

                {/* Kolom 2: Detail Resep (Prescription Details) */}
                <div className="space-y-4 print:space-y-2">
                    <div className="bg-slate-900 p-3 rounded-lg border border-slate-700 print:bg-white print:border-gray-300">
                        <div className="flex justify-between items-center mb-2">
                            <h4 className="text-lg font-semibold text-tcm-secondary flex items-center gap-2 print:text-black">
                                <MapPin className='w-4 h-4 text-rose-400' /> Titik Akupunktur (Active)
                            </h4>
                            <span className="text-xs bg-slate-800 text-slate-400 px-2 py-0.5 rounded-full border border-slate-700">
                                {activePoints.length} Points
                            </span>
                        </div>

                        <div className="flex flex-wrap gap-2 text-sm text-white print:text-black mb-3">
                            {(activePoints).length > 0 ? (
                                activePoints.map((p, i) => (
                                    <div 
                                        key={`${p.code}-${i}`} 
                                        className={`group relative px-3 py-1 rounded-full text-xs font-semibold border flex items-center gap-1 transition-all ${
                                            p.role === 'manual' 
                                            ? 'bg-purple-900/50 text-purple-200 border-purple-500 hover:bg-purple-900' 
                                            : 'bg-emerald-700/50 text-white border-emerald-600 print:bg-emerald-100 print:text-black print:border-emerald-300'
                                        }`}
                                    >
                                        {p.code}
                                        {p.role === 'manual' && (
                                            <button 
                                                onClick={() => removeManualPoint(p.code)}
                                                className="ml-1 text-purple-300 hover:text-white"
                                            >
                                                <X className="w-3 h-3" />
                                            </button>
                                        )}
                                    </div>
                                ))
                            ) : (
                                <span className="text-slate-500">Tidak ada titik akupunktur yang direkomendasikan.</span>
                            )}
                        </div>

                        {/* INPUT TITIK MANUAL */}
                        <form onSubmit={handleAddManualPoint} className="flex gap-2 items-center mt-4 pt-3 border-t border-slate-800 print:hidden">
                            <Syringe className="w-4 h-4 text-slate-500" />
                            <input 
                                type="text"
                                value={manualInput}
                                onChange={(e) => setManualInput(e.target.value)}
                                placeholder="Tambah Titik (e.g. LI4)"
                                className="flex-1 bg-slate-950 border border-slate-700 rounded-lg px-3 py-1.5 text-xs text-white placeholder-slate-500 focus:border-indigo-500 outline-none uppercase"
                            />
                            <button 
                                type="submit"
                                disabled={!manualInput.trim()}
                                className="bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 text-white p-1.5 rounded-lg transition-colors"
                            >
                                <Plus className="w-4 h-4" />
                            </button>
                        </form>
                    </div>

                    {/* ... Sisa logika resep herbal ... */}
                    <div className="bg-slate-900 p-3 rounded-lg border border-slate-700 print:bg-white print:border-gray-300">
                        <h4 className="text-lg font-semibold text-tcm-secondary mb-2 flex items-center gap-2 print:text-black">
                             <Leaf className='w-4 h-4 text-yellow-400'/> Herbal Prescription
                        </h4>
                        <div className="grid grid-cols-2 gap-3 text-xs">
                             <div className="bg-slate-950/20 border border-slate-700/50 p-2 rounded">
                                 <span className="text-tcm-primary font-bold block mb-1 uppercase text-[10px] print:text-black">Chief (Jun)</span>
                                 <div className="text-slate-300 print:text-black">
                                     {renderHerbList(selectedSyndrome.herbal_recommendation?.chief)}
                                 </div>
                             </div>
                             <div className="bg-slate-950/20 border border-slate-700/50 p-2 rounded">
                                 <span className="text-tcm-primary font-bold block mb-1 uppercase text-[10px] print:text-black">Assistant (Chen)</span>
                                 <div className="text-slate-300 print:text-black">
                                     {renderHerbList(selectedSyndrome.herbal_recommendation?.assistants)}
                                 </div>
                             </div>
                        </div>
                    </div>
                </div>

            </div>

            {/* Footer / Print Button */}
            <div className="flex-shrink-0 mt-4 text-xs text-slate-500 border-t border-slate-800 pt-4 print:border-t print:border-gray-300 print:pt-4">
                 Generated by TCM WuXing Pro Auto-Rx Engine v{TCM_DB.metadata.version}
            </div>

            {/* Bottom Actions Floating Bar */}
            <div className="absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-slate-950 via-slate-950 to-transparent flex justify-end gap-3 print:hidden">
               <button 
                  onClick={handleSnapshot}
                  className="px-4 py-2 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-lg text-sm font-semibold border border-slate-700 transition-colors flex items-center gap-2"
                  title="Simpan tampilan layar sebagai PDF"
               >
                  <Camera className="w-4 h-4" /> Snapshot PDF
               </button>
               <button 
                  onClick={() => setShowNoteModal(true)}
                  className="px-5 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg text-sm font-bold shadow-lg shadow-indigo-900/20 flex items-center gap-2 transition-colors"
                  title="Buat Nota / Resep Resmi"
               >
                  <FileText className="w-4 h-4" /> Nota / Resep
               </button>
            </div>
          </>
        ) : (
          <div className="flex items-center justify-center h-full text-slate-500 print:hidden">
             <div className="text-center">
               <ArrowRight className="w-8 h-8 mx-auto mb-2 opacity-30" />
               <p>Pilih hasil diagnosis dari panel kiri untuk melihat detail.</p>
               <button onClick={onAnalyzeRequest} className="mt-4 text-tcm-primary hover:underline text-sm font-semibold">
                    Atau mulai analisis baru
               </button>
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default ScoringAndPointsHub;

import React, { useState } from 'react';
import { TcmDiagnosisResult } from '../types';
import { TCM_DB } from '../constants';
import { AlertTriangle, Activity, Thermometer, Stethoscope, GitMerge, MapPin, BrainCircuit, Info, MoveUpRight, Split, RefreshCw, ShieldAlert, ArrowRight, Download, Printer, Leaf, X, Map, FileText, Layers, Target } from 'lucide-react';
import DoctorNoteModal from './DoctorNoteModal';

interface Props {
  diagnosis: TcmDiagnosisResult;
  isPregnant: boolean;
  onShowVisualizer: (element?: string) => void;
}

const DiagnosisCard: React.FC<Props> = ({ diagnosis, isPregnant, onShowVisualizer }) => {
  const [showHerbInfo, setShowHerbInfo] = useState<string | null>(null);
  const [showNoteModal, setShowNoteModal] = useState(false);

  // Flatten syndromes from both lists
  const allSyndromes = [
    ...TCM_DB.syndromes.FILLED_FROM_PDF,
    ...TCM_DB.syndromes.TODO_FROM_PDF
  ];

  const pattern = allSyndromes.find(p => p.id === diagnosis.patternId);

  // Fallback if ID not found directly
  const patternName = pattern ? pattern.name_id : diagnosis.patternId.replace(/_/g, ' ');

  // Robust check for multi-organ interaction
  const multiOrganKeywords = [
    'interaksi', 'interaction',
    'overacting', 'insulting', 'invading', 'attacking',
    'mempengaruhi', 'affecting', 
    'hubungan', 'relationship', 
    'combined', 'gabungan',
    'generating', 'producing'
  ];
  const isMultiOrgan = diagnosis.isMultiOrganInteraction ?? multiOrganKeywords.some(k => diagnosis.explanation.toLowerCase().includes(k));

  const handleVisualizerClick = () => {
    // Attempt to extract the primary element from the diagnosis analysis
    let elementToHighlight = diagnosis.wuxingElement?.toLowerCase();

    // Fallback if structured data missing
    if (!elementToHighlight) {
        const text = (diagnosis.wuxingAnalysis || pattern?.wuxing_element || "").toLowerCase();
        if (text.includes('wood') || text.includes('liver') || text.includes('gall')) elementToHighlight = 'wood';
        else if (text.includes('fire') || text.includes('heart') || text.includes('small intestine') || text.includes('pericardium')) elementToHighlight = 'fire';
        else if (text.includes('earth') || text.includes('spleen') || text.includes('stomach')) elementToHighlight = 'earth';
        else if (text.includes('metal') || text.includes('lung') || text.includes('large intestine')) elementToHighlight = 'metal';
        else if (text.includes('water') || text.includes('kidney') || text.includes('bladder')) elementToHighlight = 'water';
    }

    onShowVisualizer(elementToHighlight);
  };

  const handleDownload = () => {
    const timestamp = new Date().toLocaleString();
    const herbs = diagnosis.herbal_recommendation 
      ? `
HERBAL RECOMMENDATION:
Formula: ${diagnosis.herbal_recommendation.formula_name || 'Custom Formula'}
- Chief Herbs: ${diagnosis.herbal_recommendation.chief.join(', ')}
- Assistant Herbs: ${diagnosis.herbal_recommendation.assistants?.join(', ') || '-'}
- Avoid: ${diagnosis.herbal_recommendation.avoid?.join(', ') || '-'}
` 
      : '';

    const warnings = diagnosis.safetyWarnings?.length
      ? `\nSAFETY WARNINGS:\n${diagnosis.safetyWarnings.map(w => `! ${w}`).join('\n')}`
      : '';

    const secondary = diagnosis.secondaryOptions?.length 
      ? `\nDIFFERENTIAL DIAGNOSIS:\n${diagnosis.secondaryOptions.map(opt => `- ${opt.patternName} (${Math.round(opt.confidence * 100)}%): ${opt.reason}`).join('\n')}` 
      : '';

    const content = `TCM WUXING PRO - DIAGNOSIS REPORT
Date: ${timestamp}
----------------------------------------

PRIMARY DIAGNOSIS: ${patternName}
Confidence: ${Math.round(diagnosis.confidence * 100)}%
Wu Xing Element: ${diagnosis.wuxingElement || '-'}
Wu Xing Dynamic: ${diagnosis.wuxingDynamic || '-'}
Analysis: ${diagnosis.wuxingAnalysis || '-'}

CLINICAL ANALYSIS:
Root (Ben): ${diagnosis.analysisDetail?.root || '-'}
Branch (Biao): ${diagnosis.analysisDetail?.branch || '-'}

Explanation:
${diagnosis.explanation}
${warnings}

ACUPUNCTURE POINTS (Titik Final):
${diagnosis.recommendedPoints.join(', ')}

${herbs}
${secondary}

LIFESTYLE ADVICE:
${diagnosis.lifestyleAdvice}

----------------------------------------
Generated by TCM WuXing Pro AI
Disclaimer: This is for educational purposes only. Consult a licensed practitioner.
`;

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `TCM_Diagnosis_${new Date().toISOString().slice(0,10)}.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handlePrint = () => {
    window.print();
  };

  const getCycleBadge = (dynamic?: string, analysisText?: string) => {
    // Priority check on structured dynamic field
    if (dynamic) {
        const lower = dynamic.toLowerCase();
        if (lower.includes('overact') || lower.includes('cheng')) return { label: 'Overacting (Cheng)', color: 'bg-red-900/40 text-red-300 border-red-700', icon: <AlertTriangle className="w-3 h-3"/> };
        if (lower.includes('insult') || lower.includes('wu')) return { label: 'Insulting (Wu)', color: 'bg-orange-900/40 text-orange-300 border-orange-700', icon: <ShieldAlert className="w-3 h-3"/> };
        if (lower.includes('generat') || lower.includes('mother') || lower.includes('sheng')) return { label: 'Generating (Sheng)', color: 'bg-emerald-900/40 text-emerald-300 border-emerald-700', icon: <RefreshCw className="w-3 h-3"/> };
        if (lower.includes('control') || lower.includes('ke')) return { label: 'Controlling (Ke)', color: 'bg-indigo-900/40 text-indigo-300 border-indigo-700', icon: <Activity className="w-3 h-3"/> };
    }

    // Fallback to text analysis
    const lower = (analysisText || "").toLowerCase();
    if (lower.includes('overact') || lower.includes('invad')) return { label: 'Overacting (Cheng)', color: 'bg-red-900/40 text-red-300 border-red-700', icon: <AlertTriangle className="w-3 h-3"/> };
    if (lower.includes('insult')) return { label: 'Insulting (Wu)', color: 'bg-orange-900/40 text-orange-300 border-orange-700', icon: <ShieldAlert className="w-3 h-3"/> };
    if (lower.includes('generat') || lower.includes('nourish') || lower.includes('mother')) return { label: 'Generating Issue (Sheng)', color: 'bg-emerald-900/40 text-emerald-300 border-emerald-700', icon: <RefreshCw className="w-3 h-3"/> };
    if (lower.includes('control')) return { label: 'Controlling (Ke)', color: 'bg-indigo-900/40 text-indigo-300 border-indigo-700', icon: <Activity className="w-3 h-3"/> };
    return null;
  };

  const cycleBadge = getCycleBadge(diagnosis.wuxingDynamic, diagnosis.wuxingAnalysis);

  // Helper to find herb details
  const getHerbDetails = (herbStr: string) => {
    const lower = herbStr.toLowerCase();
    if (lower.includes('sambiloto') || lower.includes('chuan xin lian')) return TCM_DB.herbal_guidelines.metadata.herb_core_properties.Chuan_Xin_Lian_Sambiloto;
    if (lower.includes('jahe segar') || lower.includes('sheng jiang')) return TCM_DB.herbal_guidelines.metadata.herb_core_properties.Sheng_Jiang_Jahe_Segar;
    if (lower.includes('jahe kering') || lower.includes('gan jiang')) return TCM_DB.herbal_guidelines.metadata.herb_core_properties.Gan_Jiang_Jahe_Kering;
    return null;
  };

  const renderHerbList = (herbs: string[]) => {
    return (
      <div className="flex flex-wrap gap-2">
        {herbs.map((herb, idx) => {
          const details = getHerbDetails(herb);
          return (
            <div key={idx} className="flex items-center gap-1">
              <span>{herb}</span>
              {details && (
                <button
                  onClick={() => setShowHerbInfo(showHerbInfo === herb ? null : herb)}
                  className="p-0.5 rounded-full hover:bg-slate-700 text-slate-400 hover:text-tcm-primary transition-colors"
                  title="View Herb Details"
                >
                  <Info className="w-3 h-3" />
                </button>
              )}
              {idx < herbs.length - 1 && <span>, </span>}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <>
      <DoctorNoteModal 
         isOpen={showNoteModal} 
         onClose={() => setShowNoteModal(false)} 
         diagnosis={diagnosis}
      />

      <div className="bg-slate-800 border border-tcm-secondary/50 rounded-xl p-4 my-2 shadow-lg animate-fade-in print:bg-white print:text-black print:border-black print:shadow-none">
        <div className="flex items-center gap-2 mb-4 border-b border-slate-700 pb-2 print:border-black">
          <Activity className="w-5 h-5 text-tcm-primary print:text-black" />
          <div className="flex flex-col flex-1">
            <h3 className="font-bold text-lg text-tcm-primary leading-tight print:text-black">{patternName}</h3>
            {pattern?.name_en && (
               <span className="text-xs text-slate-400 italic print:text-gray-600">{pattern.name_en}</span>
            )}
          </div>

          {/* Actions for Desktop/Mobile (Hidden in Print) */}
          <div className="flex items-center gap-2 print:hidden">
              <button 
                  onClick={() => setShowNoteModal(true)}
                  className="px-3 py-1.5 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg text-xs font-bold transition-colors flex items-center gap-1 shadow-lg shadow-indigo-900/20"
                  title="Buat Nota / Resep Dokter"
              >
                  <FileText className="w-3 h-3" /> Nota
              </button>
              <button 
                  onClick={handleDownload} 
                  className="p-1.5 text-slate-400 hover:text-white hover:bg-slate-700 rounded-lg transition-colors"
                  title="Save Report to TXT"
              >
                  <Download className="w-4 h-4" />
              </button>
              <button 
                  onClick={handlePrint} 
                  className="p-1.5 text-slate-400 hover:text-white hover:bg-slate-700 rounded-lg transition-colors hidden sm:block"
                  title="Print / Save to PDF"
              >
                  <Printer className="w-4 h-4" />
              </button>
          </div>

          <div className="flex flex-col items-end ml-2 print:hidden">
             <span className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">Confidence</span>
             <span className="text-sm font-bold text-emerald-400">
               {Math.round(diagnosis.confidence * 100)}%
             </span>
          </div>
        </div>

        {/* SYNDROME PROFILE SECTION */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mb-5">
           <div className="bg-slate-900/40 border border-slate-700 p-2.5 rounded-lg flex flex-col gap-1 print:bg-white print:border-gray-300">
              <div className="flex items-center gap-1.5 text-[10px] font-bold text-slate-500 uppercase tracking-wider print:text-black">
                 <Target className="w-3 h-3" /> Primary Organs
              </div>
              <div className="text-xs font-semibold text-slate-200 print:text-black">
                 {pattern?.primary_organs?.join(', ') || diagnosis.patternId.split('_')[0] || '-'}
              </div>
           </div>

