          <div className="flex flex-wrap gap-2">
            {diagnosis.recommendedPoints.map((point) => {
              const isContra = isPregnant && TCM_DB.core_rules.pregnancy_contraindications?.includes(point);
              return (
                <div 
                  key={point} 
                  className={`px-3 py-1.5 rounded-lg text-sm font-bold flex items-center gap-1 transition-transform hover:scale-105 cursor-default shadow-md print:bg-white print:text-black print:border-black print:border ${
                    isContra 
                    ? 'bg-red-900/50 text-red-400 border border-red-500' 
                    : 'bg-gradient-to-b from-tcm-secondary/30 to-slate-800 text-tcm-primary border border-tcm-secondary'
                  }`}
                >
                  {point}
                  {isContra && <AlertTriangle className="w-3 h-3" />}
                </div>
              );
            })}
          </div>
          {isPregnant && diagnosis.recommendedPoints.some(p => TCM_DB.core_rules.pregnancy_contraindications?.includes(p)) && (
               <p className="text-red-400 text-xs mt-2 flex items-center gap-1 animate-pulse bg-red-900/20 p-2 rounded print:text-red-600 print:border-red-600 print:bg-white print:border">
                  <AlertTriangle className="w-3 h-3" /> Warning: Some points are contraindicated for pregnancy!
