                      <span className="text-rose-400 font-bold block mb-1 uppercase text-[10px] print:text-black">Avoid / Contraindicated</span>
                      <span className="text-slate-300 print:text-black">{diagnosis.herbal_recommendation.avoid.join(', ')}</span>
