};

export default DiagnosisCard;

import React, { useState, useRef } from 'react';
import { TcmDiagnosisResult } from '../types';
import { TCM_DB } from '../constants';
import { AlertTriangle, Activity, Thermometer, Stethoscope, GitMerge, MapPin, BrainCircuit, Info, MoveUpRight, Split, RefreshCw, ShieldAlert, ArrowRight, Download, Printer, Leaf, X, Map, FileText, Layers, Target, FileDown } from 'lucide-react';
import DoctorNoteModal from './DoctorNoteModal';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface Props {
  diagnosis: TcmDiagnosisResult;
  isPregnant: boolean;
  onShowVisualizer: (element?: string) => void;
}

const DiagnosisCard: React.FC<Props> = ({ diagnosis, isPregnant, onShowVisualizer }) => {
  const [showHerbInfo, setShowHerbInfo] = useState<string | null>(null);
  const [showNoteModal, setShowNoteModal] = useState(false);
  const cardRef = useRef<HTMLDivElement>(null);

  // Flatten syndromes from both lists
  const allSyndromes = [
    ...TCM_DB.syndromes.FILLED_FROM_PDF,
    ...TCM_DB.syndromes.TODO_FROM_PDF
  ];

  const pattern = allSyndromes.find(p => p.id === diagnosis.patternId);

  // Fallback if ID not found directly
  const patternName = pattern ? pattern.name_id : diagnosis.patternId.replace(/_/g, ' ');

  // Robust check for multi-organ interaction
  const multiOrganKeywords = [
    'interaksi', 'interaction',
    'overacting', 'insulting', 'invading', 'attacking',
    'mempengaruhi', 'affecting', 
    'hubungan', 'relationship', 
    'combined', 'gabungan',
    'generating', 'producing'
  ];
  const isMultiOrgan = diagnosis.isMultiOrganInteraction ?? multiOrganKeywords.some(k => diagnosis.explanation.toLowerCase().includes(k));

  const handleVisualizerClick = () => {
    // Attempt to extract the primary element from the diagnosis analysis
    let elementToHighlight = diagnosis.wuxingElement?.toLowerCase();

    // Fallback if structured data missing
    if (!elementToHighlight) {
        const text = (diagnosis.wuxingAnalysis || pattern?.wuxing_element || "").toLowerCase();
        if (text.includes('wood') || text.includes('liver') || text.includes('gall')) elementToHighlight = 'wood';
        else if (text.includes('fire') || text.includes('heart') || text.includes('small intestine') || text.includes('pericardium')) elementToHighlight = 'fire';
        else if (text.includes('earth') || text.includes('spleen') || text.includes('stomach')) elementToHighlight = 'earth';
        else if (text.includes('metal') || text.includes('lung') || text.includes('large intestine')) elementToHighlight = 'metal';
        else if (text.includes('water') || text.includes('kidney') || text.includes('bladder')) elementToHighlight = 'water';
    }

    onShowVisualizer(elementToHighlight);
  };

  const handleExportPDF = async () => {
    if (!cardRef.current) return;

    try {
      const canvas = await html2canvas(cardRef.current, {
        scale: 2,
        useCORS: true,
        backgroundColor: '#1e293b', // Match slate-800
        logging: false
      });

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pageWidth = pdf.internal.pageSize.getWidth();
      const pageHeight = pdf.internal.pageSize.getHeight();

      const imgProps = pdf.getImageProperties(imgData);
      const imgHeight = (imgProps.height * pageWidth) / imgProps.width;

      // Basic padding
      const xOffset = 0;
      const yOffset = 0;

      pdf.addImage(imgData, 'PNG', xOffset, yOffset, pageWidth, imgHeight);
      pdf.save(`TCM_Report_${patternName.replace(/\s+/g, '_')}_${new Date().toISOString().slice(0,10)}.pdf`);
    } catch (error) {
      console.error("PDF Export Error:", error);
      alert("Failed to export PDF. Please try again.");
    }
  };

  const handleDownload = () => {
    const timestamp = new Date().toLocaleString();
    const herbs = diagnosis.herbal_recommendation 
      ? `
HERBAL RECOMMENDATION:
Formula: ${diagnosis.herbal_recommendation.formula_name || 'Custom Formula'}
- Chief Herbs: ${diagnosis.herbal_recommendation.chief.join(', ')}
- Assistant Herbs: ${diagnosis.herbal_recommendation.assistants?.join(', ') || '-'}
- Avoid: ${diagnosis.herbal_recommendation.avoid?.join(', ') || '-'}
` 
      : '';

    const warnings = diagnosis.safetyWarnings?.length
      ? `\nSAFETY WARNINGS:\n${diagnosis.safetyWarnings.map(w => `! ${w}`).join('\n')}`
      : '';

    const secondary = diagnosis.secondaryOptions?.length 
      ? `\nDIFFERENTIAL DIAGNOSIS:\n${diagnosis.secondaryOptions.map(opt => `- ${opt.patternName} (${Math.round(opt.confidence * 100)}%): ${opt.reason}`).join('\n')}` 
      : '';

    const content = `TCM WUXING PRO - DIAGNOSIS REPORT
Date: ${timestamp}
----------------------------------------

PRIMARY DIAGNOSIS: ${patternName}
Confidence: ${Math.round(diagnosis.confidence * 100)}%
Wu Xing Element: ${diagnosis.wuxingElement || '-'}
Wu Xing Dynamic: ${diagnosis.wuxingDynamic || '-'}
Analysis: ${diagnosis.wuxingAnalysis || '-'}

CLINICAL ANALYSIS:
Root (Ben): ${diagnosis.analysisDetail?.root || '-'}
Branch (Biao): ${diagnosis.analysisDetail?.branch || '-'}

Explanation:
${diagnosis.explanation}
${warnings}

ACUPUNCTURE POINTS (Titik Final):
${diagnosis.recommendedPoints.join(', ')}

${herbs}
${secondary}

LIFESTYLE ADVICE:
${diagnosis.lifestyleAdvice}

----------------------------------------
Generated by TCM WuXing Pro AI
Disclaimer: This is for educational purposes only. Consult a licensed practitioner.
`;

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `TCM_Diagnosis_${new Date().toISOString().slice(0,10)}.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handlePrint = () => {
    window.print();
  };

  const getCycleBadge = (dynamic?: string, analysisText?: string) => {
    // Priority check on structured dynamic field
    if (dynamic) {
        const lower = dynamic.toLowerCase();
        if (lower.includes('overact') || lower.includes('cheng')) return { label: 'Overacting (Cheng)', color: 'bg-red-900/40 text-red-300 border-red-700', icon: <AlertTriangle className="w-3 h-3"/> };
        if (lower.includes('insult') || lower.includes('wu')) return { label: 'Insulting (Wu)', color: 'bg-orange-900/40 text-orange-300 border-orange-700', icon: <ShieldAlert className="w-3 h-3"/> };
        if (lower.includes('generat') || lower.includes('mother') || lower.includes('sheng')) return { label: 'Generating (Sheng)', color: 'bg-emerald-900/40 text-emerald-300 border-emerald-700', icon: <RefreshCw className="w-3 h-3"/> };
        if (lower.includes('control') || lower.includes('ke')) return { label: 'Controlling (Ke)', color: 'bg-indigo-900/40 text-indigo-300 border-indigo-700', icon: <Activity className="w-3 h-3"/> };
    }

    // Fallback to text analysis
    const lower = (analysisText || "").toLowerCase();
    if (lower.includes('overact') || lower.includes('invad')) return { label: 'Overacting (Cheng)', color: 'bg-red-900/40 text-red-300 border-red-700', icon: <AlertTriangle className="w-3 h-3"/> };
    if (lower.includes('insult')) return { label: 'Insulting (Wu)', color: 'bg-orange-900/40 text-orange-300 border-orange-700', icon: <ShieldAlert className="w-3 h-3"/> };
    if (lower.includes('generat') || lower.includes('nourish') || lower.includes('mother')) return { label: 'Generating Issue (Sheng)', color: 'bg-emerald-900/40 text-emerald-300 border-emerald-700', icon: <RefreshCw className="w-3 h-3"/> };
    if (lower.includes('control')) return { label: 'Controlling (Ke)', color: 'bg-indigo-900/40 text-indigo-300 border-indigo-700', icon: <Activity className="w-3 h-3"/> };
    return null;
  };

  const cycleBadge = getCycleBadge(diagnosis.wuxingDynamic, diagnosis.wuxingAnalysis);

  // Helper to find herb details
  const getHerbDetails = (herbStr: string) => {
    const lower = herbStr.toLowerCase();
    if (lower.includes('sambiloto') || lower.includes('chuan xin lian')) return TCM_DB.herbal_guidelines.metadata.herb_core_properties.Chuan_Xin_Lian_Sambiloto;
    if (lower.includes('jahe segar') || lower.includes('sheng jiang')) return TCM_DB.herbal_guidelines.metadata.herb_core_properties.Sheng_Jiang_Jahe_Segar;
    if (lower.includes('jahe kering') || lower.includes('gan jiang')) return TCM_DB.herbal_guidelines.metadata.herb_core_properties.Gan_Jiang_Jahe_Kering;
    return null;
  };

  const renderHerbList = (herbs: string[]) => {
    return (
      <div className="flex flex-wrap gap-2">
        {herbs.map((herb, idx) => {
          const details = getHerbDetails(herb);
          return (
            <div key={idx} className="flex items-center gap-1">
              <span>{herb}</span>
              {details && (
                <button
                  onClick={() => setShowHerbInfo(showHerbInfo === herb ? null : herb)}
                  className="p-0.5 rounded-full hover:bg-slate-700 text-slate-400 hover:text-tcm-primary transition-colors"
                  title="View Herb Details"
                >
                  <Info className="w-3 h-3" />
                </button>
              )}
              {idx < herbs.length - 1 && <span>, </span>}
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <>
      <DoctorNoteModal 
         isOpen={showNoteModal} 
         onClose={() => setShowNoteModal(false)} 
         diagnosis={diagnosis}
      />

      <div 
        ref={cardRef}
        className="bg-slate-800 border border-tcm-secondary/50 rounded-xl p-4 my-2 shadow-lg animate-fade-in print:bg-white print:text-black print:border-black print:shadow-none"
      >
        <div className="flex items-center gap-2 mb-4 border-b border-slate-700 pb-2 print:border-black">
          <Activity className="w-5 h-5 text-tcm-primary print:text-black" />
          <div className="flex flex-col flex-1">
            <h3 className="font-bold text-lg text-tcm-primary leading-tight print:text-black">{patternName}</h3>
            {pattern?.name_en && (
               <span className="text-xs text-slate-400 italic print:text-gray-600">{pattern.name_en}</span>
            )}
          </div>

          {/* Actions for Desktop/Mobile (Hidden in Print) */}
          <div className="flex items-center gap-2 print:hidden">
              <button 
                  onClick={() => setShowNoteModal(true)}
                  className="px-3 py-1.5 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg text-xs font-bold transition-colors flex items-center gap-1 shadow-lg shadow-indigo-900/20"
                  title="Buat Nota / Resep Dokter"
              >
                  <FileText className="w-3 h-3" /> Nota
              </button>
              <button 
                  onClick={handleExportPDF} 
                  className="p-1.5 text-slate-400 hover:text-tcm-primary hover:bg-slate-700 rounded-lg transition-colors"
                  title="Export Report PDF"
              >
                  <FileDown className="w-4 h-4" />
              </button>
              <button 
                  onClick={handleDownload} 
                  className="p-1.5 text-slate-400 hover:text-white hover:bg-slate-700 rounded-lg transition-colors"
                  title="Save Report to TXT"
              >
                  <Download className="w-4 h-4" />
              </button>
              <button 
                  onClick={handlePrint} 
                  className="p-1.5 text-slate-400 hover:text-white hover:bg-slate-700 rounded-lg transition-colors hidden sm:block"
                  title="Print Interface"
              >
                  <Printer className="w-4 h-4" />
              </button>
          </div>

          <div className="flex flex-col items-end ml-2 print:hidden">
             <span className="text-[10px] text-slate-400 uppercase font-bold tracking-wider">Confidence</span>
             <span className="text-sm font-bold text-emerald-400">
               {Math.round(diagnosis.confidence * 100)}%
             </span>
          </div>
        </div>

        {/* SYNDROME PROFILE SECTION */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mb-5">
           <div className="bg-slate-900/40 border border-slate-700 p-2.5 rounded-lg flex flex-col gap-1 print:bg-white print:border-gray-300">
              <div className="flex items-center gap-1.5 text-[10px] font-bold text-slate-500 uppercase tracking-wider print:text-black">
                 <Target className="w-3 h-3" /> Primary Organs
              </div>
              <div className="text-xs font-semibold text-slate-200 print:text-black">
                 {pattern?.primary_organs?.join(', ') || diagnosis.patternId.split('_')[0] || '-'}
              </div>
           </div>

           <div className="bg-slate-900/40 border border-slate-700 p-2.5 rounded-lg flex flex-col gap-1 print:bg-white print:border-gray-300">
              <div className="flex items-center gap-1.5 text-[10px] font-bold text-slate-500 uppercase tracking-wider print:text-black">
                 <Layers className="w-3 h-3" /> Wu Xing Element
              </div>
              <div className="text-xs font-semibold text-tcm-primary print:text-black">
                 {diagnosis.wuxingElement || pattern?.wuxing_element || '-'}
              </div>
           </div>

           <div className="bg-slate-900/40 border border-slate-700 p-2.5 rounded-lg flex flex-col gap-1 print:bg-white print:border-gray-300">
              <div className="flex items-center gap-1.5 text-[10px] font-bold text-slate-500 uppercase tracking-wider print:text-black">
                 <Activity className="w-3 h-3" /> Pattern Type
              </div>
              <div className="text-xs font-semibold text-amber-400 print:text-black truncate">
                 {pattern?.pattern_type?.replace(/_/g, ' ') || 'Diagnostic Pattern'}
              </div>
           </div>
        </div>

        {/* Safety Warnings Section */}
        {diagnosis.safetyWarnings && diagnosis.safetyWarnings.length > 0 && (
           <div className="mb-4 bg-red-900/30 border-l-4 border-red-500 p-3 rounded-r-lg shadow-sm animate-pulse-slow print:border-red-600 print:bg-gray-100">
              <div className="flex items-center gap-2 text-red-400 font-bold text-xs uppercase tracking-wide mb-1 print:text-red-600">
                 <AlertTriangle className="w-4 h-4" /> Safety Warnings Detected
              </div>
              <ul className="list-disc list-inside text-sm text-red-200 print:text-black">
                 {diagnosis.safetyWarnings.map((w, i) => (
                    <li key={i}>{w}</li>
                 ))}
              </ul>
           </div>
        )}

        {/* Explanation Section */}
        <div className="bg-gradient-to-br from-slate-800 to-slate-700/60 border-l-4 border-tcm-accent rounded-r-lg p-4 mb-5 shadow-sm relative overflow-hidden print:bg-none print:border print:border-gray-300">
           <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none print:hidden">
              <Stethoscope className="w-24 h-24" />
           </div>

           <div className="flex items-center gap-2 mb-3 text-tcm-accent text-sm font-bold uppercase tracking-wide relative z-10 print:text-black">
              <Stethoscope className="w-4 h-4" /> Clinical Analysis
           </div>

           {/* Root vs Branch - Highlighted Top Section */}
           {diagnosis.analysisDetail && (
              <div className="mb-4 flex flex-col sm:flex-row items-stretch gap-2 relative z-10 print:flex-col print:gap-1">
                <div className="flex-1 bg-slate-900/60 p-3 rounded-lg border-l-2 border-emerald-500 shadow-sm flex flex-col justify-center print:bg-gray-100 print:border-black">
                  <span className="text-[10px] uppercase text-emerald-400 font-bold block mb-1 tracking-wider print:text-black">Root (Ben) • Origin</span>
                  <span className="text-xs text-slate-200 block font-medium leading-relaxed print:text-black">{diagnosis.analysisDetail.root}</span>
                </div>

                <div className="hidden sm:flex items-center justify-center px-1 print:hidden">
                  <ArrowRight className="w-4 h-4 text-slate-500 opacity-60" />
                </div>

                <div className="flex-1 bg-slate-900/60 p-3 rounded-lg border-l-2 border-amber-500 shadow-sm flex flex-col justify-center print:bg-gray-100 print:border-black">
                  <span className="text-[10px] uppercase text-amber-400 font-bold block mb-1 tracking-wider print:text-black">Branch (Biao) • Manifestation</span>
                  <span className="text-xs text-slate-200 block font-medium leading-relaxed print:text-black">{diagnosis.analysisDetail.branch}</span>
                </div>
              </div>
           )}

           <p className="text-slate-200 leading-relaxed text-sm whitespace-pre-line font-medium pl-1 relative z-10 print:text-black">
              {diagnosis.explanation}
           </p>

           {isMultiOrgan && (
              <div className="mt-3 flex items-center gap-2 text-xs text-indigo-300 bg-indigo-900/40 p-2 rounded border border-indigo-500/30 relative z-10 print:bg-white print:text-black print:border-black">
                 <GitMerge className="w-3 h-3 text-indigo-400 print:text-black" />
                 <span className="font-semibold text-indigo-200 print:text-black">Multi-Organ / Complex Interaction Detected</span>
              </div>
           )}
        </div>

        {/* Differential Diagnosis / Secondary Options */}
        {diagnosis.secondaryOptions && diagnosis.secondaryOptions.length > 0 && (
           <div className="mb-5 bg-slate-900/30 border border-slate-700 rounded-lg p-3 print:border-gray-300 print:bg-white">
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 flex items-center gap-2 print:text-black">
                <Split className="w-3 h-3" /> Differential Diagnosis (Alternatives)
              </h4>
              <div className="space-y-3">
                {diagnosis.secondaryOptions.map((opt, idx) => (
                  <div key={idx} className="relative">
                    <div className="flex justify-between items-center mb-1">
                      <span className="text-sm font-semibold text-slate-300 print:text-black">{opt.patternName || opt.patternId.replace(/_/g, ' ')}</span>
                      <span className="text-xs font-mono text-slate-400 print:text-gray-600">{Math.round(opt.confidence * 100)}%</span>
                    </div>
                    <div className="w-full bg-slate-700 h-1.5 rounded-full overflow-hidden mb-1 print:bg-gray-200">
                      <div 
                        className="bg-slate-500 h-full rounded-full print:bg-black" 
                        style={{ width: `${opt.confidence * 100}%` }}
                      ></div>
                    </div>
                    <p className="text-[11px] text-slate-500 italic leading-tight print:text-gray-600">
                      {opt.reason}
                    </p>
                  </div>
                ))}
              </div>
           </div>
        )}

        {/* Wu Xing Analysis Section */}
        <div className="mb-4 bg-slate-900/30 p-3 rounded-lg border border-slate-700/50 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-3 print:bg-white print:border-gray-300">
          <div className="flex-1">
            <p className="text-slate-400 text-xs uppercase font-semibold mb-2 flex items-center gap-1 print:text-black">
               <Activity className="w-3 h-3"/> Wu Xing Dynamics
            </p>
            <div className="text-sm text-slate-200 font-medium print:text-black">
               <div className="flex items-center flex-wrap gap-2 mb-1">
                 {cycleBadge && (
                   <span className={`text-[10px] px-2 py-0.5 rounded border flex items-center gap-1 font-bold uppercase tracking-wide print:text-black print:border-black ${cycleBadge.color}`}>
                      {cycleBadge.icon} {cycleBadge.label}
                   </span>
                 )}
                 {diagnosis.wuxingElement && (
                     <span className="font-bold text-tcm-primary">{diagnosis.wuxingElement}</span>
                 )}
                 <span className="text-slate-400 border-l border-slate-600 pl-2 ml-1 text-xs">
                   {diagnosis.wuxingAnalysis || pattern?.wuxing_element || "Not specified"}
                 </span>
               </div>

               {pattern?.primary_organs && (
                 <div className="text-slate-400 font-normal text-xs mt-1 flex items-center gap-1 print:text-gray-600">
                    Organs: <span className="text-slate-300 print:text-black">{pattern.primary_organs.join(', ')}</span>
                 </div>
               )}
            </div>
          </div>
          <button 
            onClick={handleVisualizerClick}
            className="flex items-center gap-1 text-xs bg-slate-700 hover:bg-slate-600 text-slate-200 px-3 py-2 rounded-lg transition-colors border border-slate-600 shrink-0 self-start sm:self-center print:hidden"
          >
            View Wu Xing Map <Map className="w-3 h-3" />
          </button>
        </div>

        {pattern && (
          <>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm mb-4 print:block">
              <div className="col-span-1 md:col-span-2 bg-slate-900/50 p-3 rounded-lg print:bg-white print:border print:border-gray-300 print:mb-2">
                  <p className="text-slate-400 text-xs uppercase font-semibold mb-1 flex items-center gap-1 print:text-black">
                     <BrainCircuit className="w-3 h-3"/> Manifestations
                  </p>
                  <div className="flex flex-wrap gap-2">
                      {pattern.clinical_manifestations && pattern.clinical_manifestations.length > 0 ? (
                          pattern.clinical_manifestations.map((s, i) => (
                              <span key={i} className="text-xs bg-slate-700 text-slate-300 px-2 py-1 rounded print:bg-gray-100 print:text-black">
                                  {s}
                              </span>
                          ))
                      ) : (
                          <span className="text-xs text-slate-500 italic">No symptoms details in DB yet.</span>
                      )}
                  </div>
              </div>

              <div className="col-span-1 md:col-span-2 print:border print:border-gray-300 print:p-2 print:rounded">
                  <p className="text-slate-400 text-xs uppercase font-semibold mb-1 flex items-center gap-1 print:text-black">
                      <Thermometer className="w-3 h-3"/> Tongue & Pulse
                  </p>
                  <div className="grid grid-cols-2 gap-2 text-xs">
                      <div className="bg-slate-700/30 p-2 rounded print:bg-white">
                          <span className="block text-tcm-accent font-bold mb-0.5 print:text-black">Tongue</span> <span className="print:text-black">{pattern.tongue.length ? pattern.tongue.join(', ') : '-'}</span>
                      </div>
                      <div className="bg-slate-700/30 p-2 rounded print:bg-white">
                          <span className="block text-tcm-accent font-bold mb-0.5 print:text-black">Pulse</span> <span className="print:text-black">{pattern.pulse.length ? pattern.pulse.join(', ') : '-'}</span>
                      </div>
                  </div>
              </div>
            </div>
          </>
        )}

        {/* Acupuncture Points */}
        <div className="mb-2 mt-4 pt-4 border-t border-slate-700/50 print:border-gray-300">
          <div className="flex items-center justify-between mb-3">
              <div className="flex flex-col">
                <p className="text-tcm-primary text-sm font-bold uppercase flex items-center gap-2 print:text-black">
                    <MapPin className="w-4 h-4"/> Titik Final Formula
                </p>
                <span className="text-[10px] text-slate-500 print:text-gray-500">
                    (Causal + Symptomatic + Location)
                </span>
              </div>
          </div>

          <div className="flex flex-wrap gap-2">
            {diagnosis.recommendedPoints.map((point) => {
              const isContra = isPregnant && TCM_DB.core_rules.pregnancy_contraindications?.includes(point);
              return (
                <div 
                  key={point} 
                  className={`px-3 py-1.5 rounded-lg text-sm font-bold flex items-center gap-1 transition-transform hover:scale-105 cursor-default shadow-md print:bg-white print:text-black print:border-black print:border ${
                    isContra 
                    ? 'bg-red-900/50 text-red-400 border border-red-500' 
                    : 'bg-gradient-to-b from-tcm-secondary/30 to-slate-800 text-tcm-primary border border-tcm-secondary'
                  }`}
                >
                  {point}
                  {isContra && <AlertTriangle className="w-3 h-3" />}
                </div>
              );
            })}
          </div>
          {isPregnant && diagnosis.recommendedPoints.some(p => TCM_DB.core_rules.pregnancy_contraindications?.includes(p)) && (
               <p className="text-red-400 text-xs mt-2 flex items-center gap-1 animate-pulse bg-red-900/20 p-2 rounded print:text-red-600 print:border-red-600 print:bg-white print:border">
                  <AlertTriangle className="w-3 h-3" /> Warning: Some points are contraindicated for pregnancy!
               </p>
          )}
        </div>

        {/* Herbal Recommendations */}
        {diagnosis.herbal_recommendation && (
          <div className="mt-4 pt-4 border-t border-slate-700/50 print:border-gray-300">
             <p className="text-tcm-primary text-sm font-bold uppercase flex items-center gap-2 mb-3 print:text-black">
                <Leaf className="w-4 h-4" /> Herbal Formula ({diagnosis.herbal_recommendation.formula_name || 'Custom'})
             </p>

             {/* Detailed Herb Info Modal/Card */}
             {showHerbInfo && (
               <div className="mb-4 bg-slate-800 border border-slate-600 rounded-lg p-3 text-xs animate-fade-in relative shadow-lg print:border-black print:bg-white">
                  <button onClick={() => setShowHerbInfo(null)} className="absolute top-2 right-2 text-slate-400 hover:text-white print:hidden"><X className="w-4 h-4"/></button>
                  {(() => {
                     const details = getHerbDetails(showHerbInfo);
                     if (!details) return null;
                     return (
                       <div className="print:text-black">
                          <h4 className="font-bold text-tcm-accent text-sm mb-1">{details.tcm_name}</h4>
                          <p className="italic text-slate-400 mb-2">{details.latin}</p>
                          <div className="grid grid-cols-2 gap-2 mb-2">
                             <div><span className="text-slate-500 font-semibold">Nature:</span> {details.nature}</div>
                             <div><span className="text-slate-500 font-semibold">Flavor:</span> {details.flavor}</div>
                          </div>
                          <div className="mb-2">
                             <span className="text-slate-500 font-semibold block">Channels:</span>
                             {details.channels ? details.channels.join(', ') : '-'}
                          </div>
                          <div className="mb-2">
                             <span className="text-slate-500 font-semibold block">Main Actions:</span>
                             <ul className="list-disc list-inside text-slate-300 print:text-black">
                               {details.main_actions.map((a: string, i: number) => <li key={i}>{a}</li>)}
                             </ul>
                          </div>
                          <div className="text-red-300 bg-red-900/20 p-2 rounded border border-red-900/30 print:text-black print:bg-gray-100 print:border-gray-300">
                             <span className="font-semibold block text-red-400 print:text-red-700">Contraindications / Avoid:</span>
                             {details.avoid_when.join(', ')}
                          </div>
                       </div>
                     );
                  })()}
               </div>
             )}

             <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 text-xs">
                <div className="bg-emerald-900/20 border border-emerald-500/30 p-2 rounded print:bg-white print:border-black">
                   <span className="text-emerald-400 font-bold block mb-1 uppercase text-[10px] print:text-black">Chief (Jun)</span>
                   <div className="text-slate-300 print:text-black">
                      {renderHerbList(diagnosis.herbal_recommendation.chief)}
                   </div>
                </div>

                {diagnosis.herbal_recommendation.assistants && diagnosis.herbal_recommendation.assistants.length > 0 && (
                   <div className="bg-slate-700/30 border border-slate-600/30 p-2 rounded print:bg-white print:border-black">
                      <span className="text-slate-400 font-bold block mb-1 uppercase text-[10px] print:text-black">Assistant (Chen/Zuo)</span>
                      <div className="text-slate-300 print:text-black">
                         {renderHerbList(diagnosis.herbal_recommendation.assistants)}
                      </div>
                   </div>
                )}

                {diagnosis.herbal_recommendation.avoid && diagnosis.herbal_recommendation.avoid.length > 0 && (
                   <div className="bg-rose-900/20 border border-rose-500/30 p-2 rounded col-span-1 sm:col-span-2 print:bg-white print:border-black">
                      <span className="text-rose-400 font-bold block mb-1 uppercase text-[10px] print:text-black">Avoid / Contraindicated</span>
                      <span className="text-slate-300 print:text-black">{diagnosis.herbal_recommendation.avoid.join(', ')}</span>
                   </div>
                )}
             </div>
          </div>
        )}

        {diagnosis.lifestyleAdvice && (
          <div className="mt-4 p-3 bg-indigo-900/20 rounded-lg text-xs text-slate-300 italic border border-indigo-900/30 flex gap-2 items-start print:bg-white print:text-black print:border-gray-300">
             <Info className="w-4 h-4 text-indigo-400 shrink-0 mt-0.5 print:text-black"/>
             <div>
               <span className="text-indigo-400 font-bold not-italic print:text-black">Saran Lifestyle: </span>
               {diagnosis.lifestyleAdvice}
             </div>
          </div>
        )}
      </div>
    </>
  );
};

export default DiagnosisCard;

