                    value={formData.symptoms}
                    onChange={e => setFormData({...formData, symptoms: e.target.value})}
                    placeholder="Describe all symptoms, duration, triggers..."
                />
            </div>

            <div className="border-t border-slate-700 pt-4">
              <h3 className="text-sm font-bold text-slate-300 mb-4 uppercase tracking-wider">Tongue Diagnosis</h3>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
                <div>
                  <label className="block text-xs text-slate-500 mb-1">Body Color</label>
                  <select 
                    className="w-full bg-slate-900 border border-slate-700 rounded-lg px-2 py-2 text-sm text-slate-200"
                    value={formData.tongue.body_color}
                    onChange={(e) => setFormData({...formData, tongue: {...formData.tongue, body_color: e.target.value}})}
                  >
                    <option value="">Select...</option>
                    {TONGUE_BODY_COLORS.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-xs text-slate-500 mb-1">Coating Color</label>
                  <select 
                    className="w-full bg-slate-900 border border-slate-700 rounded-lg px-2 py-2 text-sm text-slate-200"
                    value={formData.tongue.coating_color}
                    onChange={(e) => setFormData({...formData, tongue: {...formData.tongue, coating_color: e.target.value}})}
                  >
                    <option value="">Select...</option>
                    {TONGUE_COAT_COLORS.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-xs text-slate-500 mb-1">Coating Quality</label>
                  <select 
                    className="w-full bg-slate-900 border border-slate-700 rounded-lg px-2 py-2 text-sm text-slate-200"
                    value={formData.tongue.coating_quality}
                    onChange={(e) => setFormData({...formData, tongue: {...formData.tongue, coating_quality: e.target.value}})}
                  >
                    <option value="">Select...</option>
                    {TONGUE_COAT_QUALITIES.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
              </div>
              <div>
                <label className="block text-xs text-slate-500 mb-2">Special Features</label>
                <div className="flex flex-wrap gap-2">
                  {TONGUE_FEATURES.map(feature => (
                    <button
                      key={feature}
                      type="button"
                      onClick={() => toggleTongueFeature(feature)}
                      className={`px-3 py-1 rounded-full text-xs border transition-colors flex items-center gap-1 ${
                        formData.tongue.special_features.includes(feature)
                          ? 'bg-indigo-600 border-indigo-500 text-white'
                          : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500'
                      }`}
                    >
                      {feature}
                      {formData.tongue.special_features.includes(feature) && <Check className="w-3 h-3" />}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <div className="border-t border-slate-700 pt-4">
              <h3 className="text-sm font-bold text-slate-300 mb-4 uppercase tracking-wider">Pulse Diagnosis</h3>
              <div className="flex flex-wrap gap-2">
                {PULSE_QUALITIES.map(quality => (
                  <button
                    key={quality}
                    type="button"
                    onClick={() => togglePulseQuality(quality)}
                    className={`px-3 py-1 rounded-full text-xs border transition-colors flex items-center gap-1 ${
                      formData.pulse.qualities.includes(quality)
                        ? 'bg-emerald-600 border-emerald-500 text-white'
                        : 'bg-slate-900 border-slate-700 text-slate-400 hover:border-slate-500'
                    }`}
                  >
                    {quality}
                    {formData.pulse.qualities.includes(quality) && <Check className="w-3 h-3" />}
                  </button>
                ))}
              </div>
            </div>

            <div className="pt-4 flex justify-end gap-3">
                 <button 
                    type="button"
                    onClick={onClose}
                    className="px-4 py-2 rounded-lg text-slate-400 hover:text-white hover:bg-slate-700 transition-all text-sm"
                >
                    Cancel
                </button>
                <button 
                    type="submit"
                    className="flex items-center gap-2 bg-tcm-primary hover:bg-tcm-secondary text-white px-6 py-2 rounded-lg font-bold transition-all shadow-lg shadow-tcm-primary/20 text-sm"
                >
                    <Save className="w-4 h-4" /> Save & Analyze
                </button>
            </div>
        </form>
      </div>
    </div>
  );
};

