import React, { useState, useRef } from 'react';
import { TcmDiagnosisResult } from '../types';
import { TCM_DB } from '../constants';
import { db } from '../services/db';
import { AlertTriangle, Activity, Thermometer, Stethoscope, GitMerge, MapPin, BrainCircuit, Info, MoveUpRight, Split, RefreshCw, ShieldAlert, ArrowRight, Download, Printer, Leaf, X, Map, FileText, Layers, Target, FileDown, Zap, Save } from 'lucide-react';
import DoctorNoteModal from './DoctorNoteModal';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface Props {
  diagnosis: TcmDiagnosisResult;
  isPregnant: boolean;
  onShowVisualizer: (element?: string) => void;
  patientContext?: any; // To pass form data for saving
}

const DiagnosisCard: React.FC<Props> = ({ diagnosis, isPregnant, onShowVisualizer, patientContext }) => {
  const [showHerbInfo, setShowHerbInfo] = useState<string | null>(null);
  const [showNoteModal, setShowNoteModal] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const cardRef = useRef<HTMLDivElement>(null);

  const allSyndromes = [
    ...TCM_DB.syndromes.FILLED_FROM_PDF,
    ...TCM_DB.syndromes.TODO_FROM_PDF
  ];

  const pattern = allSyndromes.find(p => p.id === diagnosis.patternId);
  const patternName = pattern ? pattern.name_id : diagnosis.patternId.replace(/_/g, ' ');

  const isMultiOrgan = diagnosis.isMultiOrganInteraction || (diagnosis.wuxingRelationships && diagnosis.wuxingRelationships.length > 0);

  const handleSaveToArchive = () => {
    // If name is already in context, use it. Otherwise prompt.
    let patientName = patientContext?.patientName;
    if (!patientName) {
        patientName = prompt("Masukkan Nama Pasien (Opsional):") || "Anonim";
    }

    db.patients.add({
      id: Date.now().toString(),
      patientName: patientName,
      age: patientContext?.age || "?",
      sex: patientContext?.sex || "?",
      address: patientContext?.address || "",
      complaint: patientContext?.complaint || "Chat Diagnosis",
      symptoms: patientContext?.symptoms || "",
      tongue: patientContext?.tongue || {},
      pulse: patientContext?.pulse || { qualities: [] },
      diagnosis: diagnosis,
      timestamp: Date.now()
    });

    setIsSaved(true);
    alert(`Data diagnosis pasien "${patientName}" berhasil disimpan ke Arsip.`);
  };

  const handleVisualizerClick = () => {
    let elementToHighlight = diagnosis.wuxingElement?.toLowerCase();
    if (!elementToHighlight) {
        const text = (diagnosis.wuxingAnalysis || pattern?.wuxing_element || "").toLowerCase();
        if (text.includes('wood') || text.includes('liver') || text.includes('gall')) elementToHighlight = 'wood';
        else if (text.includes('fire') || text.includes('heart') || text.includes('small intestine') || text.includes('pericardium')) elementToHighlight = 'fire';
        else if (text.includes('earth') || text.includes('spleen') || text.includes('stomach')) elementToHighlight = 'earth';
        else if (text.includes('metal') || text.includes('lung') || text.includes('large intestine')) elementToHighlight = 'metal';
        else if (text.includes('water') || text.includes('kidney') || text.includes('bladder')) elementToHighlight = 'water';
    }
    onShowVisualizer(elementToHighlight);
  };

  const handleExportPDF = async () => {
    if (!cardRef.current) return;
    try {
      const canvas = await html2canvas(cardRef.current, {
        scale: 2,
        useCORS: true,
        backgroundColor: '#1e293b',
        logging: false
      });
      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pageWidth = pdf.internal.pageSize.getWidth();
      const imgProps = pdf.getImageProperties(imgData);
      const imgHeight = (imgProps.height * pageWidth) / imgProps.width;
      pdf.addImage(imgData, 'PNG', 0, 0, pageWidth, imgHeight);
      pdf.save(`TCM_Report_${patternName.replace(/\s+/g, '_')}_${new Date().toISOString().slice(0,10)}.pdf`);
    } catch (error) {
      console.error("PDF Export Error:", error);
      alert("Failed to export PDF.");
    }
  };

  const cycleBadge = (() => {
    const dynamic = diagnosis.wuxingDynamic?.toLowerCase();
    if (dynamic?.includes('overact') || dynamic?.includes('cheng')) return { label: 'Overacting (Cheng)', color: 'bg-red-900/40 text-red-300 border-red-700', icon: <AlertTriangle className="w-3 h-3"/> };
    if (dynamic?.includes('insult') || dynamic?.includes('wu')) return { label: 'Insulting (Wu)', color: 'bg-orange-900/40 text-orange-300 border-orange-700', icon: <ShieldAlert className="w-3 h-3"/> };
    if (dynamic?.includes('generat') || dynamic?.includes('sheng')) return { label: 'Generating (Sheng)', color: 'bg-emerald-900/40 text-emerald-300 border-emerald-700', icon: <RefreshCw className="w-3 h-3"/> };
    if (dynamic?.includes('control') || dynamic?.includes('ke')) return { label: 'Controlling (Ke)', color: 'bg-indigo-900/40 text-indigo-300 border-indigo-700', icon: <Activity className="w-3 h-3"/> };
    return null;
  })();

  const renderHerbList = (herbs: string[]) => (
    <div className="flex flex-wrap gap-2">
      {herbs.map((herb, idx) => (
        <span key={idx}>{herb}{idx < herbs.length - 1 ? ', ' : ''}</span>
      ))}
    </div>
  );

  return (
    <>
      <DoctorNoteModal 
        isOpen={showNoteModal} 
        onClose={() => setShowNoteModal(false)} 
        diagnosis={diagnosis} 
        initialPatientData={{
          name: patientContext?.patientName,
          age: patientContext?.age,
          address: patientContext?.address
        }}
      />

      <div ref={cardRef} className="bg-slate-800 border border-tcm-secondary/50 rounded-xl p-4 my-2 shadow-lg animate-fade-in print:bg-white print:text-black">
        <div className="flex items-center gap-2 mb-4 border-b border-slate-700 pb-2">
          <Activity className="w-5 h-5 text-tcm-primary" />
          <div className="flex flex-col flex-1">
            <h3 className="font-bold text-lg text-tcm-primary leading-tight">{patternName}</h3>
            {pattern?.name_en && <span className="text-xs text-slate-400 italic">{pattern.name_en}</span>}
          </div>

          <div className="flex items-center gap-2 print:hidden">
              <button 
                  onClick={handleSaveToArchive} 
                  disabled={isSaved}
                  className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-1 shadow-lg ${
                    isSaved ? 'bg-emerald-900 text-emerald-400 border border-emerald-800' : 'bg-indigo-600 hover:bg-indigo-500 text-white'
                  }`}
              >
                  <Save className="w-3 h-3" /> {isSaved ? 'Tersimpan' : 'Simpan'}
              </button>
              <button onClick={() => setShowNoteModal(true)} className="px-3 py-1.5 bg-slate-700 hover:bg-slate-600 text-white rounded-lg text-xs font-bold transition-colors flex items-center gap-1">
                  <FileText className="w-3 h-3" /> Nota
              </button>
              <button onClick={handleExportPDF} className="p-1.5 text-slate-400 hover:text-tcm-primary hover:bg-slate-700 rounded-lg transition-colors">
                  <FileDown className="w-4 h-4" />
              </button>
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mb-5">
           <div className="bg-slate-900/40 border border-slate-700 p-2.5 rounded-lg flex flex-col gap-1">
              <div className="flex items-center gap-1.5 text-[10px] font-bold text-slate-500 uppercase tracking-wider">
                 <Target className="w-3 h-3" /> Organs
              </div>
              <div className="text-xs font-semibold text-slate-200">
                 {pattern?.primary_organs?.join(', ') || diagnosis.patternId.split('_')[0] || '-'}
              </div>
           </div>
           <div className="bg-slate-900/40 border border-slate-700 p-2.5 rounded-lg flex flex-col gap-1">
              <div className="flex items-center gap-1.5 text-[10px] font-bold text-slate-500 uppercase tracking-wider">
                 <Layers className="w-3 h-3" /> Wu Xing
              </div>
              <div className="text-xs font-semibold text-tcm-primary">{diagnosis.wuxingElement || '-'}</div>
           </div>
           <div className="bg-slate-900/40 border border-slate-700 p-2.5 rounded-lg flex flex-col gap-1">
              <div className="flex items-center gap-1.5 text-[10px] font-bold text-slate-500 uppercase tracking-wider">
                 <Zap className="w-3 h-3" /> Dynamics
              </div>
              <div className="text-xs font-semibold text-amber-400 truncate">{diagnosis.wuxingDynamic || 'Balanced'}</div>
           </div>
        </div>

        {diagnosis.wuxingRelationships && diagnosis.wuxingRelationships.length > 0 && (
           <div className="mb-5 bg-indigo-900/20 border border-indigo-500/30 p-3 rounded-lg">
              <div className="flex items-center gap-2 mb-3 text-indigo-400 text-xs font-bold uppercase tracking-wider">
                 <GitMerge className="w-4 h-4" /> Zang-Fu Dynamic Interactions
              </div>
              <div className="space-y-2">
                 {diagnosis.wuxingRelationships.map((rel, i) => (
                    <div key={i} className="flex items-start gap-3 text-xs">
                       <div className="mt-0.5">
                          {rel.type === 'Generating' && <RefreshCw className="w-3.5 h-3.5 text-emerald-400" />}
                          {rel.type === 'Controlling' && <ShieldAlert className="w-3.5 h-3.5 text-blue-400" />}
                          {rel.type === 'Overacting' && <AlertTriangle className="w-3.5 h-3.5 text-red-400" />}
                          {rel.type === 'Insulting' && <MoveUpRight className="w-3.5 h-3.5 text-orange-400" />}
                       </div>
                       <div>
                          <span className="font-bold text-slate-100">{rel.type}: </span>
                          <span className="text-indigo-200">Impact on <span className="font-bold">{rel.targetElement}</span></span>
                          <p className="text-slate-400 mt-0.5 leading-relaxed">{rel.description}</p>
                       </div>
                    </div>
                 ))}
              </div>
           </div>
        )}

        <div className="bg-gradient-to-br from-slate-800 to-slate-700/60 border-l-4 border-tcm-accent rounded-r-lg p-4 mb-5 relative overflow-hidden">
           <div className="flex items-center gap-2 mb-3 text-tcm-accent text-sm font-bold uppercase tracking-wide relative z-10">
              <Stethoscope className="w-4 h-4" /> Clinical Analysis
           </div>
           {diagnosis.analysisDetail && (
              <div className="mb-4 flex flex-col sm:flex-row items-stretch gap-2 relative z-10">
                <div className="flex-1 bg-slate-900/60 p-3 rounded-lg border-l-2 border-emerald-500 flex flex-col justify-center">
                  <span className="text-[10px] uppercase text-emerald-400 font-bold block mb-1 tracking-wider">Root (Ben)</span>
                  <span className="text-xs text-slate-200 block font-medium leading-relaxed">{diagnosis.analysisDetail.root}</span>
                </div>
                <div className="flex-1 bg-slate-900/60 p-3 rounded-lg border-l-2 border-amber-500 flex flex-col justify-center">
                  <span className="text-[10px] uppercase text-amber-400 font-bold block mb-1 tracking-wider">Branch (Biao)</span>
                  <span className="text-xs text-slate-200 block font-medium leading-relaxed">{diagnosis.analysisDetail.branch}</span>
                </div>
              </div>
           )}
           <p className="text-slate-200 leading-relaxed text-sm whitespace-pre-line font-medium pl-1 relative z-10">{diagnosis.explanation}</p>
        </div>

        <div className="mb-4 bg-slate-900/30 p-3 rounded-lg border border-slate-700/50 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-3">
          <div className="flex-1">
            <p className="text-slate-400 text-xs uppercase font-semibold mb-2 flex items-center gap-1">
               <Activity className="w-3 h-3"/> Wu Xing Dynamics
            </p>
            <div className="text-sm text-slate-200 font-medium">
               <div className="flex items-center flex-wrap gap-2 mb-1">
                 {cycleBadge && (
                   <span className={`text-[10px] px-2 py-0.5 rounded border flex items-center gap-1 font-bold uppercase tracking-wide ${cycleBadge.color}`}>
                      {cycleBadge.icon} {cycleBadge.label}
                   </span>
                 )}
                 {diagnosis.wuxingElement && <span className="font-bold text-tcm-primary">{diagnosis.wuxingElement}</span>}
                 <span className="text-slate-400 border-l border-slate-600 pl-2 ml-1 text-xs">{diagnosis.wuxingAnalysis || pattern?.wuxing_element || "Not specified"}</span>
               </div>
            </div>
          </div>
          <button onClick={handleVisualizerClick} className="flex items-center gap-1 text-xs bg-slate-700 hover:bg-slate-600 text-slate-200 px-3 py-2 rounded-lg transition-colors border border-slate-600 print:hidden">
            Map <Map className="w-3 h-3" />
          </button>
        </div>

        <div className="mb-2 mt-4 pt-4 border-t border-slate-700/50">
          <p className="text-tcm-primary text-sm font-bold uppercase flex items-center gap-2 mb-3">
              <MapPin className="w-4 h-4"/> Titik Final Formula
          </p>
          <div className="flex flex-wrap gap-2">
            {diagnosis.recommendedPoints.map((point) => (
                <div key={point} className="px-3 py-1.5 rounded-lg text-sm font-bold bg-gradient-to-b from-tcm-secondary/30 to-slate-800 text-tcm-primary border border-tcm-secondary shadow-md">
                  {point}
                </div>
            ))}
          </div>
        </div>

        {diagnosis.herbal_recommendation && (
          <div className="mt-4 pt-4 border-t border-slate-700/50">
             <p className="text-tcm-primary text-sm font-bold uppercase flex items-center gap-2 mb-3">
                <Leaf className="w-4 h-4" /> Herbal Formula ({diagnosis.herbal_recommendation.formula_name || 'Custom'})
             </p>
             <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 text-xs">
                <div className="bg-emerald-900/20 border border-emerald-500/30 p-2 rounded">
                   <span className="text-emerald-400 font-bold block mb-1 uppercase text-[10px]">Chief (Jun)</span>
                   <div className="text-slate-300">{renderHerbList(diagnosis.herbal_recommendation.chief)}</div>
                </div>
                {diagnosis.herbal_recommendation.assistants && (
                   <div className="bg-slate-700/30 border border-slate-600/30 p-2 rounded">
                      <span className="text-slate-400 font-bold block mb-1 uppercase text-[10px]">Assistant</span>
                      <div className="text-slate-300">{renderHerbList(diagnosis.herbal_recommendation.assistants)}</div>
                   </div>
                )}
             </div>
          </div>
        )}
      </div>
    </>
  );
};

