import React, { useState, useEffect } from 'react';
import { db } from '../services/db';
import { SavedPatient } from '../types';
import { Search, Trash2, User, Calendar, FileText, ChevronRight, Activity, X, RotateCcw, BrainCircuit, MapPin } from 'lucide-react';

interface Props {
  onLoadPatient: (patient: SavedPatient) => void;
}

const PatientArchivePanel: React.FC<Props> = ({ onLoadPatient }) => {
