        )}

        {activePanel === 'ukom' && (
           <div className="flex-1 min-h-0 bg-slate-950">
             <UkomPracticePanel />
           </div>
        )}

        {activePanel === 'wuxing' && (
          <div className="flex-1 min-h-0 bg-slate-950 overflow-hidden">
             <WuXingMasterPanel 
                onSelectSyndrome={(id) => {
                  setLinkedSyndromeId(id);
                  setActivePanel('diagnosis');
                }}
                onShowMap={() => setIsVisualizerOpen(true)}
             />
          </div>
        )}

        {activePanel === 'theory' && (
          <div className="flex-1 min-h-0 bg-slate-950 overflow-hidden">
             <YinYangTheoryWindow />
          </div>
        )}

        {activePanel === 'atlas' && (
          <div className="flex-1 min-h-0 bg-slate-950 overflow-hidden">
             <SyndromeAtlasWindow 
                onSelectSyndrome={(id) => {
                  setLinkedSyndromeId(id);
                  setActivePanel('diagnosis');
                }}
             />
          </div>
        )}

        {activePanel === 'stroke' && (
          <div className="flex-1 min-h-0 bg-slate-950 overflow-hidden">
             <StrokeEducationPanel />
          </div>
        )}

      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Upload, User, Bot, Video, Mic, Menu, X, Baby, ClipboardList, Activity, MessageSquare, Stethoscope, LayoutDashboard, BookOpen, Map, Zap, Compass, LogOut, Users, Shield, GraduationCap, Archive } from 'lucide-react';
import { Language, ChatMessage, ScoredSyndrome, UserAccount, SavedPatient, TcmDiagnosisResult } from './types';
import { sendMessageToGemini } from './services/geminiService';
import { analyzePatient } from './services/tcmLogic';
import { db } from './services/db';
import DiagnosisCard from './components/DiagnosisCard';
import LanguageSelector from './components/LanguageSelector';
import PatientFormModal from './components/PatientFormModal';
import WuXingVisualizerModal from './components/WuXingVisualizerModal';
import ScoringAndPointsHub from './components/ScoringAndPointsHub';
import { YinYangTheoryWindow } from './components/YinYangTheoryWindow';
import StrokeEducationPanel from './components/StrokeEducationPanel';
import WuXingMasterPanel from './components/WuXingMasterPanel';
import { SyndromeAtlasWindow } from './components/SyndromeAtlasWindow';
import { TCM_DB } from './constants';
import LoginScreen from './components/LoginScreen';
import UserManagementModal from './components/UserManagementModal';
import UkomPracticePanel from './components/UkomPracticePanel';
import PatientArchivePanel from './components/PatientArchivePanel';

const App: React.FC = () => {
  // --- AUTHENTICATION STATE ---
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);

  const [activePanel, setActivePanel] = useState<'chat' | 'diagnosis' | 'theory' | 'stroke' | 'atlas' | 'wuxing' | 'ukom' | 'archive'>('chat');
  const [linkedSyndromeId, setLinkedSyndromeId] = useState<string | null>(null);

  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: 'Selamat datang di TCM WuXing Pro. Silakan isi form pasien (tombol papan klip) atau ceritakan keluhan Anda untuk diagnosis.',
      timestamp: new Date()
    }
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false); 
  const [selectedLanguage, setSelectedLanguage] = useState<Language>(Language.INDONESIAN);
  const [isPregnant, setIsPregnant] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isVisualizerOpen, setIsVisualizerOpen] = useState(false);
  const [isUserMgmtOpen, setIsUserMgmtOpen] = useState(false);
  const [visualizerHighlight, setVisualizerHighlight] = useState<string | null>(null);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [cdssResults, setCdssResults] = useState<ScoredSyndrome[]>([]);
  const [lastPatientForm, setLastPatientForm] = useState<any>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    if (activePanel === 'chat') {
        scrollToBottom();
    }
  }, [messages, activePanel]);

  const handleSendMessage = async (textOverride?: string, analysis?: ScoredSyndrome[]) => {
    const textToSend = textOverride || inputText;
    const imageToSend = textOverride ? undefined : (selectedImage || undefined);

    if ((!textToSend.trim() && !imageToSend) || isLoading) return;

    const userMessage: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend,
      image: imageToSend,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setSelectedImage(null);
    setIsLoading(true);

    try {
      const response = await sendMessageToGemini(textToSend, imageToSend, messages, selectedLanguage, isPregnant, analysis || cdssResults);

      const botMessage: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: response.conversationalResponse,
        timestamp: new Date(),
        tcmResult: response.diagnosis
      };

      setMessages(prev => [...prev, botMessage]);
    } catch (error) {
      const errorMessage: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Maaf, terjadi kesalahan koneksi atau analisis. Silakan coba lagi.",
        timestamp: new Date(),
        isError: true
      };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleFormSubmit = (data: any) => {
    setLastPatientForm(data);
    setIsAnalyzing(true);
    setActivePanel('diagnosis'); 

    setTimeout(() => {
        const results = analyzePatient({
            identity: {
                patient_name: data.patientName || "Anonymous",
                visit_date: new Date().toISOString(),
                address: data.address || "",
                age: data.age,
                sex: data.sex
            },
            chief_complaint: data.complaint,
            selected_symptoms: [], 
            body_region_selector: data.body_region_selector || [], 
            tongue: data.tongue,
            pulse: data.pulse,
            isAcuteMode: data.isAcuteMode
        } as any);

        setCdssResults(results);
        setIsAnalyzing(false);

        // --- AUTOMATICALLY SAVE TO LOCAL ARCHIVE ---
        if (results && results.length > 0) {
            const topResult = results[0];
            const diagnosisToSave: TcmDiagnosisResult = {
                patternId: topResult.syndrome.id,
                confidence: topResult.score / 100,
                explanation: topResult.rationale.join('; '),
                recommendedPoints: topResult.points.map(p => p.code),
                lifestyleAdvice: "Initial CDSS automated analysis saved to local database.",
                herbal_recommendation: topResult.herbal_recommendation,
                wuxingElement: topResult.syndrome.wuxing_element
            };

            const saved: SavedPatient = {
                id: crypto.randomUUID ? crypto.randomUUID() : Date.now().toString(),
                patientName: data.patientName || "Anonymous",
                age: data.age || "",
                sex: data.sex || "",
                address: data.address || "",
                complaint: data.complaint || "",
                symptoms: data.symptoms || "",
                tongue: data.tongue,
                pulse: data.pulse,
                diagnosis: diagnosisToSave,
                timestamp: Date.now(),
            };

            db.patients.add(saved);
        }

        const tongueDetails = [
          data.tongue.body_color ? `Body: ${data.tongue.body_color}` : '',
          data.tongue.coating_color ? `Coat Color: ${data.tongue.coating_color}` : '',
          data.tongue.coating_quality ? `Coat Quality: ${data.tongue.coating_quality}` : '',
          data.tongue.special_features.length ? `Features: ${data.tongue.special_features.join(', ')}` : ''
        ].filter(Boolean).join(' | ');

        const pulseDetails = data.pulse.qualities.length > 0 ? data.pulse.qualities.join(', ') : 'Not specified';

        // Anonymized intake note for AI Chat context
        const formattedMessage = `
**PATIENT INTAKE (ANONYMIZED)**
Name: ${data.patientName ? data.patientName.charAt(0) + '***' : 'Anonymous'}
Age: ${data.age}
Sex: ${data.sex}
Address: ${data.address ? 'Registered' : 'N/A'}
Complaint: ${data.complaint}
Acute Mode: ${data.isAcuteMode ? 'YES' : 'NO'}

Symptoms:
${data.symptoms}

Tongue: ${tongueDetails || 'Not specified'}
Pulse: ${pulseDetails}

Please analyze this case.
        `.trim();

        handleSendMessage(formattedMessage, results);
    }, 800); 
  };

  const handleLoadPatient = (savedPatient: SavedPatient) => {
    // 1. Reconstruct the form context
    const patientData = {
        patientName: savedPatient.patientName,
        age: savedPatient.age,
        sex: savedPatient.sex,
        address: savedPatient.address || "",
        complaint: savedPatient.complaint,
        symptoms: savedPatient.symptoms,
        tongue: savedPatient.tongue,
        pulse: savedPatient.pulse,
        isAcuteMode: savedPatient.diagnosis.isMultiOrganInteraction || false 
    };

    setLastPatientForm(patientData);

    setIsAnalyzing(true);
    setActivePanel('diagnosis');

    setTimeout(() => {
        const results = analyzePatient({
            identity: {
                patient_name: savedPatient.patientName,
                visit_date: new Date(savedPatient.timestamp).toISOString(),
                address: savedPatient.address || "",
                age: savedPatient.age,
                sex: savedPatient.sex
            },
            chief_complaint: savedPatient.complaint,
            selected_symptoms: [], 
            body_region_selector: [], 
            tongue: savedPatient.tongue,
            pulse: savedPatient.pulse,
            isAcuteMode: false
        } as any);

        setCdssResults(results);
        setIsAnalyzing(false);
    }, 500);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setMessages([{
      id: 'welcome',
      role: 'model',
      text: 'Selamat datang di TCM WuXing Pro. Silakan isi form pasien (tombol papan klip) atau ceritakan keluhan Anda untuk diagnosis.',
      timestamp: new Date()
    }]);
  };

  if (!currentUser) {
    return <LoginScreen onLoginSuccess={(user) => setCurrentUser(user)} />;
  }

  return (
    <div className="flex h-screen bg-slate-950 text-slate-100 font-sans overflow-hidden print:h-auto print:overflow-visible print:bg-white print:text-black print:block">
      <PatientFormModal isOpen={isFormOpen} onClose={() => setIsFormOpen(false)} onSubmit={handleFormSubmit} />
      <WuXingVisualizerModal 
        isOpen={isVisualizerOpen} 
        onClose={() => setIsVisualizerOpen(false)} 
        initialHighlight={visualizerHighlight}
      />
      {currentUser.role === 'admin' && (
        <UserManagementModal 
          isOpen={isUserMgmtOpen} 
          onClose={() => setIsUserMgmtOpen(false)} 
          currentUser={currentUser}
        />
      )}

      {/* SIDEBAR NAVIGATION */}
      <div className={`fixed inset-y-0 left-0 z-40 w-64 bg-slate-900 border-r border-slate-800 transform transition-transform duration-300 ease-in-out ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 flex flex-col print:hidden`}>
        <div className="p-5">
           <h1 className="text-xl font-black bg-gradient-to-r from-tcm-primary to-tcm-accent bg-clip-text text-transparent flex items-center gap-2">
              <Activity className="w-6 h-6 text-tcm-primary" />
              TCM WuXing
           </h1>
           <p className="text-[10px] text-slate-500 mt-1 uppercase tracking-widest font-semibold flex items-center gap-1">
             <Shield className="w-3 h-3 text-emerald-500" /> {currentUser.role === 'admin' ? 'Admin Access' : 'Pro License'}
           </p>
        </div>

        <div className="flex-1 px-3 space-y-2 overflow-y-auto">
           <div className="space-y-1 mb-6">
              <button
                type="button"
                onClick={() => { setActivePanel('chat'); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                   activePanel === 'chat' 
                   ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/20' 
                   : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                 <MessageSquare className="w-4 h-4" />
                 Chat / Input Cepat
              </button>

              <button
                type="button"
                onClick={() => { setActivePanel('diagnosis'); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                   activePanel === 'diagnosis' 
                   ? 'bg-tcm-primary text-white shadow-lg shadow-emerald-900/20' 
                   : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                 <Stethoscope className="w-4 h-4" />
                 Diagnosis & Auto-Rx
              </button>

              <button
                type="button"
                onClick={() => { setActivePanel('archive'); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                   activePanel === 'archive' 
                   ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/20' 
                   : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                 <Archive className="w-4 h-4" />
                 Arsip Pasien
              </button>

              <button
                type="button"
                onClick={() => { setActivePanel('wuxing'); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                   activePanel === 'wuxing' 
                   ? 'bg-pink-600 text-white shadow-lg shadow-pink-900/20' 
                   : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                 <Compass className="w-4 h-4" />
                 Wu Xing Master
              </button>

              <button
                type="button"
                onClick={() => { setActivePanel('ukom'); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                   activePanel === 'ukom' 
                   ? 'bg-sky-600 text-white shadow-lg shadow-sky-900/20' 
                   : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                 <GraduationCap className="w-4 h-4" />
                 Latihan UKOM
              </button>

              <button
                type="button"
                onClick={() => { setActivePanel('theory'); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                   activePanel === 'theory' 
                   ? 'bg-violet-600 text-white shadow-lg shadow-violet-900/20' 
                   : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                 <BookOpen className="w-4 h-4" />
                 Theory & Syndromes
              </button>

              <button
                type="button"
                onClick={() => { setActivePanel('atlas'); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                   activePanel === 'atlas' 
                   ? 'bg-cyan-600 text-white shadow-lg shadow-cyan-900/20' 
                   : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                 <Map className="w-4 h-4" />
                 Syndrome Atlas
              </button>

              <button
                type="button"
                onClick={() => { setActivePanel('stroke'); setIsSidebarOpen(false); }}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                   activePanel === 'stroke' 
                   ? 'bg-amber-600 text-white shadow-lg shadow-amber-900/20' 
                   : 'text-slate-400 hover:bg-slate-800 hover:text-slate-200'
                }`}
              >
                 <Zap className="w-4 h-4" />
                 Stroke Management
              </button>
           </div>

           <hr className="border-slate-800 mb-4 mx-2" />

           <div className="space-y-3">
              <div className="bg-slate-800/50 rounded-xl p-3 border border-slate-700/50">
                <label className="flex items-center cursor-pointer justify-between">
                  <div className="flex items-center gap-2">
                    <Baby className={`w-4 h-4 ${isPregnant ? 'text-pink-400' : 'text-slate-500'}`} />
                    <span className="text-sm font-medium text-slate-300">Pregnancy Mode</span>
                  </div>
                  <div className="relative">
                    <input type="checkbox" className="sr-only" checked={isPregnant} onChange={(e) => setIsPregnant(e.target.checked)} />
                    <div className={`block w-9 h-5 rounded-full transition-colors ${isPregnant ? 'bg-pink-500' : 'bg-slate-600'}`}></div>
                    <div className={`absolute left-1 top-1 bg-white w-3 h-3 rounded-full transition-transform ${isPregnant ? 'transform translate-x-4' : ''}`}></div>
                  </div>
                </label>
              </div>

              <div>
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wider mb-2 px-1">Language</label>
                <LanguageSelector selected={selectedLanguage} onChange={setSelectedLanguage} />
              </div>
           </div>
        </div>

        <div className="p-3 pb-8 border-t border-slate-800 space-y-2 bg-slate-900">
           {currentUser.role === 'admin' && (
             <button 
               type="button"
               onClick={() => setIsUserMgmtOpen(true)}
               className="w-full flex items-center justify-start gap-3 px-3 py-2 text-indigo-400 hover:text-white hover:bg-indigo-900/30 rounded-lg text-sm transition-colors border border-transparent hover:border-indigo-500/30 cursor-pointer"
             >
                <Users className="w-4 h-4" /> Manage Users
             </button>
           )}

           <button 
             type="button"
             onClick={handleLogout}
             className="w-full flex items-center justify-start gap-3 px-3 py-2 text-slate-400 hover:text-rose-400 hover:bg-rose-900/10 rounded-lg text-sm transition-colors cursor-pointer"
           >
              <LogOut className="w-4 h-4" /> Logout ({currentUser.username})
           </button>

           <div className="pt-2">
             <button 
               type="button"
               onClick={() => setIsFormOpen(true)}
               className="w-full flex items-center justify-center gap-2 py-3 bg-slate-800 hover:bg-slate-700 text-tcm-primary rounded-xl font-bold text-sm transition-colors border border-slate-700 hover:border-tcm-primary cursor-pointer"
             >
                <ClipboardList className="w-4 h-4" /> New Patient
             </button>
           </div>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col h-full relative overflow-hidden bg-slate-950 print:h-auto print:overflow-visible print:bg-white print:text-black print:block">

        <div className="md:hidden flex items-center justify-between p-4 bg-slate-900 border-b border-slate-800 shrink-0 print:hidden">
          <button onClick={() => setIsSidebarOpen(true)} className="text-slate-300">
            <Menu className="w-6 h-6" />
          </button>
          <span className="font-bold text-tcm-primary">TCM WuXing Pro</span>
          <div className="w-6"></div> 
        </div>

        {activePanel === 'chat' && (
           <div className="flex-1 flex flex-col min-h-0 print:h-auto print:overflow-visible print:block">
              <div className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-hide print:h-auto print:overflow-visible print:block">
                {messages.map((msg) => (
                  <div key={msg.id} className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`flex max-w-[90%] md:max-w-[80%] gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                      <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 shadow-lg ${msg.role === 'user' ? 'bg-indigo-500' : 'bg-tcm-primary'} print:hidden`}>
                        {msg.role === 'user' ? <User className="w-5 h-5 text-white" /> : <Bot className="w-5 h-5 text-white" />}
                      </div>
                      <div className="flex flex-col gap-1 w-full min-w-0">
                        <div className={`p-4 rounded-2xl text-sm leading-relaxed whitespace-pre-wrap shadow-md ${
                          msg.role === 'user' 
                          ? 'bg-indigo-600 text-white rounded-tr-none print:bg-gray-100 print:text-black print:border print:border-gray-300' 
                          : 'bg-slate-800 text-slate-200 border border-slate-700 rounded-tl-none print:bg-white print:text-black print:border-gray-300'
                        }`}>
                          {msg.text}
                          {msg.image && (
                            <div className="mt-3 rounded-lg overflow-hidden border border-white/20 print:border-gray-300">
                              <img src={msg.image} alt="User upload" className="max-w-full h-auto max-h-64 object-cover" />
                            </div>
                          )}
                        </div>
                        {msg.tcmResult && (
                          <DiagnosisCard 
                            diagnosis={msg.tcmResult} 
                            isPregnant={isPregnant} 
                            onShowVisualizer={(element) => {
                                setVisualizerHighlight(element || null);
                                setIsVisualizerOpen(true);
                            }}
                            patientContext={lastPatientForm}
                          />
                        )}
                        <span className={`text-[10px] text-slate-500 ${msg.role === 'user' ? 'text-right' : 'text-left'} print:text-gray-400`}>
                          {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        </span>
                      </div>
                    </div>
                  </div>
                ))}
                {isLoading && (
                  <div className="flex justify-start w-full animate-fade-in print:hidden">
                    <div className="flex items-center gap-2 bg-slate-800 p-3 rounded-2xl rounded-tl-none border border-slate-700 ml-11 shadow-sm">
                      <div className="flex gap-1">
                        <div className="w-1.5 h-1.5 bg-tcm-primary rounded-full animate-bounce" style={{ animationDelay: '0s' }}></div>
                        <div className="w-1.5 h-1.5 bg-tcm-primary rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                        <div className="w-1.5 h-1.5 bg-tcm-primary rounded-full animate-bounce" style={{ animationDelay: '0.4s' }}></div>
                      </div>
                      <span className="text-xs text-slate-400 font-medium">Analyzing patterns...</span>
                    </div>
                  </div>
                )}
                <div ref={messagesEndRef} />
              </div>

              <div className="p-4 bg-slate-900 border-t border-slate-800 shrink-0 z-10 print:hidden">
                <div className="max-w-4xl mx-auto flex items-end gap-2 relative">
                  <div className="flex-1 bg-slate-950 rounded-2xl border border-slate-800 focus-within:border-tcm-primary focus-within:ring-1 focus-within:ring-tcm-primary transition-all flex items-end shadow-inner">
                    <textarea
                      value={inputText}
                      onChange={(e) => setInputText(e.target.value)}
                      placeholder={`Type symptoms (${selectedLanguage.split(' ')[0]})...`}
                      className="w-full bg-transparent border-none text-slate-200 placeholder-slate-600 text-sm p-3 max-h-32 focus:ring-0 resize-none scrollbar-hide leading-relaxed"
                      rows={1}
                      style={{ minHeight: '46px' }}
                    />
                  </div>
                  <button
                    onClick={() => handleSendMessage()}
                    disabled={isLoading || (!inputText.trim() && !selectedImage)}
                    className="p-3 bg-tcm-primary hover:bg-tcm-secondary text-white rounded-full transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-tcm-primary/20"
                  >
                    <Send className="w-5 h-5" />
                  </button>
                </div>
              </div>
           </div>
        )}

        {activePanel === 'diagnosis' && (
           <div className="flex-1 min-h-0 bg-slate-950 print:h-auto print:overflow-visible print:bg-white print:text-black print:block">
             <ScoringAndPointsHub 
                analysis={cdssResults} 
                onAnalyzeRequest={() => setIsFormOpen(true)}
                initialSyndromeId={linkedSyndromeId ?? undefined}
                isAnalyzing={isAnalyzing}
                onBack={() => setActivePanel('atlas')}
                patientContext={lastPatientForm}
             />
           </div>
        )}

        {activePanel === 'archive' && (
           <div className="flex-1 min-h-0 bg-slate-950">
             <PatientArchivePanel onLoadPatient={handleLoadPatient} />
           </div>
        )}

        {activePanel === 'ukom' && (
           <div className="flex-1 min-h-0 bg-slate-950">
             <UkomPracticePanel />
           </div>
        )}

        {activePanel === 'wuxing' && (
          <div className="flex-1 min-h-0 bg-slate-950 overflow-hidden">
             <WuXingMasterPanel 
                onSelectSyndrome={(id) => {
                  setLinkedSyndromeId(id);
                  setActivePanel('diagnosis');
                }}
                onShowMap={() => setIsVisualizerOpen(true)}
             />
          </div>
        )}

        {activePanel === 'theory' && (
          <div className="flex-1 min-h-0 bg-slate-950 overflow-hidden">
             <YinYangTheoryWindow />
          </div>
        )}

        {activePanel === 'atlas' && (
          <div className="flex-1 min-h-0 bg-slate-950 overflow-hidden">
             <SyndromeAtlasWindow 
                onSelectSyndrome={(id) => {
                  setLinkedSyndromeId(id);
                  setActivePanel('diagnosis');
                }}
             />
          </div>
        )}

        {activePanel === 'stroke' && (
          <div className="flex-1 min-h-0 bg-slate-950 overflow-hidden">
             <StrokeEducationPanel />
          </div>
        )}

      </div>
    </div>
  );
};

export default App;

