                       <button key={q} type="button" onClick={() => togglePulseQuality(q)} 
                               className={`px-2 py-0.5 rounded text-[10px] border transition ${formData.pulse.qualities.includes(q) ? 'bg-emerald-600 border-emerald-400 text-white' : 'bg-slate-800 border-slate-700 text-slate-500'}`}>
