      id: 'welcome',
      role: 'model',
      text: 'Selamat datang di TCM WuXing Pro. Silakan isi form pasien (tombol papan klip) atau ceritakan keluhan Anda untuk diagnosis.',
      timestamp: new Date()
    }]);
  };

