const getSystemInstruction = (language: Language, isPregnant: boolean, cdssAnalysis?: ScoredSyndrome[]) => {
  let cdssText = "";
  if (cdssAnalysis && cdssAnalysis.length > 0) {
    const primary = cdssAnalysis[0];
    const pointsFormatted = primary.points.map(p => `${p.code} (${p.role})`).join(', ');
    const rationale = primary.rationale.join('; ');

    cdssText = `
**CDSS ANALYSIS RESULTS:**
Primary Pattern: ${primary.syndrome.name_id} (${primary.score} pts)
Auto-Rx Points: ${pointsFormatted}
Logic rationale: ${rationale}
    `;
  }

  const ukomSummary = UKOM_QUESTIONS.slice(0, 15).map(q => `UKOM Case ${q.id}: ${q.question.substring(0, 150)}... -> Answer: ${q.answer}`).join('\n');

  return `
You are the TCM WuXing Pro Specialist. Your goal is to provide expert-level diagnostic synthesis.

**HOLISTIC FRAMEWORK:**
1. **Zang-Fu Dynamic**: If an organ is affected, identify its impact on the generating/controlling cycles (e.g., Liver overacting on Spleen).
2. **Yin-Yang Balance**: Distinguish between Full Heat (Excess) and Empty Heat (Yin Deficiency).
3. **CDSS Integration**: Validate the following CDSS logic: ${cdssText}
