${ukomSummary}

**OUTPUT REQUIREMENTS:**
- Respond in **${language}**.
- Detail the **Root (Ben)** and **Branch (Biao)**.
- Explain organ interactions clearly.
- Suggest "Titik Final" using the Kausal + Simptom formula.
`;
};

export const sendMessageToGemini = async (
  message: string,
  image: string | undefined,
  history: any[],
  language: Language,
  isPregnant: boolean,
  cdssAnalysis?: ScoredSyndrome[]
) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const parts: any[] = [{ text: message }];
    if (image) {
        const [mimeTypePrefix, base64Data] = image.split(';base64,');
        const mimeType = mimeTypePrefix.split(':')[1];
        parts.push({ inlineData: { mimeType: mimeType, data: base64Data } });
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { role: 'user', parts },
      config: {
        systemInstruction: getSystemInstruction(language, isPregnant, cdssAnalysis),
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            conversationalResponse: { type: Type.STRING },
            diagnosis: {
              type: Type.OBJECT,
              nullable: true,
              properties: {
                patternId: { type: Type.STRING },
                confidence: { type: Type.NUMBER },
                wuxingDynamic: { type: Type.STRING },
                explanation: { type: Type.STRING },
                recommendedPoints: { type: Type.ARRAY, items: { type: Type.STRING } },
                analysisDetail: {
                  type: Type.OBJECT,
                  properties: {
                    root: { type: Type.STRING },
                    branch: { type: Type.STRING }
                  }
                },
                wuxingRelationships: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      type: { type: Type.STRING },
                      targetElement: { type: Type.STRING },
                      description: { type: Type.STRING }
                    }
                  }
                }
              }
            }
          }
        }
      }
    });

    if (response.text) return JSON.parse(response.text);
    throw new Error("Empty response");
  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

