// === FUZZY MATCHING HELPERS ===
export const normalize = (s: string) => 
  (s || "").toLowerCase().replace(/[^\p{L}\p{N}\s]/gu, " ").replace(/\s+/g, " ").trim();

const similarityRatio = (a: string, b: string): number => {
  const normA = normalize(a);
  const normB = normalize(b);
  if (normA === normB) return 1.0;
  if (normA.length === 0 || normB.length === 0) return 0.0;

  // Simple token based similarity for better performance and relevance
  const setA = new Set(normA.split(/\s+/));
  const setB = new Set(normB.split(/\s+/));
  const intersection = new Set([...setA].filter(x => setB.has(x)));
  return intersection.size / Math.max(setA.size, setB.size);
};

export const fuzzyMatch = (a: string, b: string, threshold = 0.75): boolean => {
  const normA = normalize(a);
  const normB = normalize(b);
  if (normA.includes(normB) || normB.includes(normA)) return true;
  return similarityRatio(a, b) >= threshold;
};

const expandWithSynonyms = (base: string[]): Set<string> => {
  const out = new Set<string>();
  const synonymMap = TCM_DB.clinical_config.matching.synonym_map;

  base.forEach(s => {
    const key = normalize(s);
    if (!key) return;
    out.add(key);

    if (synonymMap[key]) {
      synonymMap[key].forEach(syn => out.add(normalize(syn)));
    }

    Object.entries(synonymMap).forEach(([k, values]) => {
      if (values.map(normalize).includes(key)) {
        out.add(normalize(k));
        values.forEach(v => out.add(normalize(v)));
      }
    });
  });
  return out;
};

const hasStrongIndicator = (selExpanded: Set<string>, indicators: string[]): boolean => {
  for (const ind of indicators) {
    for (const sel of selExpanded) {
      if (fuzzyMatch(sel, ind)) return true;
    }
  }
  return false;
};

const extractSymptoms = (text: string): string[] => {
    return text.split(/[\n,.]+/).map(normalize).filter(s => s.length > 2);
};

// === PATHOLOGY DETECTION ===

interface PathologicalSigns {
  HEAT: boolean;
  COLD: boolean;
  DAMP_PHLEGM: boolean;
  STASIS: boolean;
  YIN_DEF: boolean;
  YANG_DEF: boolean;
  BLOOD_DEF: boolean;
  QI_DEF: boolean;
  QI_STAG: boolean;
  YANG_RISING: boolean;
  ORGANS_IMPLICATED: Set<string>;
}

const detectPathologyFromSigns = (
  tongue: PatientFormSchema['tongue'],
  pulse: PatientFormSchema['pulse']
): PathologicalSigns => {
  const signs: PathologicalSigns = {
    HEAT: false,
    COLD: false,
    DAMP_PHLEGM: false,
    STASIS: false,
    YIN_DEF: false,
    YANG_DEF: false,
    BLOOD_DEF: false,
    QI_DEF: false,
    QI_STAG: false,
    YANG_RISING: false,
    ORGANS_IMPLICATED: new Set<string>()
  };

  const tBody = normalize(tongue.body_color);
  const tCoat = normalize(tongue.coating_color);
  const tQual = normalize(tongue.coating_quality);
  const tFeat = tongue.special_features.map(normalize);
  const pQuals = pulse.qualities.map(normalize);

  // --- HEAT ---
  if (tBody.includes('red') || tBody.includes('purple')) signs.HEAT = true;
  if (tCoat.includes('yellow')) signs.HEAT = true;
  if (pQuals.some(q => q.includes('rapid') || q.includes('surging'))) signs.HEAT = true;

  // --- COLD ---
  if (tBody.includes('pale') || tBody.includes('blue')) signs.COLD = true;
  if (tCoat.includes('white') && !tCoat.includes('yellow')) signs.COLD = true;
  if (pQuals.some(q => q.includes('slow') || q.includes('tight'))) signs.COLD = true;

  // --- DAMP/PHLEGM ---
  if (tFeat.some(f => f.includes('swollen') || f.includes('teeth mark'))) signs.DAMP_PHLEGM = true;
  if (tQual.includes('greasy') || tQual.includes('sticky') || tQual.includes('thick')) signs.DAMP_PHLEGM = true;
  if (pQuals.some(q => q.includes('slippery') || q.includes('soggy'))) signs.DAMP_PHLEGM = true;

  // --- STASIS ---
  if (tBody.includes('purple') || tFeat.some(f => f.includes('spot') || f.includes('stasis'))) signs.STASIS = true;
  if (pQuals.some(q => q.includes('choppy'))) signs.STASIS = true;

  // --- QI STAGNATION / LIVER YANG RISING ---
  if (pQuals.some(q => q.includes('wiry'))) {
      signs.QI_STAG = true;
      if (signs.HEAT) signs.YANG_RISING = true;
  }

  // --- DEFICIENCIES ---
  if (tBody.includes('red') && (tQual.includes('none') || tQual.includes('peeling') || tFeat.some(f => f.includes('crack')))) signs.YIN_DEF = true;
  if (tBody.includes('pale') && tQual.includes('wet')) signs.YANG_DEF = true;
  if (tBody.includes('pale') && !tQual.includes('wet')) signs.BLOOD_DEF = true;
  if (tFeat.some(f => f.includes('teeth mark')) && tBody.includes('pale')) signs.QI_DEF = true;

  // --- ORGAN AFFINITY ---
  if (tFeat.some(f => f.includes('tip') && (f.includes('red') || f.includes('prickle')))) signs.ORGANS_IMPLICATED.add('Heart');
  if (tFeat.some(f => f.includes('side') && (f.includes('red') || f.includes('swollen')))) {
      signs.ORGANS_IMPLICATED.add('Liver');
      signs.ORGANS_IMPLICATED.add('Gall Bladder');
  }
  if (tQual.includes('center') || tFeat.some(f => f.includes('center'))) {
      signs.ORGANS_IMPLICATED.add('Spleen');
      signs.ORGANS_IMPLICATED.add('Stomach');
  }
  if (pQuals.some(q => q.includes('deep'))) signs.ORGANS_IMPLICATED.add('Kidney');

  return signs;
};

// === SCORING LOGIC ===
export const scoreSyndrome = (
  syn: Syndrome, 
  selExpanded: Set<string>, 
  tongue: PatientFormSchema['tongue'], 
  pulse: PatientFormSchema['pulse'], 
  regions: string[],
  pathology: PathologicalSigns
): number => {
  let score = 0;
  const weights = TCM_DB.clinical_config.scoring.weights;
  const pType = normalize(syn.pattern_type);

  // 1. Key Symptoms (Strict Match)
  (syn.key_symptoms || []).forEach(ks => {
    if (Array.from(selExpanded).some(sel => fuzzyMatch(sel, ks))) {
        score += weights.key_symptom_match;
    }
  });

  // 2. Clinical Manifestations (General Match)
  (syn.clinical_manifestations || []).forEach(m => {
    if (Array.from(selExpanded).some(sel => fuzzyMatch(sel, m, 0.8))) {
        score += weights.manifestation_match;
    }
  });

  // 3. High-Value Multipliers
  Object.entries(SYMPTOM_WEIGHTS).forEach(([key, val]) => {
      if (Array.from(selExpanded).some(sel => fuzzyMatch(sel, key))) {
          if (val.element && syn.wuxing_element.includes(val.element)) score += val.weight;
          if (val.type && pType.includes(val.type)) score += (val.weight * 1.5);
      }
  });

  // 4. Pathological Sign Alignment
  if (pathology.HEAT && (pType.includes('heat') || pType.includes('fire'))) score += 10;
  if (pathology.COLD && pType.includes('cold')) score += 10;
  if (pathology.DAMP_PHLEGM && (pType.includes('damp') || pType.includes('phlegm'))) score += 8;
  if (pathology.STASIS && (pType.includes('stasis') || pType.includes('blood'))) score += 8;
  if (pathology.YIN_DEF && (pType.includes('yin deficiency') || pType.includes('empty heat'))) score += 12;
  if (pathology.YANG_DEF && (pType.includes('yang deficiency') || pType.includes('empty cold'))) score += 12;
  if (pathology.QI_DEF && pType.includes('qi deficiency')) score += 8;
  if (pathology.BLOOD_DEF && pType.includes('blood deficiency')) score += 8;

  // 5. Zang-Fu Interactions (Generating/Controlling logic)
  const synOrgans = syn.primary_organs || [];
  synOrgans.forEach(org => {
      if (pathology.ORGANS_IMPLICATED.has(org)) score += 15;
  });

  // Wood overacting on Earth logic
  if (synOrgans.includes('Liver') && (pathology.ORGANS_IMPLICATED.has('Spleen') || pathology.ORGANS_IMPLICATED.has('Stomach'))) {
      if (pType.includes('stagnation') || pType.includes('fire')) score += 5;
  }

  // 6. Regional Bonus
  const regionMap = TCM_DB.clinical_config.diagnosis_engine.region_organ_map || {};
  regions.forEach(r => {
      const organs = regionMap[normalize(r)];
      if (organs && organs.some(o => synOrgans.includes(o))) score += weights.organ_region_bonus;
  });

  return score;
};

// === AUTO PRESCRIPTION ENGINE ===

function organToChannelCodes(organs: string[]) {
  const map: Record<string, string[]> = {
    Lung: ["LU"], "Large Intestine": ["LI"], Heart: ["HT"], "Small Intestine": ["SI"],
    Spleen: ["SP"], Stomach: ["ST"], Kidney: ["KI"], Bladder: ["BL"],
    Liver: ["LR"], "Gall Bladder": ["GB"], Pericardium: ["PC"], "San Jiao": ["TE"]
  };
  const out: string[] = [];
  organs.forEach(o => (map[o] || []).forEach(c => out.push(c)));
  return [...new Set(out)];
}

export function buildAutoPrescription(DB: any, input: AutoRxInput): { points: RxPoint[], warnings: string[], rationale: string[] } {
  const syn = input.syndrome;
  const points: RxPoint[] = [];
  const rationale: string[] = [];
  const warnings: string[] = [];

  const channels = organToChannelCodes(syn.primary_organs || []);
  const tables = DB.special_point_tables;

  // 1. Kausal (Root) from Database
  const kausal = Array.isArray(syn.acupuncture_points) ? syn.acupuncture_points : (syn.acupuncture_points?.kausal || []);
  kausal.forEach((code: string) => points.push({ code, role: "kausal", source: "syndrome" }));

  // 2. Yuan-Luo Pairing (Advanced)
  channels.forEach(ch => {
      const yuan = tables.yuan_source_points[ch];
      const paired = getPairedChannel(ch);
      const luo = tables.luo_connecting_points.yin_channels[paired] || tables.luo_connecting_points.yang_channels[paired];

      if (yuan) points.push({ code: yuan, role: "yuan_source", source: "auto:yuan_luo", note: `Yuan-Source of ${ch}` });
      if (luo) points.push({ code: luo, role: "luo_paired", source: "auto:yuan_luo", note: `Luo-Connecting of paired ${paired}` });
  });

  // 3. Mu-Shu Pairing (Organ level)
  channels.forEach(ch => {
      const mu = tables.front_mu_points[ch];
      const shu = tables.back_shu_points[ch];
      if (mu) points.push({ code: mu, role: "front_mu", source: "auto:mu_shu" });
      if (shu) points.push({ code: shu, role: "back_shu", source: "auto:mu_shu" });
  });

  // 4. Pathogen Clearing
  const text = normalize(input.selectedSymptoms.join(' ') + ' ' + input.tongue?.join(' '));
  if (text.includes('angin') || text.includes('wind')) tables.pathogen_cause_points.wind.forEach((c:string) => points.push({ code: c, role: "pathogen", source: "auto:pathogen" }));
  if (text.includes('dingin') || text.includes('cold')) tables.pathogen_cause_points.cold.forEach((c:string) => points.push({ code: c, role: "pathogen", source: "auto:pathogen" }));
  if (text.includes('panas') || text.includes('heat')) tables.pathogen_cause_points.heat.forEach((c:string) => points.push({ code: c, role: "pathogen", source: "auto:pathogen" }));
  if (text.includes('dahak') || text.includes('phlegm')) tables.pathogen_cause_points.phlegm.forEach((c:string) => points.push({ code: c, role: "pathogen", source: "auto:pathogen" }));

  // 5. Deduplicate and Finalize
  const seen = new Set<string>();
  const finalPoints = points.filter(p => {
      if (seen.has(p.code)) return false;
      seen.add(p.code);
      return true;
  });

  return { points: finalPoints, warnings, rationale: ["Applied Yuan-Luo and Mu-Shu point pairing logic."] };
}

function getPairedChannel(ch: string): string {
    const pairs: Record<string, string> = {
        LU: "LI", LI: "LU", ST: "SP", SP: "ST", HT: "SI", SI: "HT",
        BL: "KI", KI: "BL", PC: "TE", TE: "PC", GB: "LR", LR: "GB"
    };
    return pairs[ch] || ch;
}

/**
 * Resolves herbal recommendation based on pattern type and overrides
 */
export const getHerbalRecommendation = (syndrome: Syndrome) => {
  const guidelines = TCM_DB.herbal_guidelines;
  const patternType = syndrome.pattern_type;

  // 1. Check if there's a specific override for this syndrome ID
  const overrides = guidelines.per_syndrome_overrides_for_current_DB_snippet;
  if (overrides && overrides[syndrome.id]) {
    const rule = overrides[syndrome.id];
    return {
      formula_name: rule.notes || "Custom Formula",
      chief: rule.suggest_chief || rule.suggest_chief_herbs || [],
      assistants: rule.suggest_assistants || [],
      avoid: rule.avoid || []
    };
  }

  // 2. Check general rules by pattern type
  const patternRules = guidelines.herbal_rules_by_pattern_type;
  if (patternRules && patternRules[patternType]) {
    const rule = patternRules[patternType];
    return {
      formula_name: "Standard Pattern Prescription",
      chief: rule.suggest_chief || rule.suggest_chief_herbs || [],
      assistants: rule.suggest_assistants || [],
      avoid: rule.avoid || []
    };
  }

  return undefined;
};

// === MAIN ANALYZER ===
export const analyzePatient = (data: PatientFormSchema): ScoredSyndrome[] => {
    const allSyndromes = [...TCM_DB.syndromes.FILLED_FROM_PDF, ...TCM_DB.syndromes.TODO_FROM_PDF];
    const symptomsList = [...(data.selected_symptoms || []), ...extractSymptoms((data as any).symptoms || "")];
    const selExpanded = expandWithSynonyms(symptomsList);
    const pathology = detectPathologyFromSigns(data.tongue, data.pulse);

    const scored = allSyndromes.map(syn => ({
        syndrome: syn,
        score: scoreSyndrome(syn, selExpanded, data.tongue, data.pulse, data.body_region_selector, pathology)
    }));

    return scored
        .filter(s => s.score > 10)
        .sort((a, b) => b.score - a.score)
        .slice(0, 3)
        .map(s => {
            const autoRx = buildAutoPrescription(TCM_DB, {
                syndrome: s.syndrome,
                selectedSymptoms: symptomsList,
                tongue: Object.values(data.tongue).flat() as string[],
                pulse: data.pulse.qualities,
                bodyRegion: data.body_region_selector
            });
            return {
                ...s,
                points: autoRx.points,
                warnings: autoRx.warnings,
                rationale: autoRx.rationale,
                herbal_recommendation: getHerbalRecommendation(s.syndrome)
            };
        });
};

