// === CONSTANTS FOR SEMANTIC ANALYSIS ===
const SEVERITY_HIGH = ["sangat", "hebat", "parah", "severe", "intense", "extreme", "berlebihan", "tajam", "sharp"];
const DURATION_CHRONIC = ["lama", "kronis", "chronic", "bertahun", "berbulan", "long-term", "persistent", "hilang timbul"];
const DURATION_ACUTE = ["mendadak", "baru", "akut", "sudden", "recent", "acute", "just started", "tiba-tiba"];

// === FUZZY MATCHING HELPERS ===
export const normalize = (s: string) => 
  (s || "").toLowerCase().replace(/[^\p{L}\p{N}\s]/gu, " ").replace(/\s+/g, " ").trim();

const similarityRatio = (a: string, b: string): number => {
  const normA = normalize(a);
  const normB = normalize(b);
  if (normA === normB) return 1.0;
  if (normA.length === 0 || normB.length === 0) return 0.0;

  const setA = new Set(normA.split(/\s+/));
  const setB = new Set(normB.split(/\s+/));
  const intersection = new Set([...setA].filter(x => setB.has(x)));
  return intersection.size / Math.max(setA.size, setB.size);
};

export const fuzzyMatch = (a: string, b: string, threshold = 0.75): boolean => {
  const normA = normalize(a);
  const normB = normalize(b);
  if (normA.includes(normB) || normB.includes(normA)) return true;
  return similarityRatio(a, b) >= threshold;
};

const expandWithSynonyms = (base: string[]): Set<string> => {
  const out = new Set<string>();
  const synonymMap = TCM_DB.clinical_config.matching.synonym_map;

  base.forEach(s => {
    const key = normalize(s);
    if (!key) return;
    out.add(key);
    if (synonymMap[key]) {
      synonymMap[key].forEach(syn => out.add(normalize(syn)));
    }
  });
  return out;
};

const extractSymptoms = (text: string): string[] => {
    return text.split(/[\n,.]+/).map(normalize).filter(s => s.length > 2);
};

// === PATHOLOGY DETECTION ===

interface PathologicalSigns {
  HEAT: boolean;
  COLD: boolean;
  DAMP_PHLEGM: boolean;
  STASIS: boolean;
  YIN_DEF: boolean;
  YANG_DEF: boolean;
  BLOOD_DEF: boolean;
  QI_DEF: boolean;
  QI_STAG: boolean;
  YANG_RISING: boolean;
  ORGANS_IMPLICATED: Set<string>;
}

const detectPathologyFromSigns = (
  tongue: PatientFormSchema['tongue'],
  pulse: PatientFormSchema['pulse']
): PathologicalSigns => {
  const signs: PathologicalSigns = {
    HEAT: false, COLD: false, DAMP_PHLEGM: false, STASIS: false,
    YIN_DEF: false, YANG_DEF: false, BLOOD_DEF: false, QI_DEF: false,
    QI_STAG: false, YANG_RISING: false,
    ORGANS_IMPLICATED: new Set<string>()
  };

  const tBody = normalize(tongue.body_color);
  const tCoat = normalize(tongue.coating_color);
  const tQual = normalize(tongue.coating_quality);
  const tFeat = (tongue.special_features || []).map(normalize);
  const pQuals = (pulse.qualities || []).map(normalize);

  // --- THERMAL DYNAMICS ---
  if (tBody.includes('red') || tBody.includes('purple')) signs.HEAT = true;
  if (tCoat.includes('yellow')) signs.HEAT = true;
  if (pQuals.some(q => q.includes('rapid') || q.includes('surging'))) signs.HEAT = true;

  if (tBody.includes('pale') || tBody.includes('blue')) signs.COLD = true;
  if (tCoat.includes('white') && !tCoat.includes('yellow')) signs.COLD = true;
  if (pQuals.some(q => q.includes('slow') || q.includes('tight'))) signs.COLD = true;

  // --- SUBSTANCE DYNAMICS (Dahak/Lembap/Phlegm) ---
  if (tFeat.some(f => f.includes('swollen') || f.includes('teeth mark') || f.includes('bengkak'))) signs.DAMP_PHLEGM = true;
  if (tQual.includes('greasy') || tQual.includes('sticky') || tQual.includes('thick') || tQual.includes('lengket') || tQual.includes('berminyak')) signs.DAMP_PHLEGM = true;
  if (pQuals.some(q => q.includes('slippery') || q.includes('soggy') || q.includes('licin'))) signs.DAMP_PHLEGM = true;

  if (tBody.includes('purple') || tFeat.some(f => f.includes('spot') || f.includes('stasis'))) signs.STASIS = true;
  if (pQuals.some(q => q.includes('choppy'))) signs.STASIS = true;

  if (pQuals.some(q => q.includes('wiry'))) {
      signs.QI_STAG = true;
      if (signs.HEAT) signs.YANG_RISING = true;
  }

  // --- DEFICIENCIES ---
  if (tBody.includes('red') && (tQual.includes('none') || tQual.includes('peeling') || tFeat.some(f => f.includes('crack')))) signs.YIN_DEF = true;
  if (tBody.includes('pale') && tQual.includes('wet')) signs.YANG_DEF = true;
  if (tBody.includes('pale') && !tQual.includes('wet')) signs.BLOOD_DEF = true;
  if (tFeat.some(f => f.includes('teeth mark')) && tBody.includes('pale')) signs.QI_DEF = true;

  // --- ORGAN MAPPING ---
  if (tFeat.some(f => f.includes('tip') && (f.includes('red') || f.includes('prickle')))) signs.ORGANS_IMPLICATED.add('Heart');
  if (tFeat.some(f => f.includes('side') && (f.includes('red') || f.includes('swollen')))) {
      signs.ORGANS_IMPLICATED.add('Liver');
      signs.ORGANS_IMPLICATED.add('Gall Bladder');
  }
  if (tQual.includes('center') || tFeat.some(f => f.includes('center'))) {
      signs.ORGANS_IMPLICATED.add('Spleen');
      signs.ORGANS_IMPLICATED.add('Stomach');
  }
  if (pQuals.some(q => q.includes('deep'))) signs.ORGANS_IMPLICATED.add('Kidney');

  return signs;
};

