import { TCM_DB } from '../constants';
import { Syndrome, PatientFormSchema, RxPoint, ScoredSyndrome } from '../types';

export interface AutoRxInput {
  syndrome: Syndrome;
  selectedSymptoms: string[];
  tongue?: string[];
  pulse?: string[];
  bodyRegion?: string[];
  isPregnant?: boolean;
}

// === CONSTANTS FOR SEMANTIC ANALYSIS ===
const SEVERITY_HIGH = ["sangat", "hebat", "parah", "severe", "intense", "extreme", "berlebihan", "tajam", "sharp"];
const DURATION_CHRONIC = ["lama", "kronis", "chronic", "bertahun", "berbulan", "long-term", "persistent", "hilang timbul"];
const DURATION_ACUTE = ["mendadak", "baru", "akut", "sudden", "recent", "acute", "just started", "tiba-tiba"];

// === FUZZY MATCHING HELPERS ===
export const normalize = (s: string) => 
  (s || "").toLowerCase().replace(/[^\p{L}\p{N}\s]/gu, " ").replace(/\s+/g, " ").trim();

const similarityRatio = (a: string, b: string): number => {
  const normA = normalize(a);
  const normB = normalize(b);
  if (normA === normB) return 1.0;
  if (normA.length === 0 || normB.length === 0) return 0.0;

  const setA = new Set(normA.split(/\s+/));
  const setB = new Set(normB.split(/\s+/));
  const intersection = new Set([...setA].filter(x => setB.has(x)));
  return intersection.size / Math.max(setA.size, setB.size);
};

export const fuzzyMatch = (a: string, b: string, threshold = 0.75): boolean => {
  const normA = normalize(a);
  const normB = normalize(b);
  if (normA.includes(normB) || normB.includes(normA)) return true;
  return similarityRatio(a, b) >= threshold;
};

const expandWithSynonyms = (base: string[]): Set<string> => {
  const out = new Set<string>();
  const synonymMap = TCM_DB.clinical_config.matching.synonym_map;

  base.forEach(s => {
    const key = normalize(s);
    if (!key) return;
    out.add(key);
    if (synonymMap[key]) {
      synonymMap[key].forEach(syn => out.add(normalize(syn)));
    }
  });
  return out;
};

const extractSymptoms = (text: string): string[] => {
    return text.split(/[\n,.]+/).map(normalize).filter(s => s.length > 2);
};

// === PATHOLOGY DETECTION ===

interface PathologicalSigns {
  HEAT: boolean;
  COLD: boolean;
  DAMP_PHLEGM: boolean;
  STASIS: boolean;
  YIN_DEF: boolean;
  YANG_DEF: boolean;
  BLOOD_DEF: boolean;
  QI_DEF: boolean;
  QI_STAG: boolean;
  YANG_RISING: boolean;
  ORGANS_IMPLICATED: Set<string>;
}

const detectPathologyFromSigns = (
  tongue: PatientFormSchema['tongue'],
  pulse: PatientFormSchema['pulse']
): PathologicalSigns => {
  const signs: PathologicalSigns = {
    HEAT: false, COLD: false, DAMP_PHLEGM: false, STASIS: false,
    YIN_DEF: false, YANG_DEF: false, BLOOD_DEF: false, QI_DEF: false,
    QI_STAG: false, YANG_RISING: false,
    ORGANS_IMPLICATED: new Set<string>()
  };

  const tBody = normalize(tongue.body_color);
  const tCoat = normalize(tongue.coating_color);
  const tQual = normalize(tongue.coating_quality);
  const tFeat = (tongue.special_features || []).map(normalize);
  const pQuals = (pulse.qualities || []).map(normalize);

  // --- THERMAL DYNAMICS ---
  if (tBody.includes('red') || tBody.includes('purple')) signs.HEAT = true;
  if (tCoat.includes('yellow')) signs.HEAT = true;
  if (pQuals.some(q => q.includes('rapid') || q.includes('surging'))) signs.HEAT = true;

  if (tBody.includes('pale') || tBody.includes('blue')) signs.COLD = true;
  if (tCoat.includes('white') && !tCoat.includes('yellow')) signs.COLD = true;
  if (pQuals.some(q => q.includes('slow') || q.includes('tight'))) signs.COLD = true;

  // --- SUBSTANCE DYNAMICS (Dahak/Lembap/Phlegm) ---
  if (tFeat.some(f => f.includes('swollen') || f.includes('teeth mark') || f.includes('bengkak'))) signs.DAMP_PHLEGM = true;
  if (tQual.includes('greasy') || tQual.includes('sticky') || tQual.includes('thick') || tQual.includes('lengket') || tQual.includes('berminyak')) signs.DAMP_PHLEGM = true;
  if (pQuals.some(q => q.includes('slippery') || q.includes('soggy') || q.includes('licin'))) signs.DAMP_PHLEGM = true;

  if (tBody.includes('purple') || tFeat.some(f => f.includes('spot') || f.includes('stasis'))) signs.STASIS = true;
  if (pQuals.some(q => q.includes('choppy'))) signs.STASIS = true;

  if (pQuals.some(q => q.includes('wiry'))) {
      signs.QI_STAG = true;
      if (signs.HEAT) signs.YANG_RISING = true;
  }

  // --- DEFICIENCIES ---
  if (tBody.includes('red') && (tQual.includes('none') || tQual.includes('peeling') || tFeat.some(f => f.includes('crack')))) signs.YIN_DEF = true;
  if (tBody.includes('pale') && tQual.includes('wet')) signs.YANG_DEF = true;
  if (tBody.includes('pale') && !tQual.includes('wet')) signs.BLOOD_DEF = true;
  if (tFeat.some(f => f.includes('teeth mark')) && tBody.includes('pale')) signs.QI_DEF = true;

  // --- ORGAN MAPPING ---
  if (tFeat.some(f => f.includes('tip') && (f.includes('red') || f.includes('prickle')))) signs.ORGANS_IMPLICATED.add('Heart');
  if (tFeat.some(f => f.includes('side') && (f.includes('red') || f.includes('swollen')))) {
      signs.ORGANS_IMPLICATED.add('Liver');
      signs.ORGANS_IMPLICATED.add('Gall Bladder');
  }
  if (tQual.includes('center') || tFeat.some(f => f.includes('center'))) {
      signs.ORGANS_IMPLICATED.add('Spleen');
      signs.ORGANS_IMPLICATED.add('Stomach');
  }
  if (pQuals.some(q => q.includes('deep'))) signs.ORGANS_IMPLICATED.add('Kidney');

  return signs;
};

// === SCORING LOGIC ===
export const scoreSyndrome = (
  syn: Syndrome, 
  selExpanded: Set<string>, 
  pathology: PathologicalSigns,
  modifiers: { isHighSeverity: boolean, isChronic: boolean, isAcute: boolean },
  regions: string[]
): number => {
  let score = 0;
  const weights = TCM_DB.clinical_config.scoring.weights;
  const pType = normalize(syn.pattern_type);

  // 1. Key Symptoms (High Weight)
  (syn.key_symptoms || []).forEach(ks => {
    if (Array.from(selExpanded).some(sel => fuzzyMatch(sel, ks))) {
        score += weights.key_symptom_match;
        if (modifiers.isHighSeverity) score += 5; // Severity boost
    }
  });

  // 2. Clinical Manifestations (Breadth)
  (syn.clinical_manifestations || []).forEach(m => {
    if (Array.from(selExpanded).some(sel => fuzzyMatch(sel, m, 0.8))) {
        score += weights.manifestation_match;
    }
  });

  // 3. Polarizing by Duration
  if (modifiers.isChronic && (pType.includes('deficiency') || pType.includes('empty'))) score += 15;
  if (modifiers.isAcute && (pType.includes('excess') || pType.includes('full') || pType.includes('invasion'))) score += 15;

  // 4. Pathological Sign Alignment (Lidah & Nadi)
  if (pathology.HEAT && (pType.includes('heat') || pType.includes('fire'))) score += 15;
  if (pathology.COLD && pType.includes('cold')) score += 15;
  if (pathology.DAMP_PHLEGM && (pType.includes('damp') || pType.includes('phlegm'))) score += 12;
  if (pathology.YIN_DEF && (pType.includes('yin deficiency') || pType.includes('empty heat'))) score += 18;
  if (pathology.YANG_DEF && (pType.includes('yang deficiency') || pType.includes('empty cold'))) score += 18;

  // 5. Zang-Fu Dynamics & Element Interactions
  const synOrgans = syn.primary_organs || [];
  synOrgans.forEach(org => {
      if (pathology.ORGANS_IMPLICATED.has(org)) score += 20;
  });

  return score;
};

// === AUTO PRESCRIPTION ENGINE ===

function organToChannelCodes(organs: string[]) {
  const map: Record<string, string[]> = {
    Lung: ["LU"], "Large Intestine": ["LI"], Heart: ["HT"], "Small Intestine": ["SI"],
    Spleen: ["SP"], Stomach: ["ST"], Kidney: ["KI"], Bladder: ["BL"],
    Liver: ["LR"], "Gall Bladder": ["GB"], Pericardium: ["PC"], "San Jiao": ["TE"]
  };
  const out: string[] = [];
  organs.forEach(o => (map[o] || []).forEach(c => out.push(c)));
  return [...new Set(out)];
}

export function buildAutoPrescription(DB: any, input: AutoRxInput): { points: RxPoint[], warnings: string[], rationale: string[] } {
  const syn = input.syndrome;
  const points: RxPoint[] = [];
  const rationale: string[] = [];
  const warnings: string[] = [];

  const channels = organToChannelCodes(syn.primary_organs || []);
  const tables = DB.special_point_tables;

  // 1. Root Points (Kausal)
  const kausal = Array.isArray(syn.acupuncture_points) ? syn.acupuncture_points : (syn.acupuncture_points?.kausal || []);
  kausal.forEach((code: string) => points.push({ code, role: "kausal", source: "syndrome" }));

  // 2. Yuan-Luo Dynamic Pairing
  channels.forEach(ch => {
      const yuan = tables.yuan_source_points[ch];
      if (yuan) points.push({ code: yuan, role: "yuan_source", source: "auto:logic", note: `Yuan of ${ch}` });
  });

  // 3. Pathogen Specific Logic (DETEKSI DAHAK/PHLEGM - PERBAIKAN ST40)
  const allText = normalize(
    input.selectedSymptoms.join(' ') + ' ' + 
    (input.tongue || []).join(' ') + ' ' + 
    (syn.name_en || '') + ' ' + 
    (syn.name_id || '') + ' ' +
    (syn.pattern_type || '')
  );

  const signs = detectPathologyFromSigns({
    body_color: input.tongue?.[0] || '',
    coating_color: input.tongue?.[1] || '',
    coating_quality: input.tongue?.[2] || '',
    special_features: []
  }, { qualities: input.pulse || [] });

  // DETEKSI DAHAK (PHLEGM) SECARA KOMPREHENSIF
  const isPhlegmDetected = 
    allText.includes('dahak') || 
    allText.includes('phlegm') || 
    allText.includes('lendir') || 
    allText.includes('greasy') || 
    allText.includes('lengket') || 
    allText.includes('sticky') ||
    allText.includes('licin') ||
    allText.includes('slippery') ||
    allText.includes('thick') ||
    allText.includes('tebal') ||
    signs.DAMP_PHLEGM || 
    (syn.pattern_type || '').includes('phlegm');

  if (isPhlegmDetected) {
    // ST40 adalah titik empiris terpenting untuk transformasi dahak (Fenglong)
    // Kita paksa masuk ke urutan atas jika belum ada
    if (!points.some(p => p.code === "ST40")) {
        points.unshift({ 
            code: "ST40", 
            role: "resolve_phlegm", 
            source: "auto_essential_priority", 
            note: "Fenglong: Titik utama transformasi dahak internal & eksternal." 
        });
    }

    // RN12 membantu Spleen dalam mengolah kelembapan (asal muasal dahak)
    if (!points.some(p => p.code === "RN12")) {
        points.push({ 
            code: "RN12", 
            role: "resolve_phlegm", 
            source: "auto_essential", 
            note: "Membantu transformasi Spleen (akar dahak)." 
        });
    }

    rationale.push("Tanda Dahak/Lembap terdeteksi: ST40 (Fenglong) disertakan sebagai titik prioritas wajib untuk transformasi patogen.");
  }

  // Detect WIND
  if (allText.includes('angin') || allText.includes('wind')) {
    (tables.pathogen_cause_points.wind || []).forEach((c:string) => {
        if (!points.some(p => p.code === c)) points.push({ code: c, role: "expel_wind", source: "auto" });
    });
  }

  // Detect HEAT
  if (allText.includes('panas') || allText.includes('heat') || allText.includes('fire') || signs.HEAT) {
     (tables.pathogen_cause_points.heat || []).forEach((c:string) => {
         if (!points.some(p => p.code === c)) points.push({ code: c, role: "clear_heat", source: "auto" });
     });
  }

  // 4. Deduplicate and Finalize
  const seen = new Set<string>();
  const finalPoints = points.filter(p => {
      const cleanCode = p.code.split(' ')[0].toUpperCase();
      if (seen.has(cleanCode)) return false;
      seen.add(cleanCode);
      return true;
  });

  return { 
    points: finalPoints, 
    warnings, 
    rationale: rationale.length > 0 ? rationale : ["Applied pattern-based auto-point selection."] 
  };
}

export const getHerbalRecommendation = (syndrome: Syndrome) => {
  const guidelines = TCM_DB.herbal_guidelines;
  const overrides = guidelines.per_syndrome_overrides_for_current_DB_snippet;
  if (overrides && overrides[syndrome.id]) {
    const rule = overrides[syndrome.id];
    return {
      formula_name: rule.notes || "Custom Formula",
      chief: rule.suggest_chief || rule.suggest_chief_herbs || [],
      assistants: rule.suggest_assistants || [],
      avoid: rule.avoid || []
    };
  }
  const patternRules = guidelines.herbal_rules_by_pattern_type;
  if (patternRules && patternRules[syndrome.pattern_type]) {
    const rule = patternRules[syndrome.pattern_type];
    return {
      formula_name: "Standard Pattern Prescription",
      chief: rule.suggest_chief || rule.suggest_chief_herbs || [],
      assistants: rule.suggest_assistants || [],
      avoid: rule.avoid || []
    };
  }
  return undefined;
};

// === MAIN ANALYZER ===
export const analyzePatient = (data: PatientFormSchema): ScoredSyndrome[] => {
    const allSyndromes = [...TCM_DB.syndromes.FILLED_FROM_PDF, ...TCM_DB.syndromes.TODO_FROM_PDF];
    const rawSymptoms = (data as any).symptoms || "";
    const symptomsList = [...(data.selected_symptoms || []), ...extractSymptoms(rawSymptoms)];
    const selExpanded = expandWithSynonyms(symptomsList);

    // Severity and Duration Analysis
    const allText = normalize(data.chief_complaint + " " + rawSymptoms);
    const modifiers = {
        isHighSeverity: SEVERITY_HIGH.some(k => allText.includes(k)),
        isChronic: DURATION_CHRONIC.some(k => allText.includes(k)),
        isAcute: DURATION_ACUTE.some(k => allText.includes(k)) || !!data.isAcuteMode,
    };

    const pathology = detectPathologyFromSigns(data.tongue, data.pulse);

    const scored = allSyndromes.map(syn => ({
        syndrome: syn,
        score: scoreSyndrome(syn, selExpanded, pathology, modifiers, data.body_region_selector)
    }));

    return scored
        .filter(s => s.score > 15)
        .sort((a, b) => b.score - a.score)
        .slice(0, 3)
        .map(s => {
            const autoRx = buildAutoPrescription(TCM_DB, {
                syndrome: s.syndrome,
                selectedSymptoms: symptomsList,
                tongue: [data.tongue.body_color, data.tongue.coating_color, data.tongue.coating_quality],
                pulse: data.pulse.qualities,
                bodyRegion: data.body_region_selector
            });
            return {
                ...s,
                points: autoRx.points,
                warnings: autoRx.warnings,
                rationale: [
                    ...autoRx.rationale,
                    modifiers.isHighSeverity ? "High severity detected (+Score)" : "",
                    modifiers.isChronic ? "Chronic status suggests root deficiency focus" : "",
                    modifiers.isAcute ? "Acute status suggests pathogen excess focus" : ""
                ].filter(Boolean),
                herbal_recommendation: getHerbalRecommendation(s.syndrome)
            };
        });
};

import React, { useState, useEffect, useRef } from 'react';
import { ScoredSyndrome, RxPoint, TcmDiagnosisResult } from '../types';
import { TCM_DB } from '../constants';
import { getHerbalRecommendation } from '../services/tcmLogic';
import { Activity, CheckCircle, MapPin, ArrowRight, BrainCircuit, Printer, Leaf, Loader2, ArrowLeft, Plus, Trash2, Syringe, X, FileText, Camera, Virus } from 'lucide-react';
import BodyMapSekarangJadi from './BodyMapSekarangJadi'; 
import DoctorNoteModal from './DoctorNoteModal';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

// Helper function
const renderHerbList = (herbs: string[] | undefined) => (herbs || []).map((h, i) => <div key={i}>{h}</div>);

interface Props {
  analysis: ScoredSyndrome[];
  onAnalyzeRequest: () => void;
  initialSyndromeId?: string;
  isAnalyzing?: boolean;
  onBack?: () => void;
}

const ScoringAndPointsHub: React.FC<Props> = ({ analysis, onAnalyzeRequest, initialSyndromeId, isAnalyzing = false, onBack }) => {
  const [selectedSyndrome, setSelectedSyndrome] = useState<ScoredSyndrome | null>(null);
  const [manualPoints, setManualPoints] = useState<RxPoint[]>([]);
  const [manualInput, setManualInput] = useState('');
  const [showNoteModal, setShowNoteModal] = useState(false);

  const contentRef = useRef<HTMLDivElement>(null);

  // Load initial syndrome from Atlas/Link
  useEffect(() => {
    if (initialSyndromeId) {
        const allSyndromes = [...TCM_DB.syndromes.FILLED_FROM_PDF, ...TCM_DB.syndromes.TODO_FROM_PDF];
        const found = allSyndromes.find(s => s.id === initialSyndromeId);

        if (found) {
            const existingInAnalysis = analysis.find(a => a.syndrome.id === initialSyndromeId);
            if (existingInAnalysis) {
                setSelectedSyndrome(existingInAnalysis);
            } else {
                // Not in analysis, mock a result for display
                let mockPoints: RxPoint[] = [];
                if (Array.isArray(found.acupuncture_points)) {
                     mockPoints = found.acupuncture_points.map(code => ({ code, role: 'kausal', source: 'manual' }));
                } else if (found.acupuncture_points && typeof found.acupuncture_points === 'object') {
                     const pts = found.acupuncture_points as any; 
                     if (pts.kausal) mockPoints = [...mockPoints, ...pts.kausal.map((c:string) => ({ code: c, role: 'kausal', source: 'manual' }))];
                     if (pts.simptomatik) mockPoints = [...mockPoints, ...pts.simptomatik.map((c:string) => ({ code: c, role: 'simptom', source: 'manual' }))];
                }

                setSelectedSyndrome({
                    syndrome: found,
                    score: 0, 
                    points: mockPoints,
                    warnings: [],
                    rationale: ["Manual selection from Atlas"],
                    herbal_recommendation: getHerbalRecommendation(found),
                });
            }
        }
    }
  }, [initialSyndromeId, analysis]);

  // Reset manual points when syndrome selection changes
  useEffect(() => {
    setManualPoints([]);
  }, [selectedSyndrome?.syndrome.id]);

  const sortedAnalysis = [...analysis].sort((a, b) => b.score - a.score);

  // Fallback to top score if nothing is selected
  useEffect(() => {
    if (!selectedSyndrome && sortedAnalysis.length > 0) {
        setSelectedSyndrome(sortedAnalysis[0]);
    }
  }, [sortedAnalysis]);


  // Helper for printing/snapshot
  const handleSnapshot = async () => {
    if (!contentRef.current) return;
    try {
        const canvas = await html2canvas(contentRef.current, {
            scale: 2,
            useCORS: true,
            backgroundColor: '#1e293b' // Keep slate-800 background
        });
        const imgData = canvas.toDataURL('image/png');
        const pdf = new jsPDF('l', 'mm', 'a4');
        const pdfW = pdf.internal.pageSize.getWidth();

        const imgProps = pdf.getImageProperties(imgData);
        const imgH = (imgProps.height * pdfW) / imgProps.width;

        pdf.addImage(imgData, 'PNG', 0, 0, pdfW, imgH);
        pdf.save(`CDSS_Snapshot_${selectedSyndrome?.syndrome.name_id || 'Analysis'}.pdf`);
    } catch(e) {
        console.error("Snapshot failed", e);
        alert("Gagal membuat snapshot PDF.");
    }
  };

  const handleAddManualPoint = (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!manualInput.trim()) return;

    const code = manualInput.toUpperCase().trim();

    // Check duplication
    const existsInSystem = selectedSyndrome?.points.some(p => p.code === code);
    const existsInManual = manualPoints.some(p => p.code === code);

    if (!existsInSystem && !existsInManual) {
        const newPoint: RxPoint = {
            code: code,
            role: 'manual',
            source: 'user_add',
            note: 'Ditambahkan manual'
        };
        setManualPoints([...manualPoints, newPoint]);
    }
    setManualInput('');
  };

  const removeManualPoint = (code: string) => {
      setManualPoints(manualPoints.filter(p => p.code !== code));
  };

  // Combine system points + manual points for visualization
  const activePoints = selectedSyndrome 
    ? [...(selectedSyndrome.points || []), ...manualPoints] 
    : [];

  // Convert to TcmDiagnosisResult for the modal
  const diagnosisForModal: TcmDiagnosisResult | null = selectedSyndrome ? {
      patternId: selectedSyndrome.syndrome.id,
      confidence: selectedSyndrome.score / 100,
      explanation: selectedSyndrome.rationale.join('\n\n'),
      recommendedPoints: activePoints.map(p => p.code),
      lifestyleAdvice: "Disarankan istirahat cukup, hindari faktor patogen (Angin/Dingin/Lembap), dan jaga pola makan sesuai sindrom.",
      herbal_recommendation: selectedSyndrome.herbal_recommendation,
      safetyWarnings: selectedSyndrome.warnings,
      isMultiOrganInteraction: false,
      wuxingElement: selectedSyndrome.syndrome.wuxing_element
  } : null;

  return (
    <div className="flex h-full p-4 gap-4 print:p-0 print:gap-0 print:block">
      {diagnosisForModal && (
          <DoctorNoteModal 
            isOpen={showNoteModal} 
            onClose={() => setShowNoteModal(false)} 
            diagnosis={diagnosisForModal}
          />
      )}

      {/* Kolom Kiri: Daftar Sindrom & Scoring */}
      <div className="w-1/3 min-h-full max-h-full overflow-y-auto bg-slate-900 rounded-xl p-3 shadow-lg print:hidden flex flex-col">
        {onBack && (
            <button 
                onClick={onBack}
                className="flex items-center gap-2 text-slate-400 hover:text-white mb-4 text-xs font-semibold uppercase tracking-wider transition-colors px-1"
            >
                <ArrowLeft className="w-4 h-4" /> Back to Syndrome Atlas
