import { ScoredSyndrome, RxPoint, TcmDiagnosisResult } from '../types';
import { TCM_DB } from '../constants';
import { getHerbalRecommendation } from '../services/tcmLogic';
import { Activity, CheckCircle, MapPin, ArrowRight, BrainCircuit, Printer, Leaf, Loader2, ArrowLeft, Plus, Trash2, Syringe, X, FileText, Camera, Stethoscope } from 'lucide-react';
import BodyMapSekarangJadi from './BodyMapSekarangJadi'; 
import DoctorNoteModal from './DoctorNoteModal';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

// Helper function
const renderHerbList = (herbs: string[] | undefined) => (herbs || []).map((h, i) => <div key={i}>{h}</div>);

interface Props {
  analysis: ScoredSyndrome[];
  onAnalyzeRequest: () => void;
  initialSyndromeId?: string;
  isAnalyzing?: boolean;
  onBack?: () => void;
  patientContext?: any;
}

const ScoringAndPointsHub: React.FC<Props> = ({ analysis, onAnalyzeRequest, initialSyndromeId, isAnalyzing = false, onBack, patientContext }) => {
  const [selectedSyndrome, setSelectedSyndrome] = useState<ScoredSyndrome | null>(null);
  const [manualPoints, setManualPoints] = useState<RxPoint[]>([]);
  const [manualInput, setManualInput] = useState('');
  const [showNoteModal, setShowNoteModal] = useState(false);

  const contentRef = useRef<HTMLDivElement>(null);

  // Load initial syndrome from Atlas/Link
  useEffect(() => {
    if (initialSyndromeId) {
        const allSyndromes = [...TCM_DB.syndromes.FILLED_FROM_PDF, ...TCM_DB.syndromes.TODO_FROM_PDF];
        const found = allSyndromes.find(s => s.id === initialSyndromeId);

        if (found) {
            const existingInAnalysis = analysis.find(a => a.syndrome.id === initialSyndromeId);
            if (existingInAnalysis) {
                setSelectedSyndrome(existingInAnalysis);
            } else {
                // Not in analysis, mock a result for display
                let mockPoints: RxPoint[] = [];
                if (Array.isArray(found.acupuncture_points)) {
                     mockPoints = found.acupuncture_points.map(code => ({ code, role: 'kausal', source: 'manual' }));
                } else if (found.acupuncture_points && typeof found.acupuncture_points === 'object') {
                     const pts = found.acupuncture_points as any; 
                     if (pts.kausal) mockPoints = [...mockPoints, ...pts.kausal.map((c:string) => ({ code: c, role: 'kausal', source: 'manual' }))];
                     if (pts.simptomatik) mockPoints = [...mockPoints, ...pts.simptomatik.map((c:string) => ({ code: c, role: 'simptom', source: 'manual' }))];
                }

                setSelectedSyndrome({
                    syndrome: found,
                    score: 0, 
                    points: mockPoints,
                    warnings: [],
                    rationale: ["Manual selection from Atlas"],
                    herbal_recommendation: getHerbalRecommendation(found),
                });
            }
        }
    }
  }, [initialSyndromeId, analysis]);

  // Reset manual points when syndrome selection changes
  useEffect(() => {
    setManualPoints([]);
  }, [selectedSyndrome?.syndrome.id]);

  const sortedAnalysis = [...analysis].sort((a, b) => b.score - a.score);

  // Fallback to top score if nothing is selected
  useEffect(() => {
    if (!selectedSyndrome && sortedAnalysis.length > 0) {
        setSelectedSyndrome(sortedAnalysis[0]);
    }
  }, [sortedAnalysis]);


  // Helper for printing/snapshot
  const handleSnapshot = async () => {
    if (!contentRef.current) return;
    try {
        const canvas = await html2canvas(contentRef.current, {
            scale: 2,
            useCORS: true,
            backgroundColor: '#1e293b' // Keep slate-800 background
        });
        const imgData = canvas.toDataURL('image/png');
        const pdf = new jsPDF('l', 'mm', 'a4');
        const pdfW = pdf.internal.pageSize.getWidth();

        const imgProps = pdf.getImageProperties(imgData);
        const imgH = (imgProps.height * pdfW) / imgProps.width;

        pdf.addImage(imgData, 'PNG', 0, 0, pdfW, imgH);
        pdf.save(`CDSS_Snapshot_${selectedSyndrome?.syndrome.name_id || 'Analysis'}.pdf`);
    } catch(e) {
        console.error("Snapshot failed", e);
        alert("Gagal membuat snapshot PDF.");
    }
  };

  const handleAddManualPoint = (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!manualInput.trim()) return;

    const code = manualInput.toUpperCase().trim();

    // Check duplication
    const existsInSystem = selectedSyndrome?.points.some(p => p.code === code);
    const existsInManual = manualPoints.some(p => p.code === code);

    if (!existsInSystem && !existsInManual) {
        const newPoint: RxPoint = {
            code: code,
            role: 'manual',
            source: 'user_add',
            note: 'Ditambahkan manual'
        };
        setManualPoints([...manualPoints, newPoint]);
    }
    setManualInput('');
  };

  const removeManualPoint = (code: string) => {
      setManualPoints(manualPoints.filter(p => p.code !== code));
  };

