import React, { useState, useEffect } from 'react';
import { X, Info, Flame, Mountain, Wind, Droplets, Leaf, ArrowRight, ShieldAlert, RefreshCw } from 'lucide-react';
import { TCM_DB } from '../constants';
import { OrganDetail } from '../types';

interface Props {
  initialHighlight?: string | null;
  onClose?: () => void;
  className?: string;
  embedded?: boolean;
  onElementSelect?: (element: string | null) => void;
}

interface WuXingElement {
  id: string;
  label: string;
  zang: string;
  fu: string;
  zang2?: string;
  fu2?: string;
  x: number;
  y: number;
  color: string;
  icon: React.ReactNode;
}

export const WuXingInteractiveDiagram: React.FC<Props> = ({ initialHighlight, onClose, className, embedded = false, onElementSelect }) => {
  const [activeCycle, setActiveCycle] = useState<'all' | 'generating' | 'controlling'>('all');
  const [selectedElement, setSelectedElement] = useState<string | null>(initialHighlight || null);

  useEffect(() => {
    if (initialHighlight) {
      setSelectedElement(initialHighlight);
    }
  }, [initialHighlight]);

  const handleNodeClick = (label: string) => {
    const newVal = selectedElement === label ? null : label;
    setSelectedElement(newVal);
    if (onElementSelect) {
      onElementSelect(newVal);
    }
  };

  const positions = {
    fire: { x: 50, y: 15, color: '#ef4444', label: 'FIRE', icon: <Flame /> },
    earth: { x: 85, y: 38, color: '#f59e0b', label: 'EARTH', icon: <Mountain /> },
    metal: { x: 72, y: 80, color: '#94a3b8', label: 'METAL', icon: <Wind /> },
    water: { x: 28, y: 80, color: '#3b82f6', label: 'WATER', icon: <Droplets /> },
    wood: { x: 15, y: 38, color: '#10b981', label: 'WOOD', icon: <Leaf /> },
  };

  const elements: WuXingElement[] = [
    { id: 'fire', zang: 'Heart', fu: 'Small Intestine', zang2: 'Pericardium', fu2: 'San Jiao', ...positions.fire },
    { id: 'earth', zang: 'Spleen', fu: 'Stomach', ...positions.earth },
    { id: 'metal', zang: 'Lung', fu: 'Large Intestine', ...positions.metal },
    { id: 'water', zang: 'Kidney', fu: 'Bladder', ...positions.water },
    { id: 'wood', zang: 'Liver', fu: 'Gall Bladder', ...positions.wood },
  ];

  const getOrganData = (name: string): OrganDetail | undefined => {
    return TCM_DB.organ_details[name];
  };

  const isPathRelevant = (startLabel: string, endLabel: string) => {
    if (!selectedElement) return true;
    return startLabel === selectedElement || endLabel === selectedElement;
  };

  const renderArrow = (start: any, end: any, type: 'generating' | 'controlling', key: string) => {
    if (activeCycle !== 'all' && activeCycle !== type) return null;

    const isRelevant = isPathRelevant(start.label, end.label);
    const opacity = selectedElement ? (isRelevant ? 1 : 0.1) : 1;

    const angle = Math.atan2(end.y - start.y, end.x - start.x);
    const r = 13;
    const x1 = start.x + r * Math.cos(angle);
    const y1 = start.y + r * Math.sin(angle);
    const x2 = end.x - (r + 2) * Math.cos(angle);
    const y2 = end.y - (r + 2) * Math.sin(angle);

    const color = type === 'generating' ? '#10b981' : '#f43f5e';
    const width = type === 'generating' ? 2 : 1.5;
    const dash = type === 'generating' ? '8 4' : '4 4';

    const animationStyle = (activeCycle === type || activeCycle === 'all') 
        ? { animation: 'flow 1.5s linear infinite' } 
        : {};

    if (selectedElement && !isRelevant) {
        (animationStyle as any).animationPlayState = 'paused';
    }

    return (
      <line
        key={key}
        x1={x1} y1={y1}
        x2={x2} y2={y2}
        stroke={color}
        strokeWidth={width}
        strokeDasharray={dash}
        strokeLinecap="round"
        opacity={opacity}
        markerEnd={`url(#arrow-${type})`}
        style={animationStyle}
        className="transition-opacity duration-300"
      />
    );
  };

  const selectedNode = elements.find(e => e.label === selectedElement?.toUpperCase());

  const OrganDetailCard = ({ name, isFu, color }: { name: string, isFu?: boolean, color: string }) => {
    const data = getOrganData(name);
    if (!data) return null;

    return (
      <div className={`mb-3 p-4 rounded-xl shadow-sm border border-slate-700/50 ${isFu ? 'bg-slate-800/30' : 'bg-slate-800/80'}`}>
        <div className="flex justify-between items-start mb-2" style={{ borderLeft: isFu ? 'none' : `4px solid ${color}`, paddingLeft: isFu ? 0 : '0.5rem' }}>
          <div className="flex flex-col">
            <h4 className={`text-sm md:text-base font-bold ${isFu ? 'text-slate-300' : 'text-slate-200'}`}>
              {data.name} 
              <span className={`text-[9px] md:text-[10px] ml-2 px-1.5 py-0.5 rounded uppercase ${isFu ? 'bg-slate-700 text-slate-400' : 'bg-slate-700 text-white'}`}>
                {isFu ? 'FU' : 'ZANG'}
              </span>
            </h4>
          </div>
          <span className="text-[9px] text-slate-500 bg-slate-950 px-2 py-1 rounded-full whitespace-nowrap border border-slate-800">
            {data.time_of_day}
          </span>
        </div>
        <div className="space-y-1 md:space-y-2 text-[11px] md:text-xs text-slate-400 mt-2">
          <ul className="list-disc list-inside space-y-0.5 md:space-y-1 ml-1 mb-3">
             {data.main_functions.map((f, i) => <li key={i}>{f}</li>)}
          </ul>
          <div className="grid grid-cols-2 gap-x-3 gap-y-1.5 pt-3 border-t border-slate-700/50 text-[9px] md:text-[10px]">
            {data.emotion && <div className="flex justify-between"><span className="text-slate-500">Emotion:</span> <span className="text-slate-300">{data.emotion}</span></div>}
            {data.season && <div className="flex justify-between"><span className="text-slate-500">Season:</span> <span className="text-slate-300">{data.season}</span></div>}
            {data.flavor && <div className="flex justify-between"><span className="text-slate-500">Flavor:</span> <span className="text-slate-300">{data.flavor}</span></div>}
            {data.paired_organ && <div className="flex justify-between"><span className="text-slate-500">Pair:</span> <span className="text-tcm-primary">{data.paired_organ}</span></div>}
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className={`bg-slate-900 flex flex-col h-full overflow-hidden ${className || ''}`}>
        {/* Header Modal - Only if not embedded */}
        {!embedded && (
            <div className="flex items-center justify-between p-4 md:p-5 border-b border-slate-800 bg-slate-900 shrink-0">
                <div className="flex flex-col">
                    <h2 className="text-xl font-bold text-tcm-primary flex items-center gap-2">Wu Xing Interactive Map</h2>
                    <p className="text-[10px] md:text-xs text-slate-500">Explore the Generating & Controlling Cycles</p>
                </div>
                {onClose && (
                    <button onClick={onClose} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-full transition-colors">
                        <X className="w-6 h-6" />
                    </button>
                )}
            </div>
        )}

        <div className="flex-1 overflow-hidden flex flex-col md:flex-row min-h-0 relative">

          {/* LEFT/TOP: Diagram SVG Section */}
          <div className={`relative bg-gradient-to-br from-slate-900 to-slate-800/50 flex items-center justify-center p-4 md:p-8 transition-all duration-500 ${selectedElement ? 'h-[40%] md:h-full md:flex-1' : 'h-full md:flex-1'}`}>
            <svg 
              viewBox="0 0 100 100" 
              className="w-full h-full max-h-[95%] select-none filter drop-shadow-2xl"
              preserveAspectRatio="xMidYMid meet"
            >
              <defs>
                <marker id="arrow-generating" markerWidth="6" markerHeight="6" refX="5" refY="3" orient="auto">
                  <path d="M0,0 L0,6 L6,3 z" fill="#10b981" />
                </marker>
                <marker id="arrow-controlling" markerWidth="6" markerHeight="6" refX="5" refY="3" orient="auto">
                  <path d="M0,0 L0,6 L6,3 z" fill="#f43f5e" />
                </marker>
              </defs>

              {/* Lines rendering */}
              {renderArrow(positions.wood, positions.fire, 'generating', 'wood-fire')}
              {renderArrow(positions.fire, positions.earth, 'generating', 'fire-earth')}
              {renderArrow(positions.earth, positions.metal, 'generating', 'earth-metal')}
              {renderArrow(positions.metal, positions.water, 'generating', 'metal-water')}
              {renderArrow(positions.water, positions.wood, 'generating', 'water-wood')}

              {renderArrow(positions.wood, positions.earth, 'controlling', 'wood-earth')}
              {renderArrow(positions.earth, positions.water, 'controlling', 'earth-water')}
              {renderArrow(positions.water, positions.fire, 'controlling', 'water-fire')}
              {renderArrow(positions.fire, positions.metal, 'controlling', 'fire-metal')}
              {renderArrow(positions.metal, positions.wood, 'controlling', 'metal-wood')}

              {/* Nodes rendering */}
              {elements.map((el) => {
                const isSelected = selectedElement === el.label;
                const isDimmed = selectedElement && !isSelected;
                return (
                  <g 
                    key={el.id} 
                    className="cursor-pointer transition-all duration-300" 
                    onClick={() => handleNodeClick(el.label)}
                    style={{ opacity: isDimmed ? 0.2 : 1 }}
                  >
                    {isSelected && (
                       <circle cx={el.x} cy={el.y} r="18" fill="none" stroke={el.color} strokeWidth="0.5" strokeDasharray="3,3" className="animate-spin-slow" />
                    )}
                    <circle 
                      cx={el.x} cy={el.y} 
                      r={isSelected ? "14" : "12"} 
                      fill={isSelected ? el.color : "#1e293b"} 
                      stroke={el.color} 
                      strokeWidth={isSelected ? "0" : "1.5"} 
                      className="transition-all duration-300"
                    />
                    <text x={el.x} y={el.y - 1} textAnchor="middle" fontSize="3.2" fill={isSelected ? '#1e293b' : el.color} fontWeight="900" pointerEvents="none">{el.label}</text>
                    <text x={el.x} y={el.y + 3} textAnchor="middle" fontSize="2.8" fill={isSelected ? 'white' : '#cbd5e1'} fontWeight="bold" pointerEvents="none">{el.zang}</text>
                    {el.zang2 && <text x={el.x} y={el.y + 5.5} textAnchor="middle" fontSize="2.8" fill={isSelected ? 'white' : '#cbd5e1'} fontWeight="bold" pointerEvents="none">& {el.zang2}</text>}
                  </g>
                );
              })}
            </svg>

            {/* Legend Overlay - Adjusted for better mobile fit */}
            <div className={`absolute bottom-4 left-4 right-4 md:right-auto bg-slate-950/80 p-2.5 rounded-2xl border border-slate-800 backdrop-blur-md flex md:flex-col justify-around md:justify-start gap-4 transition-opacity duration-300 ${selectedElement ? 'opacity-30 md:opacity-100' : 'opacity-100'}`}>
               <div className="flex items-center gap-2">
                 <div className="w-3 md:w-4 h-0.5 bg-emerald-500 rounded-full"></div>
                 <span className="text-slate-400 font-bold uppercase tracking-wider text-[8px] md:text-[10px]">Generating</span>
               </div>
               <div className="flex items-center gap-2">
                 <div className="w-3 md:w-4 h-0.5 border-t border-rose-500 border-dashed"></div>
                 <span className="text-slate-400 font-bold uppercase tracking-wider text-[8px] md:text-[10px]">Controlling</span>
               </div>
            </div>
          </div>

          {/* RIGHT/BOTTOM: Info & Detail Panel Section */}
          <div className={`bg-slate-950 md:bg-slate-900 flex flex-col h-full overflow-hidden transition-all duration-500 border-t md:border-t-0 md:border-l border-slate-800 shrink-0 ${selectedElement ? 'flex-1 md:w-[420px]' : 'h-0 md:w-0 overflow-hidden opacity-0'}`}>
            {!selectedElement ? (
               <div className="p-6 h-full flex flex-col justify-center animate-fade-in space-y-6">
                  {/* Content when nothing is selected (usually hidden by flex-0 on desktop) */}
               </div>
            ) : (
               <div className="flex-1 overflow-y-auto p-4 md:p-6 animate-slide-in-right scrollbar-hide relative">
                 <div className="sticky top-0 z-10 bg-slate-950 md:bg-slate-900 pb-4 mb-2">
                   <button onClick={() => handleNodeClick(selectedElement)} className="text-[9px] md:text-[10px] text-tcm-primary hover:text-white flex items-center gap-1 font-black uppercase tracking-[0.2em] transition-colors py-1">
                      &larr; Return to Map
                   </button>
                 </div>

                 <div className="flex items-center gap-4 mb-6">
                   <div className="p-3 md:p-4 rounded-3xl bg-slate-800 border border-slate-700 shadow-xl" style={{ color: selectedNode?.color }}>
                      {selectedNode?.id === 'fire' && <Flame className="w-6 h-6 md:w-8 md:h-8" />}
                      {selectedNode?.id === 'earth' && <Mountain className="w-6 h-6 md:w-8 md:h-8" />}
                      {selectedNode?.id === 'metal' && <Wind className="w-6 h-6 md:w-8 md:h-8" />}
                      {selectedNode?.id === 'water' && <Droplets className="w-6 h-6 md:w-8 md:h-8" />}
                      {selectedNode?.id === 'wood' && <Leaf className="w-6 h-6 md:w-8 md:h-8" />}
                   </div>
                   <div>
                      <h3 className="text-3xl md:text-4xl font-black tracking-tighter text-white uppercase">{selectedElement}</h3>
                      <p className="text-[9px] md:text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-0.5">Core Dynamic Analysis</p>
                   </div>
                 </div>

                 <div className="space-y-4 pb-12">
                    <div className="text-[10px] md:text-xs text-slate-500 font-black uppercase tracking-[0.1em] border-b border-slate-800 pb-2 mb-3">Associated Zang-Fu Organs</div>
