                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-2 gap-4">
                    {syndromes.map(s => (
                      <div 
                        key={s.id}
                        onClick={() => onSelectSyndrome?.(s.id)}
                        className={`bg-slate-900/40 hover:bg-slate-800/60 p-5 rounded-2xl border border-slate-800/50 hover:border-white/20 cursor-pointer transition-all group flex items-start gap-4 shadow-lg active:scale-[0.98] ${el.borderColor}`}
                      >
                         <div className={`p-3 rounded-xl bg-black border border-slate-800 shadow-inner group-hover:scale-110 transition-transform ${el.color}`}>
                            <Target className="w-5 h-5" />
                         </div>
                         <div className="flex-1 min-w-0">
                            <h4 className="font-bold text-white text-base leading-tight group-hover:text-tcm-primary transition-colors mb-1">{s.name_id}</h4>
                            <p className="text-slate-500 text-xs italic mb-3 truncate">{s.name_en}</p>
                            <div className="flex flex-wrap gap-1.5">
                               {s.primary_organs?.map(org => (
                                 <span key={org} className="px-2 py-0.5 rounded bg-slate-800/80 text-[9px] text-slate-400 font-bold uppercase tracking-tighter">{org}</span>
                               ))}
                            </div>
                         </div>
                         <ArrowRight className="w-4 h-4 text-slate-700 group-hover:text-white transition-colors self-center" />
                      </div>
                    ))}

                    {syndromes.length === 0 && (
                      <div className="col-span-full py-10 px-4 border border-dashed border-slate-800 rounded-2xl flex flex-col items-center justify-center text-slate-600">
                         <Info className="w-8 h-8 mb-2 opacity-20" />
                         <p className="text-xs italic">No syndromes found for this category with current filters.</p>
                      </div>
                    )}
                  </div>
                </div>
              );
            })}
         </div>

         <div className="mt-20 py-10 border-t border-slate-900 text-center">
            <p className="text-[10px] text-slate-700 uppercase tracking-widest font-mono">
               TCM WuXing Pro Visualizer v{TCM_DB.metadata.version} • Sync Engine Active
            </p>
         </div>
      </div>
    </div>
  );
};

