import React, { useState, useEffect } from 'react';
import { X, Info, Flame, Mountain, Wind, Droplets, Leaf, ArrowRight, ShieldAlert, RefreshCw, Zap, Heart, AlertCircle } from 'lucide-react';
import { TCM_DB } from '../constants';
import { OrganDetail } from '../types';

interface Props {
  initialHighlight?: string | null;
  onClose?: () => void;
  className?: string;
  embedded?: boolean;
  onElementSelect?: (element: string | null) => void;
}

interface WuXingElement {
  id: string;
  label: string;
  zang: string;
  fu: string;
  zang2?: string;
  fu2?: string;
  x: number;
  y: number;
  color: string;
  icon: React.ReactNode;
  mother: string;
  child: string;
  controls: string;
  controlledBy: string;
}

export const WuXingInteractiveDiagram: React.FC<Props> = ({ initialHighlight, onClose, className, embedded = false, onElementSelect }) => {
  const [selectedElement, setSelectedElement] = useState<string | null>(initialHighlight || null);

  useEffect(() => {
    if (initialHighlight) {
      setSelectedElement(initialHighlight);
    }
  }, [initialHighlight]);

  const handleNodeClick = (label: string) => {
    const newVal = selectedElement?.toLowerCase() === label.toLowerCase() ? null : label.toLowerCase();
    setSelectedElement(newVal);
    if (onElementSelect) {
      onElementSelect(newVal);
    }
  };

  const positions = {
    fire: { x: 50, y: 18, color: '#f43f5e', label: 'FIRE', icon: <Flame /> },
    earth: { x: 82, y: 42, color: '#f59e0b', label: 'EARTH', icon: <Mountain /> },
    metal: { x: 70, y: 82, color: '#cbd5e1', label: 'METAL', icon: <Wind /> },
    water: { x: 30, y: 82, color: '#3b82f6', label: 'WATER', icon: <Droplets /> },
    wood: { x: 18, y: 42, color: '#10b981', label: 'WOOD', icon: <Leaf /> },
  };

  const elements: WuXingElement[] = [
    { id: 'fire', zang: 'Heart', fu: 'Small Intestine', zang2: 'Pericardium', fu2: 'San Jiao', mother: 'wood', child: 'earth', controls: 'metal', controlledBy: 'water', ...positions.fire },
    { id: 'earth', zang: 'Spleen', fu: 'Stomach', mother: 'fire', child: 'metal', controls: 'water', controlledBy: 'wood', ...positions.earth },
    { id: 'metal', zang: 'Lung', fu: 'Large Intestine', mother: 'earth', child: 'water', controls: 'wood', controlledBy: 'fire', ...positions.metal },
    { id: 'water', zang: 'Kidney', fu: 'Bladder', mother: 'metal', child: 'wood', controls: 'fire', controlledBy: 'earth', ...positions.water },
    { id: 'wood', zang: 'Liver', fu: 'Gall Bladder', mother: 'water', child: 'fire', controls: 'earth', controlledBy: 'metal', ...positions.wood },
  ];

  const getOrganData = (name: string): OrganDetail | undefined => {
    return TCM_DB.organ_details[name];
  };

  const isPathRelevant = (startId: string, endId: string) => {
    if (!selectedElement) return true;
    return startId === selectedElement || endId === selectedElement;
  };

  const renderArrow = (start: any, end: any, type: 'generating' | 'controlling', key: string) => {
    const startEl = elements.find(e => e.label === start.label);
    const endEl = elements.find(e => e.label === end.label);
    if (!startEl || !endEl) return null;

    const isRelevant = isPathRelevant(startEl.id, endEl.id);
    const opacity = selectedElement ? (isRelevant ? 1 : 0.05) : 0.6;

    const angle = Math.atan2(end.y - start.y, end.x - start.x);
    const r = 14;
    const x1 = start.x + r * Math.cos(angle);
    const y1 = start.y + r * Math.sin(angle);
    const x2 = end.x - (r + 2) * Math.cos(angle);
    const y2 = end.y - (r + 2) * Math.sin(angle);

    const color = type === 'generating' ? '#10b981' : '#f43f5e';
    const width = type === 'generating' ? 1.5 : 1.2;
    const dash = type === 'generating' ? '' : '3 3';

    return (
      <g key={key} className="transition-opacity duration-500">
        <line
          x1={x1} y1={y1}
          x2={x2} y2={y2}
          stroke={color}
          strokeWidth={width}
          strokeDasharray={dash}
          strokeLinecap="round"
          opacity={opacity}
          markerEnd={`url(#arrow-${type})`}
        />
        {isRelevant && selectedElement && (
            <circle cx={(x1+x2)/2} cy={(y1+y2)/2} r="0.8" fill={color} className="animate-pulse" />
        )}
      </g>
    );
  };

  const activeElementData = elements.find(e => e.id === selectedElement);

  const OrganDetailCard = ({ name, isFu, color }: { name: string, isFu?: boolean, color: string }) => {
    const data = getOrganData(name);
    if (!data) return null;

    return (
      <div className={`mb-3 p-3 rounded-xl border border-slate-800/50 bg-slate-900/50 hover:bg-slate-800/80 transition-colors shadow-sm`}>
        <div className="flex justify-between items-start mb-2">
          <div className="flex flex-col">
            <h4 className="text-sm font-bold text-white flex items-center gap-2">
              <span className="w-1.5 h-3 rounded-full" style={{ backgroundColor: color }}></span>
              {data.name} 
              <span className={`text-[9px] px-1.5 py-0.5 rounded font-black ${isFu ? 'bg-slate-800 text-slate-500' : 'bg-tcm-primary/20 text-tcm-primary'}`}>
                {isFu ? 'FU' : 'ZANG'}
              </span>
            </h4>
          </div>
          <span className="text-[9px] text-slate-500 font-mono">{data.time_of_day}</span>
        </div>
        <div className="text-[10px] text-slate-400 leading-relaxed">
           {data.main_functions.slice(0, 2).join(' • ')}
        </div>
      </div>
    );
  };

  return (
    <div className={`bg-slate-950 flex flex-col h-full overflow-hidden ${className || ''}`}>
        {!embedded && (
            <div className="flex items-center justify-between p-4 border-b border-slate-800 bg-slate-900 shrink-0">
                <div className="flex flex-col">
                    <h2 className="text-xl font-bold text-emerald-400 flex items-center gap-2">Wu Xing Interactive Master</h2>
                    <p className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">Generating & Controlling Dynamics</p>
                </div>
                {onClose && (
                    <button onClick={onClose} className="p-2 text-slate-400 hover:text-white hover:bg-slate-800 rounded-full transition-colors">
                        <X className="w-6 h-6" />
                    </button>
                )}
            </div>
        )}

        <div className="flex-1 overflow-hidden flex flex-col md:flex-row min-h-0">

          {/* DIAGRAM SECTION */}
          <div className={`relative bg-black flex items-center justify-center p-4 md:p-8 transition-all duration-500 ${selectedElement ? 'h-[45%] md:h-full md:flex-1' : 'h-full md:flex-1'}`}>
            <svg 
              viewBox="0 0 100 100" 
              className="w-full h-full max-h-[90%] select-none"
              preserveAspectRatio="xMidYMid meet"
            >
              <defs>
                <marker id="arrow-generating" markerWidth="6" markerHeight="6" refX="5" refY="3" orient="auto">
                  <path d="M0,0 L0,6 L6,3 z" fill="#10b981" />
                </marker>
                <marker id="arrow-controlling" markerWidth="6" markerHeight="6" refX="5" refY="3" orient="auto">
                  <path d="M0,0 L0,6 L6,3 z" fill="#f43f5e" />
                </marker>
                <filter id="glow-node">
                  <feGaussianBlur stdDeviation="2" result="blur" />
                  <feComposite in="SourceGraphic" in2="blur" operator="over" />
                </filter>
              </defs>

              {/* Generating Cycles (Sheng) */}
              {renderArrow(positions.wood, positions.fire, 'generating', 'wood-fire')}
              {renderArrow(positions.fire, positions.earth, 'generating', 'fire-earth')}
              {renderArrow(positions.earth, positions.metal, 'generating', 'earth-metal')}
              {renderArrow(positions.metal, positions.water, 'generating', 'metal-water')}
              {renderArrow(positions.water, positions.wood, 'generating', 'water-wood')}

              {/* Controlling Cycles (Ke) */}
              {renderArrow(positions.wood, positions.earth, 'controlling', 'wood-earth')}
              {renderArrow(positions.earth, positions.water, 'controlling', 'earth-water')}
              {renderArrow(positions.water, positions.fire, 'controlling', 'water-fire')}
              {renderArrow(positions.fire, positions.metal, 'controlling', 'fire-metal')}
              {renderArrow(positions.metal, positions.wood, 'controlling', 'metal-wood')}

              {/* Nodes */}
              {elements.map((el) => {
                const isSelected = selectedElement === el.id;
                const isDimmed = selectedElement && !isSelected;

                return (
                  <g 
                    key={el.id} 
                    className="cursor-pointer transition-all duration-500" 
                    onClick={() => handleNodeClick(el.label)}
                    style={{ opacity: isDimmed ? 0.15 : 1 }}
                  >
                    {isSelected && (
                       <circle cx={el.x} cy={el.y} r="16" fill="none" stroke={el.color} strokeWidth="0.3" strokeDasharray="2,2" className="animate-spin-slow" />
                    )}
                    <circle 
                      cx={el.x} cy={el.y} 
                      r={isSelected ? "12" : "10"} 
                      fill={isSelected ? el.color : "#0f172a"} 
                      stroke={el.color} 
                      strokeWidth={isSelected ? "1.5" : "1"} 
                      className="transition-all duration-500 shadow-xl"
                    />
                    <text x={el.x} y={el.y - 1} textAnchor="middle" fontSize="3" fill={isSelected ? 'black' : el.color} fontWeight="900" pointerEvents="none">{el.label}</text>
                    <text x={el.x} y={el.y + 3} textAnchor="middle" fontSize="2.5" fill={isSelected ? 'white' : '#94a3b8'} fontWeight="bold" pointerEvents="none">{el.zang}</text>
                  </g>
                );
              })}
            </svg>

            {/* Legend */}
            <div className={`absolute bottom-6 left-6 flex flex-col gap-2 bg-black/60 p-3 rounded-xl border border-white/5 backdrop-blur-sm transition-opacity duration-500 ${selectedElement ? 'opacity-20 hover:opacity-100' : 'opacity-100'}`}>
               <div className="flex items-center gap-3">
                 <div className="w-8 h-0.5 bg-emerald-500 rounded-full"></div>
                 <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Generating (Sheng)</span>
               </div>
               <div className="flex items-center gap-3">
                 <div className="w-8 h-0.5 border-t border-rose-500 border-dashed"></div>
                 <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Controlling (Ke)</span>
               </div>
            </div>
          </div>

          {/* DETAIL PANEL */}
          <div className={`bg-slate-950 flex flex-col h-full overflow-hidden transition-all duration-500 border-t md:border-t-0 md:border-l border-slate-800 shrink-0 ${selectedElement ? 'flex-1 md:w-[450px]' : 'h-0 md:w-0 opacity-0'}`}>
            {activeElementData && (
               <div className="flex-1 overflow-y-auto p-5 md:p-8 animate-slide-in-right scrollbar-hide">
                 <div className="mb-8">
                   <button onClick={() => setSelectedElement(null)} className="text-[10px] text-slate-500 hover:text-white font-bold uppercase tracking-widest mb-6 flex items-center gap-2">
                     &larr; View Full Map
                   </button>

                   <div className="flex items-center gap-5">
                      <div className="w-16 h-16 rounded-3xl flex items-center justify-center bg-slate-900 border border-slate-800 shadow-2xl" style={{ color: activeElementData.color }}>
                         {React.cloneElement(activeElementData.icon as React.ReactElement, { className: 'w-8 h-8' })}
                      </div>
                      <div>
                         <h3 className="text-4xl font-black text-white uppercase tracking-tighter">{activeElementData.label}</h3>
                         <div className="flex items-center gap-2 mt-1">
                            <span className="text-[10px] bg-slate-800 px-2 py-0.5 rounded text-slate-400 font-bold uppercase">Element Dynamic</span>
                         </div>
                      </div>
                   </div>
                 </div>

                 {/* Dynamic Relationships */}
                 <div className="grid grid-cols-2 gap-3 mb-8">
                    <div className="bg-emerald-900/10 border border-emerald-500/30 p-4 rounded-2xl">
                       <div className="text-[10px] text-emerald-400 font-black uppercase mb-1 tracking-widest">Generating</div>
                       <div className="text-sm text-white font-bold">Generates <span className="uppercase text-emerald-400">{activeElementData.child}</span></div>
                    </div>
                    <div className="bg-rose-900/10 border border-rose-500/30 p-4 rounded-2xl">
                       <div className="text-[10px] text-rose-400 font-black uppercase mb-1 tracking-widest">Controlling</div>
                       <div className="text-sm text-white font-bold">Controls <span className="uppercase text-rose-400">{activeElementData.controls}</span></div>
                    </div>
                 </div>

                 {/* Clinical Clinical Logic Section */}
                 <div className="bg-slate-900 border border-slate-800 rounded-2xl p-5 mb-8">
                    <h4 className="text-[11px] text-indigo-400 font-black uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                        <Zap className="w-4 h-4" /> Clinical Strategy
                    </h4>
                    <div className="space-y-4">
                       <div className="flex items-start gap-3">
                          <div className="w-8 h-8 rounded-lg bg-emerald-500/20 flex items-center justify-center shrink-0 text-emerald-400 font-bold text-xs">M</div>
                          <div>
                             <p className="text-[10px] font-bold text-slate-500 uppercase">If Deficient (Tonify Mother)</p>
                             <p className="text-xs text-slate-200">Tonify <span className="font-bold text-emerald-400 uppercase">{activeElementData.mother}</span> organs.</p>
                          </div>
                       </div>
                       <div className="flex items-start gap-3">
                          <div className="w-8 h-8 rounded-lg bg-rose-500/20 flex items-center justify-center shrink-0 text-rose-400 font-bold text-xs">C</div>
                          <div>
                             <p className="text-[10px] font-bold text-slate-500 uppercase">If Excess (Sedate Child)</p>
                             <p className="text-xs text-slate-200">Sedate <span className="font-bold text-rose-400 uppercase">{activeElementData.child}</span> organs.</p>
                          </div>
                       </div>
                    </div>
                 </div>

                 {/* Associated Organs */}
                 <div className="space-y-4 pb-20">
                    <h4 className="text-[11px] text-slate-500 font-black uppercase tracking-[0.2em] mb-2 flex items-center gap-2">
                       <Heart className="w-4 h-4" /> Zang-Fu Mapping
                    </h4>
                    <OrganDetailCard name={activeElementData.zang} color={activeElementData.color} />
                    {activeElementData.zang2 && <OrganDetailCard name={activeElementData.zang2} color={activeElementData.color} />}
                    <OrganDetailCard name={activeElementData.fu} color={activeElementData.color} isFu />
                    {activeElementData.fu2 && <OrganDetailCard name={activeElementData.fu2} color={activeElementData.color} isFu /> }
                 </div>
               </div>
            )}
          </div>
        </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { TCM_DB } from '../constants';
import { ArrowRight, Loader2, Info, ChevronDown, Target, Filter, LayoutGrid, Map as MapIcon, X, Search } from 'lucide-react';
import { WuXingInteractiveDiagram } from './WuXingInteractiveDiagram';

interface Props {
  onSelectSyndrome?: (id: string) => void;
  onGenerateImage?: (prompt: string) => void;
  onShowMap?: () => void;
  isLoading?: boolean;
}

const elements = [
  { 
    name: 'wood', display: 'Wood (Kayu)', 
    color: 'text-emerald-400', borderColor: 'border-emerald-500/50', shadowColor: 'shadow-emerald-900/50',
    keywords: ['Liver', 'Gall', 'Wood', 'Hati', 'Empedu'],
    organs: ['Liver', 'Gall Bladder']
  },
  { 
    name: 'fire', display: 'Fire (Api)', 
    color: 'text-rose-400', borderColor: 'border-rose-500/50', shadowColor: 'shadow-rose-900/50',
    keywords: ['Heart', 'Small Intestine', 'Pericardium', 'San Jiao', 'Fire', 'Jantung'],
    organs: ['Heart', 'Small Intestine', 'Pericardium', 'San Jiao']
  },
  { 
    name: 'earth', display: 'Earth (Tanah)', 
    color: 'text-amber-400', borderColor: 'border-amber-500/50', shadowColor: 'shadow-amber-900/50',
    keywords: ['Spleen', 'Stomach', 'Earth', 'Limpa', 'Lambung'],
    organs: ['Spleen', 'Stomach']
  },
  { 
    name: 'metal', display: 'Metal (Logam)', 
    color: 'text-slate-100', borderColor: 'border-slate-300/50', shadowColor: 'shadow-slate-500/50',
    keywords: ['Lung', 'Large Intestine', 'Metal', 'Paru', 'Usus Besar'],
    organs: ['Lung', 'Large Intestine']
  },
  { 
    name: 'water', display: 'Water (Air)', 
    color: 'text-blue-400', borderColor: 'border-blue-500/50', shadowColor: 'shadow-blue-900/50',
    keywords: ['Kidney', 'Bladder', 'Water', 'Ginjal', 'Kandung Kemih'],
    organs: ['Kidney', 'Bladder']
  },
];

const WuXingMasterPanel: React.FC<Props> = ({ onSelectSyndrome, isLoading = false }) => {
  const [diagramSelection, setDiagramSelection] = useState<string | null>(null);
  const [organFilter, setOrganFilter] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  const allSyndromes = [
    ...TCM_DB.syndromes.FILLED_FROM_PDF,
    ...TCM_DB.syndromes.TODO_FROM_PDF
  ];

  const handleElementSelect = (el: string | null) => {
    setOrganFilter(null);
    setDiagramSelection(el);
    if (scrollRef.current) {
        scrollRef.current.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const handleOrganFilter = (org: string) => {
    setOrganFilter(org);
    const foundEl = elements.find(e => e.organs.includes(org));
    if (foundEl) setDiagramSelection(foundEl.name);
  };

  const clearAllFilters = () => {
    setDiagramSelection(null);
    setOrganFilter(null);
    setSearchQuery('');
  };

  if (isLoading) {
    return (
      <div className="h-full flex flex-col items-center justify-center bg-black text-white p-6 animate-fade-in">
        <Loader2 className="w-16 h-16 text-emerald-500 animate-spin mb-6" />
        <h3 className="text-2xl font-bold text-emerald-400 tracking-wider">TCM Wu Xing Master</h3>
        <p className="text-slate-500 text-sm mt-2 font-mono uppercase tracking-widest">Architecting Elemental Dynamics...</p>
      </div>
    );
  }

  const activeElementData = diagramSelection 
    ? elements.find(e => e.name.toLowerCase() === diagramSelection.toLowerCase()) 
    : null;

  const getFilteredSyndromes = (elName: string) => {
    const el = elements.find(e => e.name === elName);
    if (!el) return [];

    return allSyndromes.filter(s => {
      // 1. Search Query Filter
      if (searchQuery.trim()) {
          const q = searchQuery.toLowerCase();
          const match = (s.name_id || "").toLowerCase().includes(q) || 
                        (s.name_en || "").toLowerCase().includes(q);
          if (!match) return false;
      }

      // 2. Specific Organ Filter
      if (organFilter) {
          return (s.primary_organs || []).some(o => o.toLowerCase() === organFilter.toLowerCase());
      }

      // 3. Element Membership Filter
      if (s.wuxing_element && s.wuxing_element.toLowerCase().startsWith(elName.toLowerCase())) return true;
      const text = (s.name_en || "") + " " + (s.name_id || "") + " " + (s.primary_organs || []).join(" ");
      return el.keywords.some(k => text.toLowerCase().includes(k.toLowerCase()));
    });
  };

  return (
    <div className="h-full bg-black text-white flex flex-col md:flex-row overflow-hidden font-sans">

      {/* MAP SECTION */}
      <div className="w-full md:w-[45%] lg:w-[420px] border-r border-slate-800 bg-slate-900/40 flex flex-col h-[450px] md:h-full shrink-0">
         <div className="p-4 md:p-6 border-b border-slate-800 flex justify-between items-center bg-slate-900/90 backdrop-blur-md z-10">
            <div>
               <h3 className="text-xl font-black text-emerald-400 flex items-center gap-2">
                 <MapIcon className="w-5 h-5" /> Interactive Map
               </h3>
               <p className="text-[10px] text-slate-500 uppercase font-bold tracking-[0.2em]">Five Elements Cycle</p>
            </div>
            {(diagramSelection || organFilter || searchQuery) && (
               <button onClick={clearAllFilters} className="text-[10px] font-bold text-slate-400 hover:text-white flex items-center gap-1 bg-slate-800 px-3 py-1.5 rounded-full border border-slate-700 transition-all">
                  <X className="w-3 h-3" /> Reset
               </button>
            )}
         </div>

         <div className="flex-1 min-h-0">
            <WuXingInteractiveDiagram 
                embedded={true} 
                className="h-full w-full" 
                onElementSelect={handleElementSelect}
                initialHighlight={diagramSelection}
            />
         </div>

         {/* Organ Fast-Switch */}
         <div className="p-4 border-t border-slate-800 bg-slate-900/50 overflow-x-auto scrollbar-hide shrink-0">
            <div className="flex gap-2 min-w-max">
               {['Liver', 'Heart', 'Spleen', 'Lung', 'Kidney'].map(org => (
                 <button 
                    key={org}
                    onClick={() => handleOrganFilter(org)}
                    className={`px-3 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all border ${
                        organFilter === org 
                        ? 'bg-emerald-600 border-emerald-400 text-white shadow-lg shadow-emerald-900/40' 
                        : 'bg-slate-800 border-slate-700 text-slate-500 hover:border-slate-500'
                    }`}
                 >
                    {org}
                 </button>
               ))}
            </div>
         </div>
      </div>

      {/* SYNDROMES CONTENT */}
