import { TCM_DB } from '../constants';
import { Syndrome, PatientFormSchema, RxPoint, ScoredSyndrome } from '../types';

export interface AutoRxInput {
  syndrome: Syndrome;
  selectedSymptoms: string[];
  tongue?: string[];
  pulse?: string[];
  bodyRegion?: string[];
  isPregnant?: boolean;
}

const SEVERITY_HIGH = ["sangat", "hebat", "parah", "severe", "intense", "extreme", "berlebihan", "tajam", "sharp", "mendadak"];
const DURATION_CHRONIC = ["lama", "kronis", "chronic", "bertahun", "berbulan", "long-term", "persistent", "hilang timbul"];
const DURATION_ACUTE = ["baru", "akut", "sudden", "recent", "acute", "just started", "tiba-tiba"];

export const normalize = (s: string) => 
  (s || "").toLowerCase().replace(/[^\p{L}\p{N}\s]/gu, " ").replace(/\s+/g, " ").trim();

const similarityRatio = (a: string, b: string): number => {
  const normA = normalize(a);
  const normB = normalize(b);
  if (normA === normB) return 1.0;
  if (normA.length === 0 || normB.length === 0) return 0.0;

  const setA = new Set(normA.split(/\s+/));
  const setB = new Set(normB.split(/\s+/));
  const intersection = new Set([...setA].filter(x => setB.has(x)));
  return intersection.size / Math.max(setA.size, setB.size);
};

export const fuzzyMatch = (a: string, b: string, threshold = 0.75): boolean => {
  const normA = normalize(a);
  const normB = normalize(b);
  if (normA.includes(normB) || normB.includes(normA)) return true;
  return similarityRatio(a, b) >= threshold;
};

const expandWithSynonyms = (base: string[]): Set<string> => {
  const out = new Set<string>();
  const synonymMap = TCM_DB.clinical_config.matching.synonym_map;

  base.forEach(s => {
    const key = normalize(s);
    if (!key) return;
    out.add(key);
    if (synonymMap[key]) {
      synonymMap[key].forEach(syn => out.add(normalize(syn)));
    }
  });
  return out;
};

const extractSymptoms = (text: string): string[] => {
    return text.split(/[\n,.]+/).map(normalize).filter(s => s.length > 2);
};

interface PathologicalSigns {
  HEAT_FULL: boolean;
  HEAT_EMPTY: boolean; // Yin Def
  COLD_FULL: boolean;
  COLD_EMPTY: boolean; // Yang Def
  DAMP_PHLEGM: boolean;
  STASIS: boolean;
  BLOOD_DEF: boolean;
  QI_DEF: boolean;
  QI_STAG: boolean;
  YANG_RISING: boolean;
  ORGANS_IMPLICATED: Set<string>;
}

const detectPathologyFromSigns = (
  tongue: PatientFormSchema['tongue'],
  pulse: PatientFormSchema['pulse']
): PathologicalSigns => {
  const signs: PathologicalSigns = {
    HEAT_FULL: false, HEAT_EMPTY: false,
    COLD_FULL: false, COLD_EMPTY: false,
    DAMP_PHLEGM: false, STASIS: false,
    BLOOD_DEF: false, QI_DEF: false,
    QI_STAG: false, YANG_RISING: false,
    ORGANS_IMPLICATED: new Set<string>()
  };

  const tBody = normalize(tongue.body_color);
  const tCoat = normalize(tongue.coating_color);
  const tQual = normalize(tongue.coating_quality);
  const tFeat = (tongue.special_features || []).map(normalize);
  const pQuals = (pulse.qualities || []).map(normalize);

  // HEAT DIFFERENTIATION
  if (tBody.includes('red') || tCoat.includes('yellow') || pQuals.some(q => q.includes('rapid'))) {
    if (tQual.includes('none') || tQual.includes('peeling') || tQual.includes('dry')) {
      signs.HEAT_EMPTY = true; // Yin Deficiency Heat
    } else {
      signs.HEAT_FULL = true; // Excess Heat
    }
  }

  // COLD DIFFERENTIATION
  if (tBody.includes('pale') || tCoat.includes('white') || pQuals.some(q => q.includes('slow'))) {
    if (tQual.includes('wet') || tQual.includes('slippery') || pQuals.some(q => q.includes('weak'))) {
      signs.COLD_EMPTY = true; // Yang Deficiency Cold
    } else {
      signs.COLD_FULL = true; // Excess Cold
    }
  }

  // DAMP & PHLEGM
  if (tQual.includes('greasy') || tQual.includes('sticky') || tQual.includes('thick') || tFeat.some(f => f.includes('swollen')) || pQuals.some(q => q.includes('slippery'))) {
    signs.DAMP_PHLEGM = true;
  }

  // BLOOD & QI
  if (tBody.includes('pale') && !tQual.includes('wet')) signs.BLOOD_DEF = true;
  if (tFeat.some(f => f.includes('teeth mark')) && pQuals.some(q => q.includes('empty') || q.includes('weak'))) signs.QI_DEF = true;
  if (pQuals.some(q => q.includes('wiry'))) signs.QI_STAG = true;
  if (tBody.includes('purple') || pQuals.some(q => q.includes('choppy'))) signs.STASIS = true;

  // ORGAN TOPOGRAPHY ON TONGUE
  if (tFeat.some(f => f.includes('tip') && f.includes('red'))) signs.ORGANS_IMPLICATED.add('Heart');
  if (tFeat.some(f => (f.includes('side') || f.includes('edge')) && f.includes('red'))) signs.ORGANS_IMPLICATED.add('Liver');
  if (tQual.includes('center') && (tQual.includes('peeling') || tQual.includes('thick'))) signs.ORGANS_IMPLICATED.add('Spleen');
  if (tBody.includes('root') && tQual.includes('thick')) signs.ORGANS_IMPLICATED.add('Kidney');

  return signs;
};

export const scoreSyndrome = (
  syn: Syndrome, 
  selExpanded: Set<string>, 
  pathology: PathologicalSigns,
  modifiers: { isHighSeverity: boolean, isChronic: boolean, isAcute: boolean },
  regions: string[]
): number => {
  let score = 0;
  const weights = TCM_DB.clinical_config.scoring.weights;
  const pType = normalize(syn.pattern_type);

  // 1. Symptom Match
  (syn.key_symptoms || []).forEach(ks => {
    if (Array.from(selExpanded).some(sel => fuzzyMatch(sel, ks))) {
        score += weights.key_symptom_match;
        if (modifiers.isHighSeverity) score += 5;
    }
  });

  // 2. Heat/Cold Specific Logic
  if (pathology.HEAT_FULL && pType.includes('full_heat')) score += 20;
  if (pathology.HEAT_EMPTY && pType.includes('deficiency_yin')) score += 20;
  if (pathology.COLD_FULL && pType.includes('excess_cold')) score += 20;
  if (pathology.COLD_EMPTY && pType.includes('yang_deficiency')) score += 20;

  // 3. Organ & Wu Xing Dynamic
  const synOrgans = syn.primary_organs || [];
  synOrgans.forEach(org => {
      if (pathology.ORGANS_IMPLICATED.has(org)) score += 25;
  });

  // Inter-organ bonus (e.g. Liver overacting on Spleen)
  if (synOrgans.includes('Liver') && synOrgans.includes('Spleen')) {
    if (pathology.QI_STAG || pathology.QI_DEF) score += 15;
  }

  return score;
};

function organToChannelCodes(organs: string[]) {
  const map: Record<string, string[]> = {
    Lung: ["LU"], "Large Intestine": ["LI"], Heart: ["HT"], "Small Intestine": ["SI"],
    Spleen: ["SP"], Stomach: ["ST"], Kidney: ["KI"], Bladder: ["BL"],
    Liver: ["LR"], "Gall Bladder": ["GB"], Pericardium: ["PC"], "San Jiao": ["TE"]
  };
  const out: string[] = [];
  organs.forEach(o => (map[o] || []).forEach(c => out.push(c)));
  return [...new Set(out)];
}

export function buildAutoPrescription(DB: any, input: AutoRxInput): { points: RxPoint[], warnings: string[], rationale: string[] } {
  const syn = input.syndrome;
  const points: RxPoint[] = [];
  const rationale: string[] = [];
  const tables = DB.special_point_tables;
  const channels = organToChannelCodes(syn.primary_organs || []);

  // 1. Base Points from Syndrome
  const basePts = Array.isArray(syn.acupuncture_points) ? syn.acupuncture_points : (syn.acupuncture_points?.kausal || []);
  basePts.forEach((code: string) => points.push({ code, role: "kausal", source: "syndrome" }));

  // 2. Intelligent Shu-Mu Pairing
  channels.forEach(ch => {
      const shu = tables.back_shu_points[ch];
      const mu = tables.front_mu_points[ch];
      if (shu && mu) {
          points.push({ code: shu, role: "back_shu", source: "auto:shu_mu", note: `Back-Shu of ${ch}` });
          points.push({ code: mu, role: "front_mu", source: "auto:shu_mu", note: `Front-Mu of ${ch}` });
      }
  });

  // 3. Pathogen Clearing (Essential ST40 for Phlegm)
  const allText = normalize(input.selectedSymptoms.join(' ') + ' ' + (syn.name_en || ''));
  if (allText.includes('dahak') || allText.includes('phlegm') || allText.includes('sticky')) {
    if (!points.some(p => p.code === "ST40")) {
      points.push({ code: "ST40", role: "resolve_phlegm", source: "auto:essential", note: "Essential for Phlegm" });
    }
  }

  const seen = new Set<string>();
  return { 
    points: points.filter(p => {
      const c = p.code.toUpperCase();
      if (seen.has(c)) return false;
      seen.add(c);
      return true;
    }), 
    warnings: [], 
    rationale: ["Integrasi otomatis berdasarkan prinsip Shu-Mu dan pembersihan patogen."] 
  };
}

export const getHerbalRecommendation = (syndrome: Syndrome) => {
  const guidelines = TCM_DB.herbal_guidelines;
  const patternRules = guidelines.herbal_rules_by_pattern_type;
  if (patternRules && patternRules[syndrome.pattern_type]) {
    const rule = patternRules[syndrome.pattern_type];
    return {
      formula_name: rule.notes || "Standard Formula",
      chief: rule.suggest_chief || rule.suggest_chief_herbs || [],
      assistants: rule.suggest_assistants || [],
      avoid: rule.avoid || []
    };
  }
  return undefined;
};

export const analyzePatient = (data: PatientFormSchema): ScoredSyndrome[] => {
    const allSyndromes = [...TCM_DB.syndromes.FILLED_FROM_PDF, ...TCM_DB.syndromes.TODO_FROM_PDF];
    const symptomsList = [...(data.selected_symptoms || []), ...extractSymptoms((data as any).symptoms || "")];
    const selExpanded = expandWithSynonyms(symptomsList);
    const pathology = detectPathologyFromSigns(data.tongue, data.pulse);

    const allText = normalize(data.chief_complaint + " " + ((data as any).symptoms || ""));
    const modifiers = {
        isHighSeverity: SEVERITY_HIGH.some(k => allText.includes(k)),
        isChronic: DURATION_CHRONIC.some(k => allText.includes(k)),
        isAcute: DURATION_ACUTE.some(k => allText.includes(k)) || !!data.isAcuteMode,
    };

    const scored = allSyndromes.map(syn => ({
        syndrome: syn,
        score: scoreSyndrome(syn, selExpanded, pathology, modifiers, data.body_region_selector)
    }));

    return scored
        .filter(s => s.score > 10)
        .sort((a, b) => b.score - a.score)
        .slice(0, 5)
        .map(s => {
            const autoRx = buildAutoPrescription(TCM_DB, {
                syndrome: s.syndrome,
                selectedSymptoms: symptomsList,
                tongue: [data.tongue.body_color, data.tongue.coating_color, data.tongue.coating_quality],
                pulse: data.pulse.qualities
            });
            return {
                ...s,
                points: autoRx.points,
                warnings: autoRx.warnings,
                rationale: autoRx.rationale,
                herbal_recommendation: getHerbalRecommendation(s.syndrome)
            };
        });
};

