import React, { useState, useRef } from 'react';
import { TcmDiagnosisResult } from '../types';
import { TCM_DB } from '../constants';
import { db } from '../services/db';
import { 
  AlertTriangle, Activity, Stethoscope, GitMerge, MapPin, 
  BrainCircuit, Zap, Target, Layers, Save, FileText, 
  FileDown, Leaf, Map, ChevronRight, Info
} from 'lucide-react';
import DoctorNoteModal from './DoctorNoteModal';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface Props {
  diagnosis: TcmDiagnosisResult;
  isPregnant: boolean;
  onShowVisualizer: (element?: string) => void;
  patientContext?: any;
}

const DiagnosisCard: React.FC<Props> = ({ diagnosis, isPregnant, onShowVisualizer, patientContext }) => {
  const [showNoteModal, setShowNoteModal] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const cardRef = useRef<HTMLDivElement>(null);

  const allSyndromes = [
    ...TCM_DB.syndromes.FILLED_FROM_PDF,
    ...TCM_DB.syndromes.TODO_FROM_PDF
  ];

  const pattern = allSyndromes.find(p => p.id === diagnosis.patternId);
  const patternName = pattern ? pattern.name_id : diagnosis.patternId.replace(/_/g, ' ');

  const handleSaveToArchive = () => {
    let patientName = patientContext?.patientName;
    if (!patientName) {
        patientName = prompt("Masukkan Nama Pasien (Opsional):") || "Anonim";
    }

    db.patients.add({
      id: Date.now().toString(),
      patientName: patientName,
      age: patientContext?.age || "?",
      sex: patientContext?.sex || "?",
      address: patientContext?.address || "",
      complaint: patientContext?.complaint || "Chat Diagnosis",
      symptoms: patientContext?.symptoms || "",
      tongue: patientContext?.tongue || {},
      pulse: patientContext?.pulse || { qualities: [] },
      diagnosis: diagnosis,
      biomedicalDiagnosis: patientContext?.biomedicalDiagnosis || "",
      icd10: patientContext?.icd10 || "",
      medications: patientContext?.medications || "",
      herbs: patientContext?.herbs || "",
      treatmentPlan: patientContext?.treatmentPlan || pattern?.treatment_principle?.join(', ') || "",
      notes: patientContext?.notes || "",
      followUpDate: patientContext?.followUpDate || "",
      timestamp: Date.now()
    });

    setIsSaved(true);
  };

  const handleVisualizerClick = () => {
    let elementToHighlight = diagnosis.wuxingElement?.toLowerCase();
    if (!elementToHighlight) {
        const text = (diagnosis.wuxingAnalysis || pattern?.wuxing_element || "").toLowerCase();
        if (text.includes('wood') || text.includes('liver') || text.includes('gall')) elementToHighlight = 'wood';
        else if (text.includes('fire') || text.includes('heart') || text.includes('small intestine')) elementToHighlight = 'fire';
        else if (text.includes('earth') || text.includes('spleen') || text.includes('stomach')) elementToHighlight = 'earth';
        else if (text.includes('metal') || text.includes('lung') || text.includes('large intestine')) elementToHighlight = 'metal';
        else if (text.includes('water') || text.includes('kidney') || text.includes('bladder')) elementToHighlight = 'water';
    }
    onShowVisualizer(elementToHighlight);
  };

  const handleExportPDF = async () => {
    if (!cardRef.current) return;
    try {
      const canvas = await html2canvas(cardRef.current, {
        scale: 2,
        useCORS: true,
        backgroundColor: '#0f172a',
        logging: false
      });
      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pageWidth = pdf.internal.pageSize.getWidth();
      const imgProps = pdf.getImageProperties(imgData);
      const imgHeight = (imgProps.height * pageWidth) / imgProps.width;
      pdf.addImage(imgData, 'PNG', 0, 0, pageWidth, imgHeight);
      pdf.save(`TCM_Report_${patternName.replace(/\s+/g, '_')}.pdf`);
    } catch (error) {
      console.error("PDF Export Error:", error);
    }
  };

  const cycleBadge = (() => {
    const dynamic = (diagnosis.wuxingDynamic || "").toLowerCase();
    if (dynamic.includes('overact') || dynamic.includes('cheng')) return { label: 'Overacting (Cheng)', color: 'text-rose-400 bg-rose-500/10 border-rose-500/30', icon: <AlertTriangle className="w-3 h-3"/> };
    if (dynamic.includes('insult') || dynamic.includes('wu')) return { label: 'Insulting (Wu)', color: 'text-orange-400 bg-orange-500/10 border-orange-500/30', icon: <Zap className="w-3 h-3"/> };
    if (dynamic.includes('generat') || dynamic.includes('sheng')) return { label: 'Generating (Sheng)', color: 'text-emerald-400 bg-emerald-500/10 border-emerald-500/30', icon: <Activity className="w-3 h-3"/> };
    if (dynamic.includes('control') || dynamic.includes('ke')) return { label: 'Controlling (Ke)', color: 'text-indigo-400 bg-indigo-500/10 border-indigo-500/30', icon: <GitMerge className="w-3 h-3"/> };
    return { label: 'Balanced', color: 'text-slate-400 bg-slate-500/10 border-slate-500/30', icon: <Info className="w-3 h-3"/> };
  })();

  return (
    <>
      <DoctorNoteModal 
        isOpen={showNoteModal} 
        onClose={() => setShowNoteModal(false)} 
        diagnosis={diagnosis} 
        initialPatientData={{
          name: patientContext?.patientName,
          age: patientContext?.age,
          address: patientContext?.address
        }}
      />

      <div ref={cardRef} className="group bg-slate-900 border border-slate-800 rounded-3xl p-6 my-4 shadow-2xl animate-fade-in relative overflow-hidden transition-all hover:border-slate-700 print:bg-white print:text-black">
        {/* Aesthetic Background Accents */}
        <div className="absolute top-0 right-0 w-32 h-32 bg-tcm-primary/5 blur-[80px] rounded-full pointer-events-none"></div>
        <div className="absolute bottom-0 left-0 w-32 h-32 bg-indigo-500/5 blur-[80px] rounded-full pointer-events-none"></div>

        {/* Header Section */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8 border-b border-slate-800 pb-6 relative z-10">
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 rounded-2xl bg-tcm-primary/10 flex items-center justify-center border border-tcm-primary/20 shrink-0">
               <BrainCircuit className="w-8 h-8 text-tcm-primary" />
            </div>
            <div>
              <h3 className="text-2xl font-black text-white tracking-tight leading-none mb-1">{patternName}</h3>
              <div className="flex items-center gap-2">
                <span className="text-xs text-slate-500 font-bold uppercase tracking-widest">{diagnosis.patternId.replace(/_/g, ' ')}</span>
                {pattern?.name_en && <span className="text-xs text-slate-400 italic font-medium">• {pattern.name_en}</span>}
              </div>
            </div>
          </div>

          <div className="flex items-center gap-2 print:hidden">
              <button 
                  onClick={handleSaveToArchive} 
                  disabled={isSaved}
                  className={`px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 shadow-lg border ${
                    isSaved ? 'bg-emerald-950 text-emerald-400 border-emerald-800' : 'bg-slate-800 hover:bg-slate-700 text-white border-slate-700'
                  }`}
              >
                  <Save className="w-4 h-4" /> {isSaved ? 'Archived' : 'Archive'}
              </button>
              <button 
                  onClick={() => setShowNoteModal(true)} 
                  className="px-4 py-2 bg-tcm-primary hover:bg-emerald-400 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 shadow-lg"
              >
                  <FileText className="w-4 h-4" /> Rx Note
              </button>
              <button onClick={handleExportPDF} className="p-2.5 bg-slate-800 hover:bg-slate-700 text-slate-400 hover:text-white rounded-xl transition-all border border-slate-700">
                  <FileDown className="w-5 h-5" />
              </button>
          </div>
        </div>

        {/* Quick Insights Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8 relative z-10">
           <div className="bg-slate-950/60 border border-slate-800 p-4 rounded-2xl flex flex-col gap-2 transition-transform hover:scale-[1.02]">
              <div className="flex items-center gap-2 text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">
                 <Target className="w-4 h-4 text-emerald-500" /> Affected Organs
              </div>
              <div className="text-sm font-bold text-slate-100 flex flex-wrap gap-1">
                 {pattern?.primary_organs?.map(org => (
                   <span key={org} className="bg-slate-900 px-2 py-0.5 rounded-lg border border-slate-800">{org}</span>
                 )) || '-'}
              </div>
           </div>

           <div className="bg-slate-950/60 border border-slate-800 p-4 rounded-2xl flex flex-col gap-2 transition-transform hover:scale-[1.02]">
              <div className="flex items-center gap-2 text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">
                 <Layers className="w-4 h-4 text-tcm-primary" /> Wu Xing Element
              </div>
              <div className="text-sm font-black text-tcm-primary uppercase flex items-center gap-2">
                {diagnosis.wuxingElement || '-'}
                <button onClick={handleVisualizerClick} className="ml-auto p-1.5 bg-slate-800 rounded-lg hover:bg-slate-700 transition-colors print:hidden">
                   <Map className="w-3.5 h-3.5" />
                </button>
              </div>
           </div>

           <div className="bg-slate-950/60 border border-slate-800 p-4 rounded-2xl flex flex-col gap-2 transition-transform hover:scale-[1.02]">
              <div className="flex items-center gap-2 text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">
                 <Zap className="w-4 h-4 text-amber-500" /> Imbalance Dynamics
              </div>
              <div className={`text-xs font-bold px-3 py-1 rounded-xl border flex items-center gap-2 w-fit ${cycleBadge.color}`}>
                {cycleBadge.icon} {cycleBadge.label}
              </div>
           </div>
        </div>

        {/* Zang-Fu Dynamics Detail */}
        {diagnosis.wuxingRelationships && diagnosis.wuxingRelationships.length > 0 && (
           <div className="mb-8 bg-slate-950/40 border border-indigo-500/20 p-5 rounded-3xl relative z-10">
              <div className="flex items-center gap-2 mb-4 text-indigo-400 text-xs font-black uppercase tracking-[0.2em]">
                 <GitMerge className="w-4 h-4" /> Pathological Interactions
              </div>
              <div className="space-y-4">
                 {diagnosis.wuxingRelationships.map((rel, i) => (
                    <div key={i} className="flex items-start gap-4 p-4 rounded-2xl bg-slate-900/50 border border-slate-800 hover:border-indigo-500/30 transition-colors">
                       <div className={`mt-1 p-2 rounded-xl bg-slate-800 border ${rel.type === 'Overacting' ? 'border-rose-500/30 text-rose-400' : 'border-indigo-500/30 text-indigo-400'}`}>
                          <ChevronRight className="w-4 h-4" />
                       </div>
                       <div>
                          <div className="flex items-center gap-2 mb-1">
                            <span className="font-black text-white text-sm">{rel.type}</span>
                            <span className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">Target: {rel.targetElement}</span>
                          </div>
                          <p className="text-slate-400 text-xs leading-relaxed">{rel.description}</p>
                       </div>
                    </div>
                 ))}
              </div>
           </div>
        )}

        {/* Clinical Analysis: Root vs Branch */}
        <div className="mb-8 relative z-10">
          <div className="flex items-center gap-2 mb-4 text-slate-500 text-xs font-black uppercase tracking-[0.2em]">
             <Stethoscope className="w-4 h-4" /> Integrated Clinical Analysis
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
             <div className="bg-gradient-to-br from-emerald-950/20 to-slate-950 border border-emerald-500/20 p-5 rounded-3xl">
                <div className="text-[10px] font-black text-emerald-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                   <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div> Root (Ben)
                </div>
                <p className="text-sm text-slate-100 font-bold leading-relaxed">{diagnosis.analysisDetail?.root || 'Primary Deficiency or Originating Pattern'}</p>
             </div>
             <div className="bg-gradient-to-br from-amber-950/20 to-slate-950 border border-amber-500/20 p-5 rounded-3xl">
                <div className="text-[10px] font-black text-amber-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                   <div className="w-2 h-2 rounded-full bg-amber-500"></div> Branch (Biao)
                </div>
                <p className="text-sm text-slate-100 font-bold leading-relaxed">{diagnosis.analysisDetail?.branch || 'Manifest Symptoms or Pathogenic Branch'}</p>
             </div>
          </div>

          <div className="bg-slate-950 p-6 rounded-3xl border border-slate-800 shadow-inner">
             <p className="text-slate-300 leading-relaxed text-sm font-medium whitespace-pre-line italic">
               "{diagnosis.explanation}"
             </p>
          </div>
        </div>

        {/* Treatment Points & Herbs Section */}
        <div className="space-y-6 pt-6 border-t border-slate-800 relative z-10">
           {/* Points */}
           <div>
              <div className="flex items-center justify-between mb-4">
                <h4 className="text-xs font-black text-tcm-primary uppercase tracking-[0.2em] flex items-center gap-2">
                    <MapPin className="w-4 h-4"/> Final Prescription Formula
                </h4>
                <span className="text-[10px] bg-slate-800 text-slate-500 px-3 py-1 rounded-full font-bold uppercase tracking-widest">
                   {diagnosis.recommendedPoints.length} Acupoints
                </span>
              </div>
              <div className="flex flex-wrap gap-2">
                {diagnosis.recommendedPoints.map((point) => (
                    <div key={point} className="group/pt px-4 py-2 rounded-2xl text-sm font-black bg-slate-950 text-tcm-primary border border-tcm-primary/30 shadow-lg transition-all hover:bg-tcm-primary hover:text-white hover:border-tcm-primary">
                      {point}
                    </div>
                ))}
              </div>
           </div>

           {/* Herbs */}
           {diagnosis.herbal_recommendation && (
             <div className="bg-emerald-950/10 border border-emerald-500/20 p-6 rounded-3xl">
                <div className="flex items-center justify-between mb-4">
                   <h4 className="text-xs font-black text-tcm-primary uppercase tracking-[0.2em] flex items-center gap-2">
                      <Leaf className="w-4 h-4" /> Herbal Formula: <span className="text-white ml-1">{diagnosis.herbal_recommendation.formula_name || 'Individual Protocol'}</span>
                   </h4>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                   <div className="bg-slate-950 p-4 rounded-2xl border border-emerald-500/20">
                      <span className="text-emerald-400 font-black block mb-2 uppercase text-[9px] tracking-widest">Chief Herbs (Jun)</span>
                      <div className="flex flex-wrap gap-2 text-xs font-bold text-slate-200">
                         {diagnosis.herbal_recommendation.chief.map(h => (
                           <span key={h} className="bg-slate-900 px-2 py-1 rounded-lg border border-slate-800">{h}</span>
                         ))}
                      </div>
                   </div>
                   {diagnosis.herbal_recommendation.assistants && (
                      <div className="bg-slate-950 p-4 rounded-2xl border border-slate-800">
                         <span className="text-slate-500 font-black block mb-2 uppercase text-[9px] tracking-widest">Assistant Herbs</span>
                         <div className="flex flex-wrap gap-2 text-xs font-bold text-slate-400">
                            {diagnosis.herbal_recommendation.assistants.map(h => (
                              <span key={h} className="bg-slate-900 px-2 py-1 rounded-lg border border-slate-800">{h}</span>
                            ))}
                         </div>
                      </div>
                   )}
                </div>
             </div>
           )}
        </div>

        {/* Safety Note */}
        {diagnosis.safetyWarnings && diagnosis.safetyWarnings.length > 0 && (
          <div className="mt-8 p-4 bg-rose-950/20 border border-rose-500/20 rounded-2xl flex items-start gap-3">
             <AlertTriangle className="w-5 h-5 text-rose-500 shrink-0" />
             <div className="text-xs text-rose-200 font-medium">
                {diagnosis.safetyWarnings.join(' • ')}
             </div>
          </div>
        )}
      </div>
    </>
  );
};

