                    <input className="flex-1 bg-slate-950 border border-slate-700 rounded-xl px-4 py-2.5 text-sm text-white focus:border-tcm-primary outline-none" 
                           value={patientName} onChange={e => setPatientName(e.target.value)} placeholder="Nama Pasien" />
                    <input className="w-20 bg-slate-950 border border-slate-700 rounded-xl px-4 py-2.5 text-sm text-white focus:border-tcm-primary outline-none" 
                           value={age} onChange={e => setAge(e.target.value)} placeholder="Age" />
                 </div>
                 <input className="w-full bg-slate-950 border border-slate-700 rounded-xl px-4 py-2.5 text-sm text-white focus:border-tcm-primary outline-none" 
                        value={address} onChange={e => setAddress(e.target.value)} placeholder="Alamat Pasien" />
                 <input type="date" className="w-full bg-slate-950 border border-slate-700 rounded-xl px-4 py-2.5 text-sm text-white focus:border-tcm-primary outline-none" 
                        value={date} onChange={e => setDate(e.target.value)} />
              </div>

              <div className="space-y-3">
                 <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Resep / Instruksi Klinis</label>
                 <textarea 
                    className="w-full h-44 bg-slate-950 border border-slate-700 rounded-xl px-4 py-3 text-xs text-white font-mono leading-relaxed focus:border-tcm-primary outline-none resize-none"
                    value={notes}
                    onChange={e => setNotes(e.target.value)}
                 />
              </div>

              <div className="space-y-3">
                 <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Digital Signature</label>
                 <div className="flex items-center gap-2">
                    <label className="flex-1 cursor-pointer bg-slate-950 hover:bg-slate-900 border border-slate-700 border-dashed rounded-xl p-3 text-center transition-all group">
                        <span className="text-[10px] text-slate-500 group-hover:text-slate-300 flex items-center justify-center gap-2 font-bold uppercase tracking-widest">
                           <Upload className="w-4 h-4" /> Import PNG
                        </span>
                        <input type="file" accept="image/*" className="hidden" onChange={handleSignatureUpload} />
                    </label>
                    {signature && (
                        <button onClick={() => setSignature(null)} className="p-2.5 bg-rose-950/30 text-rose-500 rounded-xl border border-rose-900/50 hover:bg-rose-900 transition-colors">
                           <X className="w-4 h-4" />
                        </button>
                    )}
                 </div>
              </div>

              <div className="grid grid-cols-2 gap-2 mt-4">
                  <button 
                    onClick={generatePDF} 
                    disabled={isGenerating}
                    className="py-3 bg-indigo-600 hover:bg-indigo-500 text-white font-black rounded-xl shadow-lg flex items-center justify-center gap-2 text-xs uppercase tracking-widest transition-all disabled:opacity-50"
                  >
                    {isGenerating ? 'Wait...' : <><FileDown className="w-4 h-4" /> PDF</>}
                  </button>
                  <button 
                    onClick={generateTextFile}
                    className="py-3 bg-slate-700 hover:bg-slate-600 text-white font-black rounded-xl shadow-lg flex items-center justify-center gap-2 text-xs uppercase tracking-widest transition-all"
                  >
                    <Clipboard className="w-4 h-4" /> Text
                  </button>
              </div>
           </div>
        </div>

        {/* RIGHT: Live Preview */}
        <div className="flex-1 bg-slate-950 p-6 md:p-12 flex items-center justify-center overflow-auto scrollbar-hide">
            {/* PAPER CANVAS */}
            <div 
               ref={receiptRef}
               className="bg-white text-slate-900 shadow-[0_0_50px_rgba(0,0,0,0.5)] relative flex flex-col transform origin-center"
               style={{ 
                  width: '148mm',
                  height: '210mm',
                  minWidth: '148mm',
                  minHeight: '210mm',
                  padding: '18mm',
                  fontFamily: 'serif'
               }}
            >
               {/* Header */}
               <div className="border-b-2 border-slate-900 pb-5 mb-6 text-center">
                  <h1 className="text-2xl font-black uppercase tracking-widest text-slate-900 leading-none mb-1">{clinicName}</h1>
                  <p className="text-sm font-bold text-slate-700">{doctorName}</p>
                  <p className="text-[10px] text-slate-500 mt-2 uppercase tracking-[0.2em] font-sans">Traditional Chinese Medicine & Acupuncture Specialist</p>
               </div>

               {/* Patient Data */}
               <div className="flex justify-between text-[11px] mb-10 font-sans border-b border-slate-100 pb-4">
                  <div className="space-y-1.5">
                     <p><span className="font-bold text-slate-400 uppercase tracking-tighter mr-2">Nama Pasien:</span> <span className="font-black">{patientName || '-'}</span></p>
                     <p><span className="font-bold text-slate-400 uppercase tracking-tighter mr-2">Umur:</span> <span className="font-black">{age} th</span></p>
                     <p><span className="font-bold text-slate-400 uppercase tracking-tighter mr-2">Alamat:</span> <span className="font-black">{address || '-'}</span></p>
                  </div>
                  <div className="text-right space-y-1.5">
                     <p><span className="font-bold text-slate-400 uppercase tracking-tighter mr-2">Tanggal:</span> <span className="font-black">{date}</span></p>
                     <p><span className="font-bold text-slate-400 uppercase tracking-tighter mr-2">No. Reg:</span> <span className="font-black">#TCM-{Date.now().toString().slice(-6)}</span></p>
                  </div>
               </div>

               {/* Body Content */}
               <div className="flex-1 font-mono text-xs whitespace-pre-wrap leading-loose text-slate-800">
                  <div className="flex items-start gap-3 mb-4">
                     <span className="text-4xl font-black font-serif italic text-slate-300 leading-none">R/</span>
                  </div>
                  <div className="pl-2">
                    {notes}
                  </div>
               </div>

               {/* Footer / Signature */}
               <div className="mt-12 flex flex-col items-end">
                  <p className="text-[10px] text-slate-500 mb-8 font-sans uppercase tracking-widest">Klinik {clinicName.split(' ')[1] || 'Pusat'}, {date}</p>
                  <div className="w-40 h-24 flex items-center justify-center relative mb-2">
                     {signature ? (
                        <img src={signature} alt="Signature" className="max-w-full max-h-full object-contain mix-blend-multiply" />
                     ) : (
                        <div className="w-full h-full border border-slate-100 border-dashed rounded flex items-center justify-center text-[9px] text-slate-300 uppercase font-sans tracking-widest">
                           Signature Required
                        </div>
                     )}
                  </div>
                  <p className="text-sm font-black border-t-2 border-slate-900 pt-2 min-w-[180px] text-center uppercase tracking-tighter">
                     {doctorName}
                  </p>
               </div>

               {/* Bottom Brand */}
               <div className="absolute bottom-6 left-0 right-0 text-center opacity-30">
                  <p className="text-[8px] text-slate-400 uppercase tracking-[0.6em] font-sans font-bold">
                     Powered by TCM WuXing Pro CDSS
                  </p>
               </div>
            </div>

        </div>
      </div>
    </div>
  );
};

export default DoctorNoteModal;
